#==============================================================================
# MOD: ScriptLibrary
# Features:
#   1. Get-LibraryPath   -- resolves Scripts\ dir (installed vs portable)
#   2. Save-PayloadToLibrary  -- copies current payload into Scripts\
#   3. New-PayloadBat    -- generates standalone admin BAT for current payload
#   4. Update-LibraryDropdown -- populates cmbLibrary from Scripts\ dir
#   5. DispatcherTimer auto-refresh (5s) -- picks up files dropped externally
#==============================================================================

#------------------------------------------------------------------------------
# MOD: ScriptLibrary -- Path resolver
#------------------------------------------------------------------------------
function Get-LibraryPath {
    $installedScripts = 'C:\ProgramData\Paladin\Launcher\Scripts'
    if (Test-Path -LiteralPath 'C:\ProgramData\Paladin\Launcher' -PathType Container -ErrorAction SilentlyContinue) {
        return $installedScripts
    }
    $selfDir = Split-Path -Parent $MyInvocation.ScriptName -ErrorAction SilentlyContinue
    if ([string]::IsNullOrWhiteSpace($selfDir)) { $selfDir = $PSScriptRoot }
    if ([string]::IsNullOrWhiteSpace($selfDir)) { $selfDir = (Get-Location).Path }
    return (Join-Path $selfDir 'Scripts')
}

#------------------------------------------------------------------------------
# MOD: ScriptLibrary -- Recent scripts tracking
# Saves/loads a list of recently used PS1 paths from recentscripts.json
# in the Scripts library folder. Max 20 entries. Persists across sessions.
#------------------------------------------------------------------------------
function Initialize-LibraryDir {
    param([string]$LibDir)
    if (-not (Test-Path -LiteralPath $LibDir -PathType Container -ErrorAction SilentlyContinue)) {
        try {
            New-Item -ItemType Directory -Path $LibDir -Force -ErrorAction Stop | Out-Null
        } catch {
            return $false
        }
    }
    return $true
}

function Get-RecentScriptPath {
    $libDir = Get-LibraryPath
    Initialize-LibraryDir -LibDir $libDir | Out-Null
    return (Join-Path $libDir 'recentscripts.json')
}

function Get-RecentScripts {
    $jsonPath = Get-RecentScriptPath
    $result = New-Object System.Collections.ArrayList
    if (-not (Test-Path -LiteralPath $jsonPath -PathType Leaf -ErrorAction SilentlyContinue)) {
        return ,$result
    }
    try {
        $raw = [System.IO.File]::ReadAllText($jsonPath)
        $raw = $raw.Trim().TrimStart('[').TrimEnd(']')
        foreach ($item in ($raw -split ',')) {
            $item = $item.Trim().Trim('"')
            $item = $item -replace '\\\\', '\'
            # Skip any entry that looks like a .NET type name rather than a real path
            if (-not [string]::IsNullOrWhiteSpace($item) -and
                $item -notmatch '^System\.' -and
                $item -match '[\\/]') {
                $result.Add($item) | Out-Null
            }
        }
        return ,$result
    } catch {
        return ,(New-Object System.Collections.ArrayList)
    }
}

function Add-RecentScript {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return }
    if (-not (Test-Path -LiteralPath $Path -PathType Leaf -ErrorAction SilentlyContinue)) { return }

    # Get-RecentScripts returns ,$arrayList (comma-escaped to force array).
    # Index [0] unwraps it to the actual ArrayList. Fall back to empty list if null.
    $listRaw = Get-RecentScripts
    $list = if ($null -ne $listRaw -and $listRaw.Count -gt 0) { $listRaw[0] } else { $null }
    if ($null -eq $list -or $list -isnot [System.Collections.ArrayList]) {
        $list = New-Object System.Collections.ArrayList
    }

    # Remove existing entry by index to avoid overload ambiguity (KI-056-ext)
    $existingIdx = $list.IndexOf($Path)
    if ($existingIdx -ge 0) { $list.RemoveAt($existingIdx) }

    # Insert at top
    $list.Insert(0, $Path)

    # Cap at 20
    while ($list.Count -gt 20) { $list.RemoveAt($list.Count - 1) }

    # Save as JSON array
    $jsonPath = Get-RecentScriptPath
    try {
        $escaped = $list | ForEach-Object { '"' + ($_ -replace '\\', '\\\\') + '"' }
        $json = '[' + ($escaped -join ',') + ']'
        [System.IO.File]::WriteAllText($jsonPath, $json, [System.Text.Encoding]::UTF8)
    } catch { }
}

#------------------------------------------------------------------------------
# MOD: ScriptLibrary -- Save payload to library
#------------------------------------------------------------------------------
function Save-PayloadToLibrary {
    $srcPath = $script:TxtPayload.Text.Trim()
    if ([string]::IsNullOrWhiteSpace($srcPath)) {
        Add-LogEntry -Level 'FAIL' -Message "Save to Library: no payload loaded -- browse or select a script first."
        return
    }
    if (-not (Test-Path -LiteralPath $srcPath -PathType Leaf -ErrorAction SilentlyContinue)) {
        Add-LogEntry -Level 'FAIL' -Message "Save to Library: file not found: $srcPath"
        return
    }

    $libDir = Get-LibraryPath
    if (-not (Initialize-LibraryDir -LibDir $libDir)) { return }

    $fileName = Split-Path $srcPath -Leaf
    $dstPath  = Join-Path $libDir $fileName

    # Warn on overwrite but proceed
    $overwrite = $false
    if (Test-Path -LiteralPath $dstPath -PathType Leaf -ErrorAction SilentlyContinue) {
        $overwrite = $true
        Add-LogEntry -Level 'WARN' -Message "Save to Library: overwriting existing: $fileName"
    }

    try {
        if (-not (Test-Path -LiteralPath $srcPath)) {
            throw "Source path not found: $srcPath"
        }
        Copy-Item -LiteralPath $srcPath -Destination $dstPath -Force -ErrorAction Stop
        # Verify
        if (Test-Path -LiteralPath $dstPath -PathType Leaf -ErrorAction SilentlyContinue) {
            $verb = if ($overwrite) { 'Updated' } else { 'Saved' }
            Add-LogEntry -Level 'PASS' -Message "$verb to library: $dstPath"
            Update-LibraryDropdown
        } else {
            Add-LogEntry -Level 'FAIL' -Message "Save to Library: copy appeared to succeed but file not found at destination."
        }
    } catch {
        Add-LogEntry -Level 'FAIL' -Message "Save to Library failed: $($_.Exception.Message)"
    }
}

#------------------------------------------------------------------------------
# MOD: ScriptLibrary -- Generate standalone BAT for current payload
#------------------------------------------------------------------------------
function New-PayloadBat {
    $ps1Path = $script:TxtPayload.Text.Trim()
    if ([string]::IsNullOrWhiteSpace($ps1Path)) {
        Add-LogEntry -Level 'FAIL' -Message "Create BAT: no payload loaded -- browse or select a script first."
        return
    }
    if (-not (Test-Path -LiteralPath $ps1Path -PathType Leaf -ErrorAction SilentlyContinue)) {
        Add-LogEntry -Level 'FAIL' -Message "Create BAT: file not found: $ps1Path"
        return
    }

    $ps1Dir      = Split-Path $ps1Path -Parent
    $ps1Name     = Split-Path $ps1Path -Leaf
    $ps1BaseName = [System.IO.Path]::GetFileNameWithoutExtension($ps1Name)
    $batName     = "Run_${ps1BaseName}_AsAdmin.bat"
    $batPath     = Join-Path $ps1Dir $batName
    $timestamp   = (Get-Date).ToString('M/d/yyyy, h:mm:ss tt')

    # BAT content mirrors the Paladin Admin wrapper pattern
    $batContent = @"
@echo off
:: PowerShell Admin Wrapper
:: Generated for: $ps1Name
:: Created: $timestamp

set "PS1PATH=%~dp0$ps1Name"
set "SELF_PATH=%~f0"
set "WRAP_VERBOSE=1"


:: Check for admin privileges
net session >nul 2>&1
if %errorLevel% == 0 (
    echo Running with administrator privileges...
    echo.
    if "%WRAP_VERBOSE%"=="1" (
        echo [DIAG] Wrapper: %~nx0
        echo [DIAG] PS1PATH: %PS1PATH%
        echo [DIAG] User: %USERNAME%  Domain: %USERDOMAIN%  Computer: %COMPUTERNAME%
        echo [DIAG] Elevation: OK
        echo.
        powershell -NoProfile -ExecutionPolicy Bypass -Command "`$PSVersionTable | Out-String | Write-Host"
        echo.
    )
    ) else (
    echo Requesting administrator privileges...
    echo.
    :: Re-run with admin rights
    powershell -Command "Start-Process `$env:SELF_PATH -Verb RunAs"
    exit /b
)

:: Change to script directory
cd /d "%~dp0"

:: Unblock files (remove "downloaded from internet" warning)
echo Unblocking files...
set "UNBLOCK_BAT=%~f0"
set "UNBLOCK_PS1=%~dp0$ps1Name"
powershell -Command "Unblock-File -LiteralPath `$env:UNBLOCK_BAT -ErrorAction SilentlyContinue"
powershell -Command "Unblock-File -LiteralPath `$env:UNBLOCK_PS1 -ErrorAction SilentlyContinue"
echo.

:: Run PowerShell script
echo Executing: $ps1Name
echo.
powershell.exe -ExecutionPolicy Bypass -NoProfile -File "%PS1PATH%"

:: Capture exit code
set EXIT_CODE=%ERRORLEVEL%

echo.
echo Script completed with exit code: %EXIT_CODE%
echo.
echo Press any key to close...
pause >nul
exit /b %EXIT_CODE%
"@

    try {
        # Write ASCII-safe -- no BOM, standard line endings
        [System.IO.File]::WriteAllText($batPath, $batContent, [System.Text.Encoding]::ASCII)
        # Verify
        if (Test-Path -LiteralPath $batPath -PathType Leaf -ErrorAction SilentlyContinue) {
            Add-LogEntry -Level 'PASS' -Message "BAT created: $batPath"
        } else {
            Add-LogEntry -Level 'FAIL' -Message "Create BAT: write appeared to succeed but file not found."
        }
    } catch {
        Add-LogEntry -Level 'FAIL' -Message "Create BAT failed: $($_.Exception.Message)"
    }
}

#------------------------------------------------------------------------------
# MOD: ScriptLibrary -- Populate dropdown from Scripts dir
#------------------------------------------------------------------------------
$script:LibraryLastFiles = [System.Collections.Generic.List[string]]::new()

function Update-LibraryDropdown {
    $libDir = Get-LibraryPath

    if ($script:LblLibraryPath -ne $null) {
        $script:LblLibraryPath.Text = "Library: $libDir"
    }

    # --- Scripts folder files ---
    $libFiles = @(Get-ChildItem -LiteralPath $libDir -Filter '*.ps1' -ErrorAction SilentlyContinue |
                  Sort-Object Name)

    # --- Recent scripts (any path, not just library) ---
    # Get-RecentScripts returns ,$arrayList (comma-escape). @() wraps it again.
    # [0] unwraps to the actual ArrayList; then enumerate it as strings.
    $recentRawWrapped = Get-RecentScripts
    $recentRaw = @(if ($null -ne $recentRawWrapped -and $recentRawWrapped.Count -gt 0) {
        $inner = $recentRawWrapped[0]
        if ($inner -is [System.Collections.ArrayList]) { foreach ($x in $inner) { $x } }
        else { $inner }
    })
    # Filter to files that still exist and are not already in lib folder
    $libPaths = @($libFiles | ForEach-Object { $_.FullName })
    $recentFiltered = @($recentRaw | Where-Object {
        -not [string]::IsNullOrWhiteSpace($_) -and
        (Test-Path -LiteralPath $_ -PathType Leaf -ErrorAction SilentlyContinue) -and
        ($libPaths -notcontains $_)
    })

    # Build combined display list for change detection
    $newNames = [System.Collections.Generic.List[string]]::new()
    foreach ($f in $libFiles)       { $newNames.Add("LIB:$($f.Name)") }
    foreach ($r in $recentFiltered) { $newNames.Add("REC:$r") }

    $changed = $false
    if ($newNames.Count -ne $script:LibraryLastFiles.Count) {
        $changed = $true
    } else {
        for ($i = 0; $i -lt $newNames.Count; $i++) {
            if ($newNames[$i] -ne $script:LibraryLastFiles[$i]) { $changed = $true; break }
        }
    }
    if (-not $changed) { return }
    $script:LibraryLastFiles = $newNames

    # Preserve current selection text
    $previousSel = $null
    if ($script:CmbLibrary -ne $null -and $script:CmbLibrary.SelectedItem -ne $null) {
        $previousSel = $script:CmbLibrary.SelectedItem.ToString()
    }

    if ($script:CmbLibrary -eq $null) { return }
    $script:CmbLibrary.Items.Clear()

    $hasItems = $false

    # Library folder scripts
    if ($libFiles.Count -gt 0) {
        foreach ($f in $libFiles) {
            $script:CmbLibrary.Items.Add($f.FullName) | Out-Null
            $hasItems = $true
        }
    }

    # Recent scripts separator + entries
    if ($recentFiltered.Count -gt 0) {
        if ($hasItems) {
            $script:CmbLibrary.Items.Add('--- Recent ---') | Out-Null
        }
        foreach ($r in $recentFiltered) {
            $script:CmbLibrary.Items.Add($r) | Out-Null
            $hasItems = $true
        }
    }

    if (-not $hasItems) {
        $script:CmbLibrary.Items.Add('(no scripts yet -- browse or drop PS1 files in Scripts folder)') | Out-Null
        $script:CmbLibrary.IsEnabled = $false
    } else {
        $script:CmbLibrary.IsEnabled = $true
        # Restore previous selection if still present
        if (-not [string]::IsNullOrWhiteSpace($previousSel)) {
            $idx = $script:CmbLibrary.Items.IndexOf($previousSel)
            if ($idx -ge 0) { $script:CmbLibrary.SelectedIndex = $idx }
        }
    }
}

# ===========================================================================
# MODULE: ImportFolder
# PURPOSE: Browse to a folder and bulk-import all PS1 files into the library.
# REMOVE: Delete this block to END MODULE: ImportFolder
# ===========================================================================
function Import-FolderToLibrary {
    Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue
    $dlg = New-Object System.Windows.Forms.FolderBrowserDialog
    $dlg.Description    = 'Select a folder to import PS1 files from'
    $dlg.ShowNewFolderButton = $false
    if ($dlg.ShowDialog() -ne [System.Windows.Forms.DialogResult]::OK) { return }

    $srcFolder = $dlg.SelectedPath
    $libDir    = Get-LibraryPath
    $ps1Files  = @(Get-ChildItem -LiteralPath $srcFolder -Filter '*.ps1' -File -ErrorAction SilentlyContinue)

    if ($ps1Files.Count -eq 0) {
        Add-LogEntry -Level 'WARN' -Message "Import Folder: no PS1 files found in $srcFolder"
        return
    }

    $copied  = 0
    $skipped = 0
    foreach ($f in $ps1Files) {
        $dest = Join-Path $libDir $f.Name
        try {
            if (Test-Path -LiteralPath $dest) {
                $skipped++
                Add-LogEntry -Level 'INFO' -Message "Import Folder: skipped (exists) $($f.Name)"
            } else {
                Copy-Item -LiteralPath $f.FullName -Destination $dest -ErrorAction Stop
                # Verify copy succeeded before counting
                if (Test-Path -LiteralPath $dest) {
                    $copied++
                    Add-LogEntry -Level 'INFO' -Message "Import Folder: copied $($f.Name)"
                } else {
                    Add-LogEntry -Level 'WARN' -Message "Import Folder: copy appeared OK but dest missing: $($f.Name)"
                }
            }
        } catch {
            Add-LogEntry -Level 'FAIL' -Message "Import Folder: failed $($f.Name): $($_.Exception.Message)"
        }
    }

    Add-LogEntry -Level 'INFO' -Message "Import Folder: $copied copied, $skipped skipped (already existed)."
    Update-LibraryDropdown
}

