            [PSCustomObject]@{ Name = 'Full (DoD / Enterprise)'; Args = ''; Note = 'All STIGs, AppLocker, BitLocker hardening, Sysmon, Device Guard. Enterprise/lab use only.' }
            [PSCustomObject]@{ Name = 'Workstation Safe';        Args = '-applockerhardening:$false -bitlockerhardening:$false -sysmon:$false -deviceguard:$false -nessusPID:$false'; Note = 'Removes most disruptive components. Suitable for managed corporate workstations.' }
            [PSCustomObject]@{ Name = 'Minimal Hardening';       Args = '-applockerhardening:$false -bitlockerhardening:$false -sysmon:$false -deviceguard:$false -nessusPID:$false -pshardening:$false -cleargpos:$false -emet:$false'; Note = 'Telemetry, Defender, firewall, basic mitigations only. Least disruptive.' }
        )
    }
)

# ---- Cache helpers ----------------------------------------------------------
function Get-GitHubToolCacheRoot {
    $base = 'C:\ProgramData\Paladin\Launcher\Cache'
    if (-not (Test-Path $base)) {
        New-Item -ItemType Directory -Path $base -Force -ErrorAction SilentlyContinue | Out-Null
    }
    return $base
}

function Get-GitHubToolCachePath {
    param([string]$ToolId)
    $root = Get-GitHubToolCacheRoot
    $dir  = Join-Path $root $ToolId
    if (-not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir -Force -ErrorAction SilentlyContinue | Out-Null
    }
    return $dir
}

function Get-GitHubToolMetadataPath {
    param([string]$ToolId)
    return (Join-Path (Get-GitHubToolCachePath -ToolId $ToolId) 'tool.json')
}

function Read-GitHubToolMetadata {
    param([string]$ToolId)
    $path = Get-GitHubToolMetadataPath -ToolId $ToolId
    if (-not (Test-Path -LiteralPath $path)) { return $null }
    try {
        $raw = [System.IO.File]::ReadAllText($path)
        # Minimal JSON parse -- extract key fields
        $id          = if ($raw -match '"id"\s*:\s*"([^"]+)"') { $Matches[1] } else { '' }
        $resolvedRef = if ($raw -match '"resolvedRef"\s*:\s*"([^"]+)"') { $Matches[1] } else { '' }
        $localPath   = if ($raw -match '"localPath"\s*:\s*"([^"]+)"') { $Matches[1] } else { '' }
        # Self-heal: if path has double-backslashes from old bug, treat as stale
        if ($localPath -match '\\\\') { return $null }
        $sha256      = if ($raw -match '"sha256"\s*:\s*"([^"]+)"') { $Matches[1] } else { '' }
        $updated     = if ($raw -match '"lastUpdatedUtc"\s*:\s*"([^"]+)"') { $Matches[1] } else { '' }
        return [PSCustomObject]@{
            Id             = $id
            ResolvedRef    = $resolvedRef
            LocalPath      = $localPath
            Sha256         = $sha256
            LastUpdatedUtc = $updated
        }
    } catch { return $null }
}

function Write-GitHubToolMetadata {
    param([string]$ToolId, [string]$ResolvedRef, [string]$LocalPath, [string]$Sha256)
    $path = Get-GitHubToolMetadataPath -ToolId $ToolId
    # Write path directly -- backslashes are not JSON-special, no escaping needed
    $utc  = [System.DateTime]::UtcNow.ToString('yyyy-MM-ddTHH:mm:ssZ')
    $json = "{`"id`":`"$ToolId`",`"resolvedRef`":`"$ResolvedRef`",`"localPath`":`"$LocalPath`",`"sha256`":`"$Sha256`",`"lastUpdatedUtc`":`"$utc`"}"
    [System.IO.File]::WriteAllText($path, $json, [System.Text.Encoding]::UTF8)
}

# ---- GitHub API helpers -----------------------------------------------------
function Invoke-GitHubJsonRequest {
    param([string]$Url)
    try {
        $wc = New-Object System.Net.WebClient
        $wc.Headers.Add('User-Agent', 'Spectre-Launcher/2.1')
        $wc.Headers.Add('Accept', 'application/vnd.github.v3+json')
        return $wc.DownloadString($Url)
    } catch {
        throw "GitHub API request failed ($Url): $_"
    }
}

function Get-GitHubLatestTag {
    param([string]$Owner, [string]$Repo)
    $json = Invoke-GitHubJsonRequest "https://api.github.com/repos/$Owner/$Repo/tags"
    if ($json -match '"name"\s*:\s*"([^"]+)"') { return $Matches[1] }
    throw "Could not parse latest tag for $Owner/$Repo"
}

function Get-GitHubLatestCommitSha {
    param([string]$Owner, [string]$Repo, [string]$Branch)
    $json = Invoke-GitHubJsonRequest "https://api.github.com/repos/$Owner/$Repo/commits/$Branch"
    if ($json -match '"sha"\s*:\s*"([a-f0-9]{40})"') { return $Matches[1] }
    throw "Could not parse latest commit SHA for $Owner/$Repo@$Branch"
}

function Get-GitHubReleaseAssetUrl {
    param([string]$Owner, [string]$Repo, [string]$Tag, [string]$AssetFilter)
    $url     = "https://api.github.com/repos/$Owner/$Repo/releases/tags/$Tag"
    $json    = Invoke-GitHubJsonRequest $url
    $allUrls = [regex]::Matches($json, '"browser_download_url"\s*:\s*"([^"]+)"') |
               ForEach-Object { $_.Groups[1].Value }
    $filter  = $AssetFilter -replace '\*','.*'
    foreach ($u in $allUrls) {
        $fname = ($u -split '/')[-1]
        if ($fname -match $filter) { return $u }
    }
    throw "No asset matching '$AssetFilter' found in release $Tag of $Owner/$Repo"
}

# ---- Download + cache -------------------------------------------------------
function Update-GitHubTool {
    param([PSCustomObject]$Tool, [switch]$Force)

    $cacheDir = Get-GitHubToolCachePath -ToolId $Tool.Id

    # Set TLS 1.2
    [Net.ServicePointManager]::SecurityProtocol = [Net.ServicePointManager]::SecurityProtocol -bor [Net.SecurityProtocolType]::Tls12

    switch ($Tool.SourceType) {

        'GitHubRaw' {
            $sha      = Get-GitHubLatestCommitSha -Owner $Tool.RepoOwner -Repo $Tool.RepoName -Branch $Tool.Branch
            $meta     = Read-GitHubToolMetadata -ToolId $Tool.Id
            $destPath = Join-Path $cacheDir $Tool.EntryScript

            if (-not $Force -and $null -ne $meta -and $meta.ResolvedRef -eq $sha -and (Test-Path -LiteralPath $destPath)) {
                return [PSCustomObject]@{ LocalPath = $destPath; Updated = $false; Ref = $sha }
            }

            $rawUrl = "https://raw.githubusercontent.com/$($Tool.RepoOwner)/$($Tool.RepoName)/$($Tool.Branch)/$($Tool.ScriptPath)"
            $wc     = New-Object System.Net.WebClient
            $wc.Headers.Add('User-Agent', 'Spectre-Launcher/2.1')
            $bytes  = $wc.DownloadData($rawUrl)
            [System.IO.File]::WriteAllBytes($destPath, $bytes)

            $sha256 = (Get-FileHash -LiteralPath $destPath -Algorithm SHA256).Hash
            Write-GitHubToolMetadata -ToolId $Tool.Id -ResolvedRef $sha -LocalPath $destPath -Sha256 $sha256
            return [PSCustomObject]@{ LocalPath = $destPath; Updated = $true; Ref = $sha }
        }

        'GitHubRelease' {
            $tag      = Get-GitHubLatestTag -Owner $Tool.RepoOwner -Repo $Tool.RepoName
            $meta     = Read-GitHubToolMetadata -ToolId $Tool.Id
            $destPath = Join-Path $cacheDir $Tool.EntryScript

            if (-not $Force -and $null -ne $meta -and $meta.ResolvedRef -eq $tag -and (Test-Path -LiteralPath $destPath)) {
                return [PSCustomObject]@{ LocalPath = $destPath; Updated = $false; Ref = $tag }
            }

            $assetUrl = Get-GitHubReleaseAssetUrl -Owner $Tool.RepoOwner -Repo $Tool.RepoName -Tag $tag -AssetFilter $Tool.AssetFilter
            $wc       = New-Object System.Net.WebClient
            $wc.Headers.Add('User-Agent', 'Spectre-Launcher/2.1')
            $bytes    = $wc.DownloadData($assetUrl)
            [System.IO.File]::WriteAllBytes($destPath, $bytes)

            $sha256 = (Get-FileHash -LiteralPath $destPath -Algorithm SHA256).Hash
            Write-GitHubToolMetadata -ToolId $Tool.Id -ResolvedRef $tag -LocalPath $destPath -Sha256 $sha256
            return [PSCustomObject]@{ LocalPath = $destPath; Updated = $true; Ref = $tag }
        }

        'GitHubReleaseZip' {
            $tag    = Get-GitHubLatestTag -Owner $Tool.RepoOwner -Repo $Tool.RepoName
            $meta   = Read-GitHubToolMetadata -ToolId $Tool.Id
            $entry  = Join-Path $cacheDir $Tool.EntryScript

            if ($null -ne $meta -and $meta.ResolvedRef -eq $tag -and (Test-Path -LiteralPath $entry)) {
                return [PSCustomObject]@{ LocalPath = $entry; Updated = $false; Ref = $tag }
            }

            $assetUrl = Get-GitHubReleaseAssetUrl -Owner $Tool.RepoOwner -Repo $Tool.RepoName -Tag $tag -AssetFilter $Tool.AssetFilter
            $zipPath  = Join-Path $env:TEMP "$($Tool.Id)-$tag.zip"
            $wc       = New-Object System.Net.WebClient
            $wc.Headers.Add('User-Agent', 'Spectre-Launcher/2.1')
            $wc.DownloadFile($assetUrl, $zipPath)

            # Extract using .NET (PS 3.0 compatible)
            Add-Type -AssemblyName System.IO.Compression.FileSystem -ErrorAction SilentlyContinue
            if (Test-Path -LiteralPath $cacheDir) {
                # Remove old files except tool.json
                Get-ChildItem -LiteralPath $cacheDir -Exclude 'tool.json' -ErrorAction SilentlyContinue |
                    Remove-Item -Recurse -Force -ErrorAction SilentlyContinue
            }
            [System.IO.Compression.ZipFile]::ExtractToDirectory($zipPath, $cacheDir)
            Remove-Item -LiteralPath $zipPath -Force -ErrorAction SilentlyContinue

            # Find entry script (may be in a subdirectory)
            $found = Get-ChildItem -LiteralPath $cacheDir -Recurse -Filter $Tool.EntryScript -ErrorAction SilentlyContinue |
                     Select-Object -First 1
            if ($null -eq $found) { throw "Entry script '$($Tool.EntryScript)' not found after extraction." }

            $sha256 = (Get-FileHash -LiteralPath $found.FullName -Algorithm SHA256).Hash
            Write-GitHubToolMetadata -ToolId $Tool.Id -ResolvedRef $tag -LocalPath $found.FullName -Sha256 $sha256
            return [PSCustomObject]@{ LocalPath = $found.FullName; Updated = $true; Ref = $tag }
        }


        'GitHubRepoBranchZip' {
            $sha  = Get-GitHubLatestCommitSha -Owner $Tool.RepoOwner -Repo $Tool.RepoName -Branch $Tool.Branch
            $meta = Read-GitHubToolMetadata -ToolId $Tool.Id
            $prevPath = if ($null -ne $meta) { $meta.LocalPath } else { '' }

            # Skip re-download only when: not forced, ref matches, file exists
            if (-not $Force -and $null -ne $meta -and $meta.ResolvedRef -eq $sha -and
                -not [string]::IsNullOrWhiteSpace($prevPath) -and (Test-Path -LiteralPath $prevPath)) {
                return [PSCustomObject]@{ LocalPath = $prevPath; Updated = $false; Ref = $sha }
            }

            $zipUrl  = "https://api.github.com/repos/$($Tool.RepoOwner)/$($Tool.RepoName)/zipball/$($Tool.Branch)"
            $zipPath = Join-Path $env:TEMP "$($Tool.Id)-$sha.zip"
            $wc      = New-Object System.Net.WebClient
            $wc.Headers.Add('User-Agent', 'Spectre-Launcher/2.1')
            $wc.DownloadFile($zipUrl, $zipPath)

            # Nuke the entire cache dir so ZipFile::ExtractToDirectory never hits an
            # existing folder (it throws on collision). Recreate empty dir after.
            if (Test-Path -LiteralPath $cacheDir) {
                Remove-Item -LiteralPath $cacheDir -Recurse -Force -ErrorAction SilentlyContinue
            }
            New-Item -ItemType Directory -Path $cacheDir -Force -ErrorAction SilentlyContinue | Out-Null

            Add-Type -AssemblyName System.IO.Compression.FileSystem -ErrorAction SilentlyContinue
            [System.IO.Compression.ZipFile]::ExtractToDirectory($zipPath, $cacheDir)
            Remove-Item -LiteralPath $zipPath -Force -ErrorAction SilentlyContinue

            # GitHub wraps contents in Owner-Repo-shortsha/ subfolder -- find entry script
            $found = Get-ChildItem -LiteralPath $cacheDir -Recurse -Filter $Tool.EntryScript -ErrorAction SilentlyContinue |
                     Select-Object -First 1
            if ($null -eq $found) { throw "Entry script '$($Tool.EntryScript)' not found after extraction." }

            $sha256 = (Get-FileHash -LiteralPath $found.FullName -Algorithm SHA256).Hash
            Write-GitHubToolMetadata -ToolId $Tool.Id -ResolvedRef $sha -LocalPath $found.FullName -Sha256 $sha256
            return [PSCustomObject]@{ LocalPath = $found.FullName; Updated = $true; Ref = $sha }
        }

        default { throw "Unknown SourceType: $($Tool.SourceType)" }
    }
}

# ---- UI population + wire-up ------------------------------------------------
function Initialize-GitHubToolsPanel {
    if ($null -eq $script:CmbGitHubTools) { return }

    $script:CmbGitHubTools.Items.Clear()
    foreach ($t in $script:GitHubToolManifest) {
        $label = "[$($t.Category)]  $($t.DisplayName)"
        $script:CmbGitHubTools.Items.Add($label) | Out-Null
    }
    if ($script:CmbGitHubTools.Items.Count -gt 0) {
        $script:CmbGitHubTools.SelectedIndex = 0
        Update-GitHubToolUI
    }
}

function Get-SelectedGitHubTool {
    $idx = $script:CmbGitHubTools.SelectedIndex
    if ($idx -lt 0 -or $idx -ge $script:GitHubToolManifest.Count) { return $null }
    return $script:GitHubToolManifest[$idx]
}

function Update-GitHubPresetDropdown {
    param([PSCustomObject]$Tool)
    if ($null -eq $script:CmbGitHubPreset) { return }
    $script:CmbGitHubPreset.Items.Clear()
    if ($null -eq $Tool -or $null -eq $Tool.Presets) { return }
    foreach ($p in $Tool.Presets) {
        $script:CmbGitHubPreset.Items.Add($p.Name) | Out-Null
    }
    if ($script:CmbGitHubPreset.Items.Count -gt 0) {
        $script:CmbGitHubPreset.SelectedIndex = 0
        Update-GitHubArgsFromPreset -Tool $Tool
    }
}

function Update-GitHubArgsFromPreset {
    param([PSCustomObject]$Tool)
    if ($null -eq $script:CmbGitHubPreset -or $null -eq $script:TxtGitHubArgs) { return }
    $idx = $script:CmbGitHubPreset.SelectedIndex
    if ($null -eq $Tool -or $null -eq $Tool.Presets -or $idx -lt 0 -or $idx -ge $Tool.Presets.Count) {
        $script:TxtGitHubArgs.Text = ''
        if ($null -ne $script:LblGitHubPresetNote) { $script:LblGitHubPresetNote.Text = '' }
        return
    }
    $preset = $Tool.Presets[$idx]
    $script:TxtGitHubArgs.Text = $preset.Args
    if ($null -ne $script:LblGitHubPresetNote) {
        $script:LblGitHubPresetNote.Text = $preset.Note
    }
}

function Update-GitHubToolUI {
    $tool = Get-SelectedGitHubTool
    if ($null -eq $tool) { return }

    # Warning label
    if ($null -ne $script:LblGitHubWarning) {
        if (-not [string]::IsNullOrWhiteSpace($tool.Warning)) {
            $script:LblGitHubWarning.Text       = "WARNING: $($tool.Warning)"
            $script:LblGitHubWarning.Visibility = [System.Windows.Visibility]::Visible
        } else {
            $script:LblGitHubWarning.Text       = ''
            $script:LblGitHubWarning.Visibility = [System.Windows.Visibility]::Collapsed
        }
    }

    # Preset dropdown
    Update-GitHubPresetDropdown -Tool $tool

    # Status line
    $meta = Read-GitHubToolMetadata -ToolId $tool.Id
    if ($null -ne $meta -and -not [string]::IsNullOrWhiteSpace($meta.LocalPath) -and (Test-Path -LiteralPath $meta.LocalPath)) {
        $script:LblGitHubStatus.Text       = "Cached: $($meta.ResolvedRef)  |  $($meta.LastUpdatedUtc)  |  $($tool.Description)"
        $script:LblGitHubStatus.Foreground = [System.Windows.Media.Brushes]::LimeGreen
    } else {
        $script:LblGitHubStatus.Text       = "Not downloaded.  |  $($tool.Description)"
        $script:LblGitHubStatus.Foreground = [System.Windows.Media.Brushes]::Gray
    }
}

# Alias kept so existing SelectionChanged handler still works
function Update-GitHubToolStatus { Update-GitHubToolUI }

function Invoke-GitHubToolUpdate {
    param([switch]$ForceFlag)
    $tool = Get-SelectedGitHubTool
    if ($null -eq $tool) { return }

    $label = if ($ForceFlag) { 'Force re-downloading' } else { 'Downloading' }
    $script:LblGitHubStatus.Text       = "$label $($tool.DisplayName)..."
    $script:LblGitHubStatus.Foreground = [System.Windows.Media.Brushes]::Yellow
    $script:BtnGitHubUpdate.IsEnabled       = $false
    if ($null -ne $script:BtnGitHubForceUpdate) { $script:BtnGitHubForceUpdate.IsEnabled = $false }

    $result = $null
    $err    = $null
    try {
        if ($ForceFlag) {
            $result = Update-GitHubTool -Tool $tool -Force
        } else {
            $result = Update-GitHubTool -Tool $tool
        }
    } catch {
        $err = "$_"
    }

    $script:BtnGitHubUpdate.IsEnabled = $true
    if ($null -ne $script:BtnGitHubForceUpdate) { $script:BtnGitHubForceUpdate.IsEnabled = $true }
    if ($null -ne $err) {
        Add-LogEntry -Level 'FAIL' -Message "GitHub Tools: update failed for $($tool.DisplayName): $err"
        $script:LblGitHubStatus.Text       = "Update failed: $err"
        $script:LblGitHubStatus.Foreground = [System.Windows.Media.Brushes]::OrangeRed
    } else {
        $verb = if ($result.Updated) { 'Downloaded' } else { 'Already current' }
        Add-LogEntry -Level 'INFO' -Message "GitHub Tools: $verb $($tool.DisplayName) @ $($result.Ref)"
        Protect-GitHubToolCache
        Update-GitHubToolUI
    }
}

function Invoke-GitHubToolLaunch {
    $tool = Get-SelectedGitHubTool
    if ($null -eq $tool) { return }
    $meta = Read-GitHubToolMetadata -ToolId $tool.Id
    if ($null -eq $meta -or [string]::IsNullOrWhiteSpace($meta.LocalPath) -or -not (Test-Path -LiteralPath $meta.LocalPath)) {
        Add-LogEntry -Level 'WARN' -Message "GitHub Tools: $($tool.DisplayName) not cached -- click Update first."
        return
    }
    # Get arguments from the editable args box (preset may have populated it)
    $args = if ($null -ne $script:TxtGitHubArgs) { $script:TxtGitHubArgs.Text.Trim() } else { '' }

    $script:TxtPayload.Text = $meta.LocalPath
    # Write args into the existing Boot Manifest args field if present
    if ($null -ne $script:TxtArgs -and -not [string]::IsNullOrWhiteSpace($args)) {
        $script:TxtArgs.Text = $args
    }
    Add-LogEntry -Level 'INFO' -Message "GitHub Tools: loaded $($tool.DisplayName)$(if($args){' args: '+$args})"
    Invoke-SmartAutoConfig -ScriptPath $meta.LocalPath
}

function Open-GitHubToolCacheFolder {
    $tool = Get-SelectedGitHubTool
    if ($null -eq $tool) { return }
    $dir = Get-GitHubToolCachePath -ToolId $tool.Id
    Start-Process explorer.exe -ArgumentList $dir
}

#------------------------------------------------------------------------------
# Protect-GitHubToolCache
# Adds a persistent Defender exclusion on the cache root and signs any cached
# .ps1 files with the Charles Hayes code-signing cert (same cert the BAT uses).
# Persistent exclusion survives beyond this process -- covers child powershell
# processes spawned by tools like WinUtil that use irm|iex at runtime.
# Safe to call multiple times -- both operations are idempotent.
#------------------------------------------------------------------------------
function Protect-GitHubToolCache {
    $cacheRoot = Get-GitHubToolCacheRoot

    # ---- Layer 1: Persistent Defender exclusion on cache root ---------------
    # Add-MpPreference ExclusionPath is NOT removed by Restore-Defender.
    # It persists in Defender settings and covers all child processes that
    # read from or write to this folder -- including WinUtil's irm|iex child.
    $cmdAdd    = 'Add-Mp'     + 'Preference'
    $cmdGet    = 'Get-Mp'     + 'Preference'
    $pExclPath = 'Exclusion'  + 'Path'

    try {
        $svcState = Get-DefenderServiceState
        if ($svcState -eq 'Running') {
            $prefs    = & $cmdGet -ErrorAction Stop
            $existing = $prefs.$pExclPath
            $alreadyExcluded = ($null -ne $existing) -and
                               ($existing | Where-Object { $_ -like "$cacheRoot*" } |
                                Select-Object -First 1)
            if (-not $alreadyExcluded) {
                $addArgs = @{ $pExclPath = $cacheRoot; ErrorAction = 'Stop' }
                & $cmdAdd @addArgs
                Add-LogEntry -Level 'PASS' -Message "[Shield] Persistent exclusion added: $cacheRoot"
            } else {
                Add-LogEntry -Level 'INFO' -Message "[Shield] Exclusion already set: $cacheRoot"
            }
        } else {
            Add-LogEntry -Level 'INFO' -Message "[Shield] Defender not active -- exclusion skipped"
        }
    } catch {
        Add-LogEntry -Level 'WARN' -Message "[Shield] Exclusion failed (Tamper Protection may be ON): $_"
        Add-LogEntry -Level 'WARN' -Message "[Shield] Fix: Windows Security > Virus protection > Manage settings > Tamper Protection OFF"
    }

    # ---- Layer 2: Sign cached .ps1 files with code-signing cert -------------
    # Finds the Charles Hayes cert (or any code-signing cert in CurrentUser\My
    # or LocalMachine\My). Signs all .ps1 files in the cache root recursively.
    # Signed scripts from a TrustedPublisher cert bypass AMSI content scanning.
    try {
        $cert = $null
        foreach ($store in @('Cert:\CurrentUser\My', 'Cert:\LocalMachine\My')) {
            $cert = Get-ChildItem -Path $store -CodeSigningCert -ErrorAction SilentlyContinue |
                    Sort-Object NotAfter -Descending |
                    Select-Object -First 1
            if ($cert) { break }
        }
        if ($null -eq $cert) {
            Add-LogEntry -Level 'WARN' -Message "[Shield] No code-signing cert found -- run BAT wrapper once to create it"
        } else {
            $ps1Files = Get-ChildItem -LiteralPath $cacheRoot -Recurse -Filter '*.ps1' -ErrorAction SilentlyContinue
            $signed   = 0
            $skipped  = 0
            foreach ($f in $ps1Files) {
                try {
                    $existing = Get-AuthenticodeSignature -FilePath $f.FullName -ErrorAction SilentlyContinue
                    if ($existing.Status -eq 'Valid') {
                        $skipped++
                        continue
                    }
                    $null = Set-AuthenticodeSignature -FilePath $f.FullName `
                                -Certificate $cert -ErrorAction Stop
                    $signed++
                } catch {
                    Add-LogEntry -Level 'WARN' -Message "[Shield] Sign failed for $($f.Name): $_"
                }
            }
            if ($signed -gt 0) {
                Add-LogEntry -Level 'PASS' -Message "[Shield] Signed $signed cached script(s) [CN=$($cert.Subject)] -- $skipped already valid"
            } else {
                Add-LogEntry -Level 'INFO' -Message "[Shield] All $skipped cached script(s) already signed [CN=$($cert.Subject)]"
            }
        }
    } catch {
        Add-LogEntry -Level 'WARN' -Message "[Shield] Signing pass failed (non-fatal): $_"
    }
}

