# Selecting a library item loads it into the payload field
$script:CmbLibrary.Add_SelectionChanged({
    $sel = $script:CmbLibrary.SelectedItem
    if ($null -eq $sel) { return }
    $selStr = $sel.ToString()

    # Ignore separator and placeholder items
    if ($selStr -eq '--- Recent ---') { return }
    if ($selStr -like '(no scripts*')  { return }

    # Items are now full paths
    if (Test-Path -LiteralPath $selStr -PathType Leaf -ErrorAction SilentlyContinue) {
        $script:TxtPayload.Text = $selStr
        Add-LogEntry -Level 'INFO' -Message "Loaded: $selStr"
        Invoke-SmartAutoConfig -ScriptPath $selStr
    } else {
        Add-LogEntry -Level 'WARN' -Message "File no longer found: $selStr -- refreshing list."
        Update-LibraryDropdown
    }
})

$script:BtnRefreshLibrary.Add_Click({
    Update-LibraryDropdown
    Add-LogEntry -Level 'INFO' -Message "Script library refreshed: $(Get-LibraryPath)"
})

