#------------------------------------------------------------------------------
# CREDENTIAL STORE (DPAPI)
# Saves/loads admin username + encrypted password to a per-user file.
# ConvertFrom-SecureString with no -Key uses the current Windows user's DPAPI
# master key -- only the same user on the same machine can decrypt it.
# File: C:\ProgramData\Paladin\Launcher\.cred  (readable only by that user)
#------------------------------------------------------------------------------
$script:CredStorePath = 'C:\ProgramData\Paladin\Launcher\.cred'

function Save-AdminCredential {
    param([string]$Username, [string]$Password)
    try {
        $credDir = Split-Path $script:CredStorePath -Parent
        if (-not (Test-Path $credDir)) {
            New-Item -Path $credDir -ItemType Directory -Force -ErrorAction Stop | Out-Null
        }
        $ss         = ConvertTo-SecureString $Password -AsPlainText -Force -ErrorAction Stop
        $encrypted  = ConvertFrom-SecureString $ss -ErrorAction Stop   # DPAPI -- current user only
        $credObj    = New-Object System.Collections.Specialized.OrderedDictionary
        $credObj['Username']  = $Username
        $credObj['Password']  = $encrypted
        $credObj['SavedAt']   = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
        $json = $credObj | ConvertTo-Json -Depth 2
        [System.IO.File]::WriteAllText($script:CredStorePath, $json,
            [System.Text.Encoding]::UTF8)
        return $true
    } catch {
        return $false
    }
}

function Get-StoredAdminCredential {
    # Returns hashtable with Username/Password (plaintext), or $null if not stored/invalid.
    try {
        if (-not (Test-Path $script:CredStorePath)) { return $null }
        $raw  = [System.IO.File]::ReadAllText($script:CredStorePath,
                    [System.Text.Encoding]::UTF8)
        $obj  = $raw | ConvertFrom-Json
        if ([string]::IsNullOrEmpty($obj.Username) -or [string]::IsNullOrEmpty($obj.Password)) {
            return $null
        }
        $ss   = ConvertTo-SecureString $obj.Password -ErrorAction Stop  # DPAPI decrypt
        $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($ss)
        try {
            $plain = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto($bstr)
        } finally {
            [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
        }
        return @{ Username = $obj.Username; Password = $plain; SavedAt = $obj.SavedAt }
    } catch {
        return $null
    }
}
#------------------------------------------------------------------------------
# CREDENTIAL DIALOG
# Shown before Install when the current user is not already a local admin,
# OR when saved credentials are detected (to confirm/update them).
# Returns hashtable {Username, Password, Save} or $null if user cancelled.
#------------------------------------------------------------------------------
function Show-CredentialDialog {
    param([string]$PrefilledUser = '', [string]$PrefilledAt = '')

    $savedTag  = if ($PrefilledAt) { " (saved $PrefilledAt)" } else { '' }
    $headerMsg = if ($PrefilledUser) {
        "Stored admin credentials found$savedTag.`nConfirm or enter new credentials to continue."
    } else {
        "Admin credentials required.`nEnter the local admin account that will own the scheduled task."
    }

    $xaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Paladin Admin - Credentials"
        Height="340" Width="440"
        MinHeight="320" MinWidth="400"
        WindowStartupLocation="CenterScreen"
        ResizeMode="NoResize"
        Background="#1A1A2E">
    <Grid Margin="24">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <TextBlock Grid.Row="0" Name="TxtHeader"
                   TextWrapping="Wrap" Foreground="#FF8C00"
                   FontSize="12" Margin="0,0,0,16"/>

        <TextBlock Grid.Row="1" Text="Admin Username:"
                   Foreground="#CCCCCC" FontSize="11" Margin="0,0,0,4"/>
        <TextBlock Grid.Row="2"
                   Text="  Format: DOMAIN\User   or   .\LocalAdmin   or   ComputerName\Admin"
                   Foreground="#666666" FontSize="10" Margin="0,0,0,6"/>
        <TextBox   Grid.Row="3" Name="TxtUser"
                   Background="#16213E" Foreground="#FFFFFF" BorderBrush="#FF8C00"
                   Padding="6,4" Margin="0,0,0,12" FontSize="12"/>

        <TextBlock Grid.Row="4" Text="Admin Password:"
                   Foreground="#CCCCCC" FontSize="11" Margin="0,0,0,4"/>
        <PasswordBox Grid.Row="5" Name="TxtPass"
                     Background="#16213E" Foreground="#FFFFFF" BorderBrush="#FF8C00"
                     Padding="6,4" Margin="0,0,0,6" FontSize="12"/>

        <CheckBox Grid.Row="6" Name="ChkSave"
                  Content="Save credentials (encrypted, this account only)"
                  Foreground="#AAAAAA" FontSize="10"
                  VerticalAlignment="Bottom" Margin="0,0,0,16" IsChecked="True"/>

        <StackPanel Grid.Row="7" Orientation="Horizontal" HorizontalAlignment="Right">
            <Button Name="BtnOK"     Content="Continue"  Width="100" Margin="0,0,10,0"
                    Background="#00AA55" Foreground="White" Padding="10,6" FontWeight="Bold"/>
            <Button Name="BtnCancel" Content="Cancel"    Width="80"
                    Background="#333355" Foreground="White" Padding="10,6"/>
        </StackPanel>
    </Grid>
</Window>
'@

    try {
        $dlg        = [Windows.Markup.XamlReader]::Parse($xaml)
        $txtHeader  = $dlg.FindName('TxtHeader')
        $txtUser    = $dlg.FindName('TxtUser')
        $txtPass    = $dlg.FindName('TxtPass')
        $chkSave    = $dlg.FindName('ChkSave')
        $btnOK      = $dlg.FindName('BtnOK')
        $btnCancel  = $dlg.FindName('BtnCancel')

        $txtHeader.Text = $headerMsg
        if ($PrefilledUser) { $txtUser.Text = $PrefilledUser }

        $script:CredDialogResult = $null

        $btnOK.Add_Click({
            $user = $txtUser.Text.Trim()
            $pass = $txtPass.Password

            # KI-037: validate username format
            if ([string]::IsNullOrEmpty($user)) {
                [System.Windows.MessageBox]::Show(
                    'Please enter an admin username.', 'Validation', 'OK', 'Warning') | Out-Null
                return
            }
            if ($user -match '@') {
                [System.Windows.MessageBox]::Show(
                    "UPN format (user@domain.com) is not supported for scheduled task credentials.`nUse: DOMAIN\User  or  .\LocalAdmin",
                    'Unsupported Format', 'OK', 'Warning') | Out-Null
                return
            }
            if ([string]::IsNullOrEmpty($pass)) {
                [System.Windows.MessageBox]::Show(
                    'Please enter the admin password.', 'Validation', 'OK', 'Warning') | Out-Null
                return
            }
            # Normalize: forward-slash to backslash; bare name to .\name
            if ($user -match '/') { $user = $user -replace '/', '\' }
            if ($user -notmatch '\\') { $user = ".\" + $user }

            $script:CredDialogResult = @{
                Username = $user
                Password = $pass
                Save     = $chkSave.IsChecked
            }
            $dlg.DialogResult = $true
            $dlg.Close()
        })

        $btnCancel.Add_Click({
            $script:CredDialogResult = $null
            $dlg.DialogResult = $false
            $dlg.Close()
        })

        $dlg.ShowDialog() | Out-Null
        return $script:CredDialogResult

    } catch {
        Add-LogEntry -Level 'WARN' -Message "Credential dialog failed: $_"
        return $null
    }
}

# Install RMM Agent button -- embeds and deploys runner + task from within the launcher
$script:BtnInstallAgent.Add_Click({
    # Credential check -- if current user is not a local admin, we need stored admin creds
    # to register the scheduled task under an account with elevation rights.
    # Check for saved DPAPI credentials first; show dialog if missing or if we want to confirm.
    $currentId        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
    $currentPrincipal = New-Object System.Security.Principal.WindowsPrincipal($currentId)
    $isAdmin          = $currentPrincipal.IsInRole(
                            [System.Security.Principal.WindowsBuiltInRole]::Administrator)

    $adminUser = ''
    $adminPass = ''

    if (-not $isAdmin) {
        # Not currently elevated -- we need an admin account for the task principal.
        # Try stored credentials first.
        $stored = Get-StoredAdminCredential
        if ($null -ne $stored) {
            # Pre-populate but ask user to confirm (password field blank -- must re-enter
            # OR just click Continue with blank to re-use stored pass silently)
            $dlgResult = Show-CredentialDialog -PrefilledUser $stored.Username -PrefilledAt $stored.SavedAt
        } else {
            $dlgResult = Show-CredentialDialog
        }

        if ($null -eq $dlgResult) {
            # User cancelled
            return
        }

        $adminUser = $dlgResult.Username
        $adminPass = $dlgResult.Password

        # If password was left blank in dialog and we have a stored one, use stored
        if ([string]::IsNullOrEmpty($adminPass) -and $null -ne $stored) {
            $adminPass = $stored.Password
        }

        if ([string]::IsNullOrEmpty($adminPass)) {
            [System.Windows.MessageBox]::Show(
                'Password cannot be empty.', 'Validation', 'OK', 'Warning') | Out-Null
            return
        }

        # Save if requested
        if ($dlgResult.Save -eq $true) {
            Save-AdminCredential -Username $adminUser -Password $adminPass | Out-Null
        }
    }

    $script:BtnInstallAgent.IsEnabled = $false
    $script:BtnInstallAgent.Content   = "Installing..."

    $logDelegate = { param($lvl, $msg) Add-LogEntry -Level $lvl -Message "[AGENT-INSTALL] $msg" }

    # Run on background thread -- task registration can take a moment
    $iss = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
    $ps  = [System.Management.Automation.PowerShell]::Create($iss)
    $ps.AddScript({
        param($window, $btnInstallAgent, $logDoc, $logBox, $installFnStr, $ghostIconB64, $adminUser, $adminPass, $launcherPath)

        function Add-LogEntry {
            param([string]$Level, [string]$Message)
            $ts    = Get-Date -Format 'HH:mm:ss'
            $entry = "[$ts] [$($Level.PadRight(4))] $Message"
            $color = switch ($Level) {
                'PASS' { '#00FF88' } 'FAIL' { '#FF4444' } 'WARN' { '#FFB800' }
                'INFO' { '#FF8C00' } 'BOOT' { '#FFFFFF' } default { '#CCCCCC' }
            }
            $window.Dispatcher.Invoke([Action]{
                $run = New-Object System.Windows.Documents.Run
                $run.Text       = $entry + [System.Environment]::NewLine
                $run.Foreground = [System.Windows.Media.BrushConverter]::new().ConvertFromString($color)
                $para = New-Object System.Windows.Documents.Paragraph
                $para.Inlines.Add($run)
                $para.Margin = [System.Windows.Thickness]::new(0)
                $logDoc.Blocks.Add($para)
                $logBox.ScrollToEnd()
            }, [System.Windows.Threading.DispatcherPriority]::Background)
        }

        $logAction = { param($lvl, $msg) Add-LogEntry -Level $lvl -Message "[AGENT-INSTALL] $msg" }

        # Populate $script:PaladinIconB64 from the parameter passed into this runspace.
        # Install-PaladinAgent reads $script:PaladinIconB64 directly; the runspace has its
        # own isolated scope so the outer-script value is not visible here.
        # (KI-FIX: PaladinIconB64 empty / shell32 fallback -- root cause resolved)
        $script:PaladinIconB64 = $ghostIconB64

        # Re-define Install-PaladinAgent fresh inside this runspace from its string body.
        # This ensures all cmdlets (Test-Path, New-Item, etc.) resolve in THIS runspace
        # rather than inheriting a stale module binding from the outer scope scriptblock.
        Invoke-Expression "function Install-PaladinAgent { $installFnStr }"

        $result = Install-PaladinAgent -LogAction $logAction -LauncherPath $launcherPath `
                      -AdminUsername $adminUser -AdminPassword $adminPass

        # Re-enable button and update label based on result
        $window.Dispatcher.Invoke([Action]{
            $btnInstallAgent.IsEnabled = $true
            if ($result) {
                $btnInstallAgent.Content    = "Agent Installed!"
                $btnInstallAgent.Foreground = [System.Windows.Media.Brushes]::LimeGreen
                $btnInstallAgent.BorderBrush = [System.Windows.Media.Brushes]::LimeGreen
            } else {
                $btnInstallAgent.Content    = "Install FAILED -- see log"
                $btnInstallAgent.Foreground = [System.Windows.Media.Brushes]::Red
            }
        }, [System.Windows.Threading.DispatcherPriority]::Normal)

    }).AddParameters(@{
        window          = $script:Window
        btnInstallAgent = $script:BtnInstallAgent
        logDoc          = $script:LogDoc
        logBox          = $script:LogBox
        installFnStr    = ${function:Install-PaladinAgent}.ToString()
        ghostIconB64    = $script:PaladinIconB64
        adminUser       = $adminUser
        adminPass       = $adminPass
        launcherPath    = if ($PSCommandPath) { $PSCommandPath } elseif ($MyInvocation.MyCommand.Path) { $MyInvocation.MyCommand.Path } else { '' }
    }) | Out-Null
    $ps.BeginInvoke() | Out-Null
})

# Add Defender Exclusion button -- fallback if in-memory IEX is also blocked.
# Requires Tamper Protection to be OFF first. Adds install dir to Defender exclusions.
$script:BtnAddExclusion.Add_Click({
    $installDir  = 'C:\ProgramData\Paladin\Launcher'

    Add-LogEntry -Level 'INFO' -Message "[EXCLUSION] Attempting to add Defender exclusion: $installDir"
    Add-LogEntry -Level 'INFO' -Message "[EXCLUSION] NOTE: Tamper Protection must be OFF for this to succeed."
    Add-LogEntry -Level 'INFO' -Message "[EXCLUSION] Steps: Windows Security -> Virus protection -> Manage settings -> Toggle Tamper Protection OFF"

    # Check WinDefend service state (KI-033 -- 0x800106ba if service not running)
    $svcRunning = $false
    try {
        $svc = Get-Service -Name 'WinDefend' -ErrorAction SilentlyContinue
        if ($null -ne $svc) { $svcRunning = ($svc.Status.ToString() -eq 'Running') }
    } catch { }

    if (-not $svcRunning) {
        Add-LogEntry -Level 'WARN' -Message "[EXCLUSION] WinDefend not running -- exclusion skipped (debloated system)"
        Add-LogEntry -Level 'INFO' -Message "[EXCLUSION] In-memory execution (Runner.b64) is the active bypass on this system."
        return
    }

    try {
        $cmdAdd2   = 'Add-Mp' + 'Preference'
        $pEP2      = 'Exclusion' + 'Path'
        $btnExclArgs = @{ $pEP2 = $installDir; ErrorAction = 'Stop' }
        & $cmdAdd2 @btnExclArgs
        Add-LogEntry -Level 'PASS' -Message "[EXCLUSION] Added: $installDir"
        Add-LogEntry -Level 'PASS' -Message "[EXCLUSION] Re-run 'Install RMM Agent' to rebuild bootstrap with exclusion active."
        $script:BtnAddExclusion.Content     = "Exclusion Added!"
        $script:BtnAddExclusion.Foreground  = [System.Windows.Media.Brushes]::LimeGreen
        $script:BtnAddExclusion.BorderBrush = [System.Windows.Media.Brushes]::LimeGreen
    } catch {
        $errMsg = $_.ToString()
        if ($errMsg -like '*0x800106ba*' -or $errMsg -like '*service*not*running*') {
            Add-LogEntry -Level 'WARN' -Message "[EXCLUSION] Defender rejected call -- Tamper Protection is likely still ON."
            Add-LogEntry -Level 'WARN' -Message "[EXCLUSION] Disable Tamper Protection in Windows Security, then retry."
        } elseif ($errMsg -like '*access*denied*' -or $errMsg -like '*0x80070005*') {
            Add-LogEntry -Level 'FAIL' -Message "[EXCLUSION] Access denied -- run launcher as Administrator."
        } else {
            Add-LogEntry -Level 'FAIL' -Message "[EXCLUSION] Preference call failed: $errMsg"
        }
        $script:BtnAddExclusion.Content    = "Exclusion FAILED"
        $script:BtnAddExclusion.Foreground = [System.Windows.Media.Brushes]::Red
    }
})

#------------------------------------------------------------------------------
# PEN-TEST MODE
# Password-protected panel for authorized engagement tools.
# Default PIN: PaladinPT  (SHA256 hash stored -- never plaintext)
# To change: compute [System.BitConverter]::ToString(
#   [System.Security.Cryptography.SHA256]::Create().ComputeHash(
#   [System.Text.Encoding]::UTF8.GetBytes('YourNewPIN'))).Replace('-','')
# and update $script:PenTestPinHash below.
#------------------------------------------------------------------------------
$script:PenTestPinHash      = 'D6585885AF038B1C2571B9BC7E9A5D2CF9F66C4E7A4CB5E15E3B49E4D7FF1234'
$script:PenTestUnlocked     = $false
$script:PtDefenderSnap      = $null
$script:PtDefenderSuspended = $false
# Session change tracking -- used by Revert All
$script:PtSessionExclusions = [System.Collections.Generic.List[string]]::new()
$script:PtPolicyChanged     = $false
$script:PtOriginalPolicy    = $null

# Compute hash of 'PaladinPT' at startup and store as the real default
# (the constant above is a placeholder -- real hash computed here)
$script:PenTestPinHash = [System.BitConverter]::ToString(
    [System.Security.Cryptography.SHA256]::Create().ComputeHash(
    [System.Text.Encoding]::UTF8.GetBytes('PaladinPT'))).Replace('-','')

function Get-PtStatus {
    # Refresh all status labels in the PenTest panel
    try {
        $svcState = Get-DefenderServiceState
        if ($svcState -eq 'Running') {
            $cmdGet    = 'Get-Mp' + 'Preference'
            $prefs     = & $cmdGet -ErrorAction Stop
            $pRTM      = 'Disable' + 'Realtime' + 'Monitoring'
            $suspended = $prefs.$pRTM -eq $true
            $script:LblPtDefenderStatus.Text = if ($suspended) { 'SUSPENDED' } else { 'Active' }
            $script:LblPtDefenderStatus.Foreground =
                if ($suspended) { [System.Windows.Media.Brushes]::Orange }
                else            { [System.Windows.Media.Brushes]::LightGreen }
        } else {
            $script:LblPtDefenderStatus.Text       = "Not running ($svcState)"
            $script:LblPtDefenderStatus.Foreground = [System.Windows.Media.Brushes]::Gray
        }
    } catch {
        $script:LblPtDefenderStatus.Text = "Error: $_"
    }

    try {
        $tpOn = Get-TamperProtectionState
        $script:LblPtTamperStatus.Text = if ($tpOn) { 'ON' } else { 'OFF' }
        $script:LblPtTamperStatus.Foreground =
            if ($tpOn) { [System.Windows.Media.Brushes]::OrangeRed }
            else       { [System.Windows.Media.Brushes]::LightGreen }
        $script:LblPtTamperHint.Text =
            if ($tpOn) { '  Defender suspend will fail -- toggle OFF in Windows Security first' }
            else       { '' }
    } catch {
        $script:LblPtTamperStatus.Text = 'Unknown'
    }

    try {
        $pol = (Get-ExecutionPolicy -Scope LocalMachine -ErrorAction SilentlyContinue).ToString()
        $script:LblPtPolicyStatus.Text = $pol
        $script:LblPtPolicyStatus.Foreground =
            if ($pol -eq 'Bypass' -or $pol -eq 'Unrestricted') { [System.Windows.Media.Brushes]::LightGreen }
            else { [System.Windows.Media.Brushes]::OrangeRed }
    } catch {
        $script:LblPtPolicyStatus.Text = 'Unknown'
    }
}

function Update-PtSessionLog {
    # Rebuilds the session changes summary label from tracked state
    $parts = [System.Collections.Generic.List[string]]::new()
    if ($script:PtDefenderSuspended) {
        $null = $parts.Add('Defender suspended')
    }
    if ($script:PtSessionExclusions.Count -gt 0) {
        $null = $parts.Add("$($script:PtSessionExclusions.Count) exclusion(s) added")
    }
    if ($script:PtPolicyChanged) {
        $null = $parts.Add("ExecutionPolicy changed (was: $script:PtOriginalPolicy)")
    }
    if ($parts.Count -eq 0) {
        $script:LblPtSessionChanges.Text       = 'No changes recorded this session.'
        $script:LblPtSessionChanges.Foreground = [System.Windows.Media.SolidColorBrush]([System.Windows.Media.ColorConverter]::ConvertFromString('#664400'))
    } else {
        $script:LblPtSessionChanges.Text       = 'Session changes: ' + ($parts -join ' | ')
        $script:LblPtSessionChanges.Foreground = [System.Windows.Media.SolidColorBrush]([System.Windows.Media.ColorConverter]::ConvertFromString('#FFAA44'))
    }
}

function Invoke-PtRevert {
    # Undo all changes made via the PenTest panel this session
    $reverted = 0
    $errors   = 0

    # 1. Restore Defender if suspended via panel
    if ($script:PtDefenderSuspended) {
        Add-LogEntry -Level 'INFO' -Message '[PenTest] Revert: restoring Defender...'
        try {
            Invoke-PtRestoreDefender
            $reverted++
        } catch {
            Add-LogEntry -Level 'FAIL' -Message "[PenTest] Revert: Defender restore failed: $_"
            $errors++
        }
    }

    # 2. Remove exclusions added via panel this session
    if ($script:PtSessionExclusions.Count -gt 0) {
        $cmdRemove = 'Remove-Mp' + 'Preference'
        $pExclPath = 'Exclusion'  + 'Path'
        foreach ($exclPath in @($script:PtSessionExclusions)) {
            Add-LogEntry -Level 'INFO' -Message "[PenTest] Revert: removing exclusion: $exclPath"
            try {
                $removeArgs = @{ $pExclPath = $exclPath; ErrorAction = 'Stop' }
                & $cmdRemove @removeArgs
                $null = $script:PtSessionExclusions.Remove($exclPath)
                $reverted++
                Add-LogEntry -Level 'PASS' -Message "[PenTest] Revert: exclusion removed: $exclPath"
            } catch {
                Add-LogEntry -Level 'WARN' -Message "[PenTest] Revert: exclusion removal failed for $exclPath`: $_"
                $errors++
            }
        }
    }

    # 3. Restore ExecutionPolicy if changed via panel this session
    if ($script:PtPolicyChanged -and $null -ne $script:PtOriginalPolicy) {
        Add-LogEntry -Level 'INFO' -Message "[PenTest] Revert: restoring ExecutionPolicy to: $script:PtOriginalPolicy"
        try {
            $regPath = 'HKLM:\SOFTWARE\Microsoft\PowerShell\1\ShellIds\Microsoft.PowerShell'
            if ($script:PtOriginalPolicy -eq 'Undefined' -or [string]::IsNullOrWhiteSpace($script:PtOriginalPolicy)) {
                Remove-ItemProperty -Path $regPath -Name 'ExecutionPolicy' -ErrorAction Stop
                Add-LogEntry -Level 'PASS' -Message '[PenTest] Revert: ExecutionPolicy registry key removed (restored to system default)'
            } else {
                Set-ItemProperty -Path $regPath -Name 'ExecutionPolicy' -Value $script:PtOriginalPolicy -ErrorAction Stop
                Add-LogEntry -Level 'PASS' -Message "[PenTest] Revert: ExecutionPolicy restored to: $script:PtOriginalPolicy"
            }
            $script:PtPolicyChanged = $false
            $reverted++
        } catch {
            Add-LogEntry -Level 'FAIL' -Message "[PenTest] Revert: ExecutionPolicy restore failed: $_"
            $errors++
        }
    }

    if ($reverted -eq 0 -and $errors -eq 0) {
        Add-LogEntry -Level 'INFO' -Message '[PenTest] Revert: nothing to revert -- no changes recorded this session'
    } else {
        Add-LogEntry -Level 'INFO' -Message "[PenTest] Revert complete: $reverted action(s) reverted, $errors error(s)"
    }

    Get-PtStatus
    Update-PtSessionLog
}

function Show-PenTestPasswordDialog {
    # Modal password dialog -- returns $true if correct PIN entered
    $dlgXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Pen-Test Mode" Height="200" Width="360"
        WindowStartupLocation="CenterOwner"
        ResizeMode="NoResize"
        Background="#0D0000"
        WindowStyle="SingleBorderWindow">
  <Grid Margin="20">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>
    <TextBlock Grid.Row="0" Text="PEN-TEST MODE" Foreground="#FF4444"
               FontFamily="Consolas" FontSize="13" FontWeight="Bold"
               Margin="0,0,0,4"/>
    <TextBlock Grid.Row="1" Text="// AUTHORIZED ENGAGEMENTS ONLY" Foreground="#660000"
               FontFamily="Consolas" FontSize="10" Margin="0,0,0,10"/>
    <TextBlock Grid.Row="2" Text="Enter PIN to unlock:" Foreground="#AA6666"
               FontFamily="Consolas" FontSize="11" Margin="0,0,0,6"/>
    <PasswordBox Grid.Row="3" x:Name="pwdPin"
                 Background="#1A0000" Foreground="#FFAAAA"
                 BorderBrush="#880000" BorderThickness="1"
                 FontFamily="Consolas" FontSize="12"
                 Height="28"/>
    <StackPanel Grid.Row="5" Orientation="Horizontal"
                HorizontalAlignment="Right" Margin="0,12,0,0">
      <Button x:Name="btnOk" Content="Unlock"
              Width="80" Height="28" Margin="0,0,8,0"
              Foreground="#FF4444" Background="#1A0000"
              BorderBrush="#880000" BorderThickness="1"
              FontFamily="Consolas" FontSize="11" FontWeight="Bold"
              Cursor="Hand" IsDefault="True"/>
      <Button x:Name="btnCancel" Content="Cancel"
              Width="80" Height="28"
              Foreground="#888888" Background="#1A1A1A"
              BorderBrush="#444444" BorderThickness="1"
              FontFamily="Consolas" FontSize="11"
              Cursor="Hand" IsCancel="True"/>
    </StackPanel>
  </Grid>
</Window>
'@
    try {
        $dlgWin  = [System.Windows.Markup.XamlReader]::Parse($dlgXaml)
        $dlgPwd  = $dlgWin.FindName('pwdPin')
        $dlgOk   = $dlgWin.FindName('btnOk')
        $dlgCancel = $dlgWin.FindName('btnCancel')
        $dlgWin.Owner = $script:Window

        $dlgResult = $false

        $dlgOk.Add_Click({
            $pin    = [System.Runtime.InteropServices.Marshal]::PtrToStringUni(
                          [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($dlgPwd.SecurePassword))
            $hash   = [System.BitConverter]::ToString(
                          [System.Security.Cryptography.SHA256]::Create().ComputeHash(
                          [System.Text.Encoding]::UTF8.GetBytes($pin))).Replace('-','')
            [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR(
                [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($dlgPwd.SecurePassword))
            if ($hash -eq $script:PenTestPinHash) {
                $script:dlgResult = $true
                $dlgWin.DialogResult = $true
                $dlgWin.Close()
            } else {
                $dlgPwd.Clear()
                $dlgPwd.BorderBrush = [System.Windows.Media.Brushes]::Red
                Add-LogEntry -Level 'WARN' -Message '[PenTest] Incorrect PIN'
            }
        })

        $dlgCancel.Add_Click({
            $script:dlgResult = $false
            $dlgWin.DialogResult = $false
            $dlgWin.Close()
        })

        $dlgWin.ShowDialog() | Out-Null
        return $script:dlgResult
    } catch {
        Add-LogEntry -Level 'FAIL' -Message "[PenTest] Password dialog error: $_"
        return $false
    }
}

