    try {
        $regPath = 'HKLM:\SOFTWARE\Microsoft\PowerShell\1\ShellIds\Microsoft.PowerShell'
        # Snapshot original before changing (only record once per session)
        if (-not $script:PtPolicyChanged) {
            $existing = Get-ItemProperty -Path $regPath -Name 'ExecutionPolicy' -ErrorAction SilentlyContinue
            $script:PtOriginalPolicy = if ($existing) { $existing.ExecutionPolicy } else { 'Undefined' }
        }
        Set-ItemProperty -Path $regPath -Name 'ExecutionPolicy' -Value 'Bypass' -ErrorAction Stop
        $script:PtPolicyChanged = $true
        Add-LogEntry -Level 'PASS' -Message "[PenTest] ExecutionPolicy set to Bypass (was: $script:PtOriginalPolicy)"
        Get-PtStatus
        Update-PtSessionLog
