$script:BtnPtUnblock.Add_Click({
    $targetPath = $script:TxtPtUnblockPath.Text.Trim()
    if ([string]::IsNullOrWhiteSpace($targetPath)) {
        Add-LogEntry -Level 'WARN' -Message '[PenTest] Unblock: enter a path first'
        return
    }
    if (-not (Test-Path -LiteralPath $targetPath)) {
        Add-LogEntry -Level 'FAIL' -Message "[PenTest] Unblock: path not found: $targetPath"
        return
    }
    try {
        $files = Get-ChildItem -LiteralPath $targetPath -Recurse -Filter '*.ps1' -ErrorAction SilentlyContinue
        $count = 0
        foreach ($f in $files) {
            Unblock-File -LiteralPath $f.FullName -ErrorAction SilentlyContinue
            $count++
        }
        # Also unblock the path itself if it's a file
        if (Test-Path -LiteralPath $targetPath -PathType Leaf) {
            Unblock-File -LiteralPath $targetPath -ErrorAction SilentlyContinue
            $count++
        }
        Add-LogEntry -Level 'PASS' -Message "[PenTest] Unblocked $count file(s) under: $targetPath"
    } catch {
        Add-LogEntry -Level 'FAIL' -Message "[PenTest] Unblock failed: $_"
    }
})

