# Bind agent mode controls
$script:PnlAgentBanner = $script:Window.FindName('pnlAgentBanner')
$script:LblAgentStatus = $script:Window.FindName('lblAgentStatus')
$script:BtnPingAgent   = $script:Window.FindName('btnPingAgent')
$script:BtnRunAgent    = $script:Window.FindName('btnRunAgent')

#------------------------------------------------------------------------------
# AGENT MODE STARTUP
# If launched by Runner, show the banner, ping the pipe, enable Run-as-SYSTEM.
#------------------------------------------------------------------------------
if ($script:IsAgentMode) {
    $script:PnlAgentBanner.Visibility = [System.Windows.Visibility]::Visible
    $script:BtnRunAgent.Visibility    = [System.Windows.Visibility]::Visible

    Add-LogEntry -Level 'BOOT' -Message "Agent Mode active -- launched by PaladinAgent runner (SYSTEM)"
    Add-LogEntry -Level 'INFO' -Message "Pinging SYSTEM pipe: \\.\pipe\$($script:PipeName)"

    $pipeAlive = Test-AgentPipe
    if ($pipeAlive) {
        $script:LblAgentStatus.Text = "Pipe connected -- scripts execute as SYSTEM, no UAC required"
        $script:BtnRunAgent.IsEnabled = $true
        Add-LogEntry -Level 'PASS' -Message "PaladinAgent pipe is alive -- Run as SYSTEM button enabled"
    } else {
        $script:LblAgentStatus.Text     = "Pipe NOT connected -- runner may still be starting (click Ping)"
        $script:LblAgentStatus.Foreground = [System.Windows.Media.Brushes]::Orange
        Add-LogEntry -Level 'WARN' -Message "Pipe not yet available -- runner may still be initializing"
        Add-LogEntry -Level 'INFO' -Message "Click Ping to retry, or use LAUNCH for standard boot flow"
    }
}

# Ping button -- re-test pipe on demand
$script:BtnPingAgent.Add_Click({
    Add-LogEntry -Level 'INFO' -Message "Pinging PaladinAgent pipe..."
    $alive = Test-AgentPipe
    if ($alive) {
        $script:LblAgentStatus.Text = "Pipe connected -- scripts execute as SYSTEM, no UAC required"
        $script:LblAgentStatus.Foreground = [System.Windows.Media.Brushes]::LimeGreen
        $script:BtnRunAgent.IsEnabled = $true
        Add-LogEntry -Level 'PASS' -Message "Pipe alive -- Run as SYSTEM ready"
    } else {
        $script:LblAgentStatus.Text = "Pipe not responding -- is PaladinAdminRunner task still running?"
        $script:LblAgentStatus.Foreground = [System.Windows.Media.Brushes]::Orange
        $script:BtnRunAgent.IsEnabled = $false
        Add-LogEntry -Level 'WARN' -Message "Pipe not responding"
    }
})

# Run as SYSTEM button -- sends script to SYSTEM runner via named pipe
$script:BtnRunAgent.Add_Click({
    $payloadPath = $script:TxtPayload.Text.Trim()

    if ([string]::IsNullOrWhiteSpace($payloadPath)) {
        Add-LogEntry -Level 'FAIL' -Message "[AGENT] No payload selected. Click Browse to pick a PS1 file."
        return
    }
    if (-not (Test-Path -LiteralPath $payloadPath -PathType Leaf)) {
        Add-LogEntry -Level 'FAIL' -Message "[AGENT] File not found: $payloadPath"
        return
    }

    Add-LogEntry -Level 'BOOT' -Message "===================================================="
    Add-LogEntry -Level 'BOOT' -Message "RUN AS SYSTEM (via PaladinAgent pipe)"
    Add-LogEntry -Level 'BOOT' -Message "===================================================="
    Add-LogEntry -Level 'INFO' -Message "Payload: $payloadPath"

    $script:BtnRunAgent.IsEnabled = $false
    $script:BtnRunAgent.Content   = "RUNNING..."

    # Run on background thread so GUI stays responsive during execution
    $iss = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
    $ps  = [System.Management.Automation.PowerShell]::Create($iss)
    $ps.AddScript({
        param($payloadPath, $window, $btnRunAgent, $logDoc, $logBox, $pipeName)

        function Add-LogEntry {
            param([string]$Level, [string]$Message)
            $ts    = Get-Date -Format 'HH:mm:ss'
            $entry = "[$ts] [$($Level.PadRight(4))] $Message"
            $color = switch ($Level) {
                'PASS' { '#00FF88' } 'FAIL' { '#FF4444' } 'WARN' { '#FFB800' }
                'INFO' { '#FF8C00' } 'BOOT' { '#FFFFFF' } default { '#CCCCCC' }
            }
            $window.Dispatcher.Invoke([Action]{
                $run = New-Object System.Windows.Documents.Run
                $run.Text       = $entry + [System.Environment]::NewLine
                $run.Foreground = [System.Windows.Media.BrushConverter]::new().ConvertFromString($color)
                $para = New-Object System.Windows.Documents.Paragraph
                $para.Inlines.Add($run)
                $para.Margin = [System.Windows.Thickness]::new(0)
                $logDoc.Blocks.Add($para)
                $logBox.ScrollToEnd()
            }, [System.Windows.Threading.DispatcherPriority]::Background)
        }

        # Pipe client inline -- must be self-contained in this runspace
        $exitCode = -1
        try {
            $pipe = New-Object System.IO.Pipes.NamedPipeClientStream(
                '.', $pipeName,
                [System.IO.Pipes.PipeDirection]::InOut,
                [System.IO.Pipes.PipeOptions]::None)
            $pipe.Connect(10000)

            $writer = New-Object System.IO.StreamWriter($pipe, [System.Text.Encoding]::UTF8)
            $reader = New-Object System.IO.StreamReader($pipe, [System.Text.Encoding]::UTF8)
            $writer.AutoFlush = $true

            $scriptEscaped = $payloadPath -replace '\\', '\\' -replace '"', '\"'
            $cmdJson = "{`"cmd`":`"run`",`"script`":`"$scriptEscaped`",`"args`":`"`"}"
            $writer.WriteLine($cmdJson)

            $keepReading = $true
            while ($keepReading) {
                $line = $null
                try { $line = $reader.ReadLine() } catch { $keepReading = $false; break }
                if ($null -eq $line) { $keepReading = $false; break }
                $line = $line.Trim()
                if ([string]::IsNullOrEmpty($line)) { continue }
                try {
                    $pkt = $line | ConvertFrom-Json -ErrorAction Stop
                } catch { & (Get-Command Add-LogEntry) 'WARN' "[AGENT] Bad packet: $line"; continue }
                if ($null -eq $pkt) { continue }
                switch ($pkt.type) {
                    'out'  { if ($pkt.data) { Add-LogEntry -Level 'INFO' -Message "[OUT] $($pkt.data)" } }
                    'err'  { if ($pkt.data) { Add-LogEntry -Level 'WARN' -Message "[ERR] $($pkt.data)" } }
                    'done' {
                        $exitCode = if ($null -ne $pkt.exit) { [int]$pkt.exit } else { 0 }
                        $keepReading = $false
                        $lvl = if ($exitCode -eq 0) { 'PASS' } else { 'FAIL' }
                        Add-LogEntry -Level $lvl -Message "[AGENT] Done. Exit: $exitCode"
                    }
                }
            }
            try { $writer.WriteLine('{"cmd":"exit"}') } catch { }
            $reader.Dispose(); $writer.Dispose(); $pipe.Dispose()
        } catch {
            Add-LogEntry -Level 'FAIL' -Message "[AGENT] Pipe error: $_"
        }

        # Re-enable button on UI thread
        $window.Dispatcher.Invoke([Action]{
            $btnRunAgent.IsEnabled = $true
            $btnRunAgent.Content   = "RUN AS SYSTEM"
        }, [System.Windows.Threading.DispatcherPriority]::Normal)

    }).AddParameters(@{
        payloadPath  = $payloadPath
        window       = $script:Window
        btnRunAgent  = $script:BtnRunAgent
        logDoc       = $script:LogDoc
        logBox       = $script:LogBox
        pipeName     = $script:PipeName
    }) | Out-Null
    $ps.BeginInvoke() | Out-Null
})

