#------------------------------------------------------------------------------
# CERT VALIDITY: helper to compute days + update expiry preview label
#------------------------------------------------------------------------------
function Get-CertValidityDays {
    $qty  = 0
    $raw  = $script:TxtCertValidQty.Text.Trim()
    if (-not [int]::TryParse($raw, [ref]$qty) -or $qty -lt 1) { $qty = 1 }
    $unit = $script:CmbCertValidUnit.SelectedIndex  # 0=Days 1=Weeks 2=Months 3=Years
    switch ($unit) {
        0 { return $qty }
        1 { return $qty * 7 }
        2 { return $qty * 30 }
        3 { return $qty * 365 }
        default { return $qty * 365 }
    }
}

function Update-CertExpiryLabel {
    $days   = Get-CertValidityDays
    $expiry = (Get-Date).AddDays($days).ToString('yyyy-MM-dd')
    $unitNames = @('day','week','month','year')
    $idx  = $script:CmbCertValidUnit.SelectedIndex
    if ($idx -lt 0) { $idx = 3 }
    $qty  = 0
    [int]::TryParse($script:TxtCertValidQty.Text.Trim(), [ref]$qty) | Out-Null
    if ($qty -lt 1) { $qty = 1 }
    $plural = if ($qty -ne 1) { 's' } else { '' }
    $script:LblCertExpiry.Text = "Expires: $expiry  ($qty $($unitNames[$idx])$plural)"
}

$script:TxtCertValidQty.Add_TextChanged({ Update-CertExpiryLabel })
$script:CmbCertValidUnit.Add_SelectionChanged({ Update-CertExpiryLabel })
# Populate label on load
$script:Window.Add_Loaded({ Update-CertExpiryLabel })

#------------------------------------------------------------------------------
# CREDENTIAL PANEL: Detect elevation status and wire toggle
#------------------------------------------------------------------------------
function Update-CredentialStatus {
    $currentId   = [System.Security.Principal.WindowsIdentity]::GetCurrent()
    $principal   = New-Object System.Security.Principal.WindowsPrincipal($currentId)
    $isAdmin     = $principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)
    $currentUser = $currentId.Name

    if ($isAdmin) {
        $script:ChkUseCurrentUser.IsChecked = $true
        $script:ChkUseCurrentUser.Content   = "Use current user (already elevated as $currentUser)"
        $script:LblCredStatus.Text          = "STATUS: Running as $currentUser [ADMIN] -- no credentials required"
        $script:LblCredStatus.Foreground    = [System.Windows.Media.Brushes]::LimeGreen
        $script:PnlCredentials.IsEnabled    = $false
        $script:PnlCredentials.Opacity      = 0.4
    } else {
        $script:ChkUseCurrentUser.IsChecked = $false
        $script:ChkUseCurrentUser.Content   = "Use current user (NOT elevated -- enter admin credentials below)"
        $script:LblCredStatus.Text          = "STATUS: Running as $currentUser [STANDARD] -- admin credentials required"
        $script:LblCredStatus.Foreground    = [System.Windows.Media.Brushes]::Orange
        $script:PnlCredentials.IsEnabled    = $true
        $script:PnlCredentials.Opacity      = 1.0
    }
}

$script:ChkUseCurrentUser.Add_Checked({
    $script:PnlCredentials.IsEnabled = $false
    $script:PnlCredentials.Opacity   = 0.4
})

$script:ChkUseCurrentUser.Add_Unchecked({
    $script:PnlCredentials.IsEnabled = $true
    $script:PnlCredentials.Opacity   = 1.0
})

# Run status detection once on startup
Update-CredentialStatus

#------------------------------------------------------------------------------
# EVENT: Browse button
#------------------------------------------------------------------------------
#------------------------------------------------------------------------------
# MOD: SmartLaunchMode-LiveScope
# Live-scope copies of Get-TamperProtectionState, Get-DefenderServiceState,
# and Get-SmartLaunchMode for use on the GUI thread.
# The originals live inside $script:BootEngineContent (a here-string) and are
# only callable inside the payload runspace after dot-sourcing the engine.
# These copies run in the outer script scope so Invoke-SmartAutoConfig works.
# Write-BootLog replaced with Write-Warning (no boot log on GUI thread).
#------------------------------------------------------------------------------
function Get-TamperProtectionState {
    try {
        $status = Get-MpComputerStatus -ErrorAction Stop
        if ($null -ne $status) { return [bool]$status.IsTamperProtected }
    } catch { Write-Warning "Could not query Tamper Protection: $_" }
    try {
        $regVal = Get-ItemProperty `
            'HKLM:\SOFTWARE\Microsoft\Windows Defender\Features' `
            -Name TamperProtection -ErrorAction Stop
        return ($regVal.TamperProtection -eq 5)
    } catch { }
    return $false
}

function Get-DefenderServiceState {
    try {
        $svc = Get-Service -Name 'WinDefend' -ErrorAction Stop
        switch ($svc.Status) {
            'Running' { return 'Running' }
            'Stopped' { return 'Stopped' }
            default   { return 'Stopped' }
        }
    } catch {
        try {
            $svc2 = Get-WmiObject -Class Win32_Service -Filter "Name='WinDefend'" `
                        -ErrorAction Stop
            if ($null -eq $svc2)              { return 'Missing'  }
            if ($svc2.StartMode -eq 'Disabled') { return 'Disabled' }
            return 'Stopped'
        } catch { }
    }
    return 'Missing'
}

function Get-SmartLaunchMode {
    param([string]$ScriptPath)
    $result = @{
        Mode       = 'Direct'
        Reason     = ''
        Flagged    = $false
        TamperOn   = $false
        DefenderUp = $false
        WarnTamper = $false
    }
    $svcState = Get-DefenderServiceState
    $result.DefenderUp = ($svcState -eq 'Running')
    if (-not $result.DefenderUp) {
        $result.Reason = "Defender not active ($svcState) - Direct Launch"
        return $result
    }
    try {
        $content = [System.IO.File]::ReadAllText($ScriptPath, [System.Text.Encoding]::UTF8)
        $null = [System.Management.Automation.ScriptBlock]::Create($content)
        $result.Mode   = 'Direct'
        $result.Reason = "Defender running, script not flagged - Direct Launch"
    } catch {
        $errId = $_.FullyQualifiedErrorId
        if ($errId -like '*ScriptContainedMaliciousContent*' -or
            $errId -like '*UnauthorizedAccess*'              -or
            $_.Exception.Message -like '*malicious*'         -or
            $_.Exception.Message -like '*blocked*antivirus*') {
            $result.Flagged = $true
        }
        # Any other exception = parse error in the script itself, not AMSI
    }
    if (-not $result.Flagged) {
        $result.Mode   = 'Direct'
        $result.Reason = "Defender running, script not flagged - Direct Launch"
        return $result
    }
    $result.Mode     = 'BootEngine'
    $result.TamperOn = Get-TamperProtectionState
    if ($result.TamperOn) {
        $result.WarnTamper = $true
        $result.Reason = "Script flagged by Defender + Tamper Protection ON - Boot Engine (exclusion only; toggle Tamper Protection OFF for full bypass)"
    } else {
        $result.Reason = "Script flagged by Defender - Boot Engine (Defender will be suspended for launch)"
    }
    return $result
}

# GUI-thread Defender suspend/restore for PenTest panel.
# Cannot call Suspend-Defender / Restore-Defender directly -- those are
# defined inside $script:BootEngineContent and only available after
# dot-sourcing the engine in a child process. These live-scope versions
# do the same work using Add-LogEntry for output.
$script:PtGuiDefenderSnapshot = $null

function Invoke-PtSuspendDefender {
    $cmdGet    = 'Get-Mp'   + 'Preference'
    $cmdSet    = 'Set-Mp'   + 'Preference'
    $pRTM      = 'Disable'  + 'Realtime'   + 'Monitoring'
    $pScript   = 'Disable'  + 'Script'     + 'Scanning'
    $pBehavior = 'Disable'  + 'Behavior'   + 'Monitoring'
    $pIOAV     = 'Disable'  + 'IOAV'       + 'Protection'

    $svcState = Get-DefenderServiceState
    if ($svcState -ne 'Running') {
        Add-LogEntry -Level 'WARN' -Message "[PenTest] Defender not running ($svcState) -- suspend skipped"
        return
    }
    $tpOn = Get-TamperProtectionState
    if ($tpOn) {
        Add-LogEntry -Level 'WARN' -Message '[PenTest] Tamper Protection is ON -- suspension will fail'
        Add-LogEntry -Level 'WARN' -Message '[PenTest] Windows Security > Virus protection > Manage settings > Tamper Protection OFF'
        return
    }
    try {
        $prefs = & $cmdGet -ErrorAction Stop
        $script:PtGuiDefenderSnapshot = @{
            RTM      = $prefs.$pRTM
            Script   = $prefs.$pScript
            Behavior = $prefs.$pBehavior
            IOAV     = $prefs.$pIOAV
        }
        $suspendArgs = @{
            $pRTM       = $true
            $pScript    = $true
            $pBehavior  = $true
            $pIOAV      = $true
            ErrorAction = 'Stop'
        }
        & $cmdSet @suspendArgs
        $script:PtDefenderSuspended = $true
        Add-LogEntry -Level 'PASS' -Message '[PenTest] Defender scans suspended (RTM + Script + Behavior + IOAV)'
    } catch {
        Add-LogEntry -Level 'FAIL' -Message "[PenTest] Defender suspension failed: $_"
    }
}

function Invoke-PtRestoreDefender {
    $cmdSet    = 'Set-Mp'   + 'Preference'
    $pRTM      = 'Disable'  + 'Realtime'   + 'Monitoring'
    $pScript   = 'Disable'  + 'Script'     + 'Scanning'
    $pBehavior = 'Disable'  + 'Behavior'   + 'Monitoring'
    $pIOAV     = 'Disable'  + 'IOAV'       + 'Protection'

    if ($null -eq $script:PtGuiDefenderSnapshot) {
        Add-LogEntry -Level 'WARN' -Message '[PenTest] No snapshot to restore -- Defender was not suspended via this panel'
        return
    }
    try {
        $restoreArgs = @{
            $pRTM       = $script:PtGuiDefenderSnapshot.RTM
            $pScript    = $script:PtGuiDefenderSnapshot.Script
            $pBehavior  = $script:PtGuiDefenderSnapshot.Behavior
            $pIOAV      = $script:PtGuiDefenderSnapshot.IOAV
            ErrorAction = 'Stop'
        }
        & $cmdSet @restoreArgs
        $script:PtDefenderSuspended   = $false
        $script:PtGuiDefenderSnapshot = $null
        Add-LogEntry -Level 'PASS' -Message '[PenTest] Defender restored to pre-suspend state'
    } catch {
        Add-LogEntry -Level 'FAIL' -Message "[PenTest] Defender restore failed: $_"
    }
}
# END MOD: SmartLaunchMode-LiveScope

#------------------------------------------------------------------------------
# MOD: SmartAutoConfig
# Runs Get-SmartLaunchMode and applies the result to the manifest checkboxes.
# Called from Browse, from dropdown SelectionChanged, and at launch time.
# Runs on the UI thread -- probe is fast (file read + ScriptBlock.Create).
#------------------------------------------------------------------------------
function Invoke-SmartAutoConfig {
    param([string]$ScriptPath)

    if ([string]::IsNullOrWhiteSpace($ScriptPath) -or
        -not (Test-Path -LiteralPath $ScriptPath -PathType Leaf -ErrorAction SilentlyContinue)) {
        return
    }

    Add-LogEntry -Level 'INFO' -Message "[AUTO] Probing script: $(Split-Path $ScriptPath -Leaf)"

    $mode = Get-SmartLaunchMode -ScriptPath $ScriptPath

    if ($mode.Mode -eq 'Direct') {
        $script:ChkDirectLaunch.IsChecked = $true
        $script:ChkDefender.IsChecked     = $false
        $script:ChkExclusion.IsChecked    = $false
        $statusText  = "Direct Launch -- $($mode.Reason)"
        $statusColor = '#00FF88'
        Add-LogEntry -Level 'PASS' -Message "[AUTO] Mode: Direct Launch -- $($mode.Reason)"
    } else {
        $script:ChkDirectLaunch.IsChecked = $false
        $script:ChkDefender.IsChecked     = $true
        $script:ChkExclusion.IsChecked    = $true
        $script:ChkPolicy.IsChecked       = $true
        $statusText  = "Boot Engine + Defender Suspend -- $($mode.Reason)"
        $statusColor = '#FFB800'
        Add-LogEntry -Level 'WARN' -Message "[AUTO] Mode: Boot Engine -- $($mode.Reason)"

        if ($mode.WarnTamper) {
            $statusText  = "Boot Engine (Tamper Protection ON -- exclusion only) -- $($mode.Reason)"
            $statusColor = '#FF6B35'
            Add-LogEntry -Level 'WARN' -Message "[AUTO] Tamper Protection is ON -- Defender suspension will be limited"
            Add-LogEntry -Level 'WARN' -Message "[AUTO] If still blocked: Windows Security > Virus protection > Manage settings > Tamper Protection OFF"
        }
    }

    # If the script lives inside the Paladin cache dir, keep the exclusion alive
    # after launch so child processes (e.g. WinUtil's irm|iex) stay covered.
    $cacheRoot = 'C:\ProgramData\Paladin\Launcher\Cache'
    if ($ScriptPath -like "$cacheRoot*") {
        $script:ChkKeep.IsChecked = $true
        Add-LogEntry -Level 'INFO' -Message "[AUTO] Cache path detected -- Keep Exclusion enabled (covers child processes)"
    }

    # Update the auto-route status label in the UI
    if ($script:LblAutoRoute -ne $null) {
        $script:LblAutoRoute.Text = $statusText
        try {
            $script:LblAutoRoute.Foreground =
                [System.Windows.Media.BrushConverter]::new().ConvertFromString($statusColor)
        } catch { }
    }
}
# END MOD: SmartAutoConfig

$script:BtnBrowse.Add_Click({
    $dlg = New-Object System.Windows.Forms.OpenFileDialog
    $dlg.Title  = "Select PowerShell Script"
    $dlg.Filter = "PowerShell Scripts (*.ps1)|*.ps1|All Files (*.*)|*.*"
    $dlg.InitialDirectory = if (-not [string]::IsNullOrWhiteSpace($script:TxtPayload.Text) -and
                                 (Test-Path -LiteralPath $script:TxtPayload.Text -PathType Leaf -ErrorAction SilentlyContinue)) {
        Split-Path $script:TxtPayload.Text -Parent
    } else {
        [System.Environment]::GetFolderPath('Desktop')
    }
    if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
        $script:TxtPayload.Text = $dlg.FileName
        Add-LogEntry -Level 'INFO' -Message "Payload selected: $($dlg.FileName)"
        Add-RecentScript -Path $dlg.FileName
        Update-LibraryDropdown

        # Auto-detect the best launch mode for this script
        Invoke-SmartAutoConfig -ScriptPath $dlg.FileName
    }
})

#------------------------------------------------------------------------------
# EVENT: Clear log button
#------------------------------------------------------------------------------
$script:BtnClearLog.Add_Click({ Clear-Log })

#------------------------------------------------------------------------------
# EVENT: Launch button
#------------------------------------------------------------------------------
$script:BtnLaunch.Add_Click({
    $payloadPath = $script:TxtPayload.Text.Trim()

    # Re-run auto-config in case the path was typed manually or changed since Browse
    if (-not [string]::IsNullOrWhiteSpace($payloadPath) -and
        (Test-Path -LiteralPath $payloadPath -PathType Leaf -ErrorAction SilentlyContinue)) {
        Invoke-SmartAutoConfig -ScriptPath $payloadPath
    }

    # Validate payload path
    if ([string]::IsNullOrWhiteSpace($payloadPath)) {
        Add-LogEntry -Level 'FAIL' -Message "No payload selected. Click Browse to pick a PS1 file."
        return
    }
    if (-not (Test-Path -LiteralPath $payloadPath -PathType Leaf)) {
        Add-LogEntry -Level 'FAIL' -Message "File not found: $payloadPath"
        return
    }
    if (-not $payloadPath.EndsWith('.ps1', [System.StringComparison]::OrdinalIgnoreCase)) {
        Add-LogEntry -Level 'WARN' -Message "File does not have .ps1 extension -- proceeding anyway"
    }

    # Validate sign CN if signing enabled
    $doSign = $script:ChkSign.IsChecked -eq $true
    if ($doSign -and [string]::IsNullOrWhiteSpace($script:TxtSignerCN.Text)) {
        Add-LogEntry -Level 'FAIL' -Message "Auto-sign enabled but Signer CN is empty."
        return
    }

    # Detect launch tier -- determines whether credentials are needed
    # Admin      : already elevated, proceed directly (current design)
    # Tier3-Agent: PaladinBootAgent task exists (RMM pre-staged), schtasks /run, no creds
    # Tier2      : SeBatchLogonRight granted, interactive task, no creds
    # Credential : user supplied admin credentials in the panel
    # None       : no path available -- offer Tier 2 install if admin, else show instructions
    $launchTier = Get-LaunchContext
    Add-LogEntry -Level 'INFO' -Message "Launch context: $launchTier"

    # Validate credentials if not using current user
    $useCurrentUser = ($script:ChkUseCurrentUser.IsChecked -eq $true)
    if (-not $useCurrentUser) {
        if ([string]::IsNullOrWhiteSpace($script:TxtAdminUser.Text)) {
            Add-LogEntry -Level 'FAIL' -Message "Admin credentials: username is required when not using current user."
            return
        }
        if ($script:PwdAdminPass.SecurePassword.Length -eq 0) {
            Add-LogEntry -Level 'FAIL' -Message "Admin credentials: password is required when not using current user."
            return
        }
        # Normalize and validate username format
        # UPN (user@domain.com) not supported by LogonType Password -- requires DOMAIN\User
        $rawUser = $script:TxtAdminUser.Text.Trim()
        if ($rawUser -match '@') {
            Add-LogEntry -Level 'FAIL' -Message "Username format: use DOMAIN\User or .\LocalAdmin -- UPN (user@domain.com) not supported for Password logon."
            return
        }
        if ($rawUser -match '/') {
            $rawUser = $rawUser -replace '/', '\'
            Add-LogEntry -Level 'INFO' -Message "Username: normalized / to \ -> $rawUser"
            $script:TxtAdminUser.Text = $rawUser
        }
        if ($rawUser -notmatch '\\') {
            $rawUser = ".\" + $rawUser
            Add-LogEntry -Level 'INFO' -Message "Username: no domain prefix -- assuming local account -> $rawUser"
            $script:TxtAdminUser.Text = $rawUser
        }
        Add-LogEntry -Level 'INFO' -Message "Credentials: will launch as $($script:TxtAdminUser.Text.Trim())"
    }

    # Warn if payload is on a non-C: drive when using a different admin account
    # LogonType Password runs in that user's session -- mapped drives may differ
    if (-not $useCurrentUser -and $payloadPath.Length -ge 2) {
        $payDrive = $payloadPath.Substring(0,2).ToUpper()
        if ($payDrive -ne 'C:') {
            Add-LogEntry -Level 'WARN' -Message "Payload on drive $payDrive -- verify that '$($script:TxtAdminUser.Text.Trim())' has access to this drive (mapped drives may differ per session)."
        }
    }

    # Disable launch button during operation
    $script:BtnLaunch.IsEnabled = $false
    $script:BtnLaunch.Content   = "  LAUNCHING...  "

    Add-LogEntry -Level 'BOOT' -Message "===================================================="
    Add-LogEntry -Level 'BOOT' -Message "PALADIN POWERSHELL LAUNCHER v$($script:Version)"
    Add-LogEntry -Level 'BOOT' -Message "===================================================="

    # Reset and show the boot checklist panel
    Reset-Checklist
    Show-Checklist
    Add-LogEntry -Level 'INFO' -Message "Payload : $payloadPath"
    Add-LogEntry -Level 'INFO' -Message ("Manifest: DirectLaunch={0} Defender={1} Exclusion={2} Policy={3} Elevate={4}" -f
        $script:ChkDirectLaunch.IsChecked,
        $script:ChkDefender.IsChecked,
        $script:ChkExclusion.IsChecked,
        $script:ChkPolicy.IsChecked,
        $script:ChkElevate.IsChecked)
    Add-LogEntry -Level 'INFO' -Message ("         Session={0} KeepExcl={1} Prompt={2}" -f
        $script:ChkSession.IsChecked,
        $script:ChkKeep.IsChecked,
        $script:ChkPrompt.IsChecked)
    if ($doSign) {
        Add-LogEntry -Level 'INFO' -Message ("Sign: ON  CN={0}  AutoCreate={1}  TrustCU={2}  TrustLM={3}  TS={4}" -f
            $script:TxtSignerCN.Text,
            $script:ChkAutoCreate.IsChecked,
            $script:ChkTrustCU.IsChecked,
            $script:ChkTrustLM.IsChecked,
            $script:ChkTimestamp.IsChecked)
    }

    # TIER ROUTING -- act on context before background runspace fires
    # Tier3-Agent: fire the pre-staged agent task and return -- no wrapper needed
    if ($launchTier -eq 'Tier3-Agent') {
        Add-LogEntry -Level 'INFO' -Message "Tier 3: firing PaladinBootAgent task (RMM pre-staged)"
        try {
            Start-ScheduledTask -TaskName 'PaladinBootAgent' -ErrorAction Stop
            Add-LogEntry -Level 'PASS' -Message "PaladinBootAgent started -- zero credentials, zero UAC"
        } catch {
            Add-LogEntry -Level 'FAIL' -Message "PaladinBootAgent start failed: $_"
        }
        $script:BtnLaunch.IsEnabled = $true
        $script:BtnLaunch.Content   = ">>  LAUNCH  <<"
        return
    }

    # None: no viable launch path -- offer Tier 2 install if admin, else explain options
    if ($launchTier -eq 'None') {
        Add-LogEntry -Level 'WARN' -Message "No viable launch context detected."
        Add-LogEntry -Level 'INFO' -Message "Options:"
        Add-LogEntry -Level 'INFO' -Message "  [Tier 2] Run launcher once as Administrator to install SeBatchLogonRight (persists)"
        Add-LogEntry -Level 'INFO' -Message "  [Tier 3] Have admin/RMM register a PaladinBootAgent scheduled task"
        Add-LogEntry -Level 'INFO' -Message "  [Tier 4] Enter admin credentials in the credential panel below"
        # Attempt Tier 2 auto-install if we are somehow already admin (edge case: admin forgot to check)
        try {
            $id        = [System.Security.Principal.WindowsIdentity]::GetCurrent()
            $principal = New-Object System.Security.Principal.WindowsPrincipal($id)
            if ($principal.IsInRole([System.Security.Principal.WindowsBuiltInRole]::Administrator)) {
                Add-LogEntry -Level 'INFO' -Message "Admin rights detected -- attempting Tier 2 bootstrap..."
                $bootstrapLog = { param($lvl,$msg) Add-LogEntry -Level $lvl -Message "[T2] $msg" }
                $installed = Install-Tier2Bootstrap -LogAction $bootstrapLog
                if ($installed) {
                    Add-LogEntry -Level 'PASS' -Message "Tier 2 bootstrap complete. Click LAUNCH again to proceed."
                } else {
                    Add-LogEntry -Level 'WARN' -Message "Bootstrap did not complete. Use credential panel (Tier 4) instead."
                }
            }
        } catch { }
        $script:BtnLaunch.IsEnabled = $true
        $script:BtnLaunch.Content   = ">>  LAUNCH  <<"
        return
    }

    # Run launch on background thread to keep GUI responsive
    $iss = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
    $ps  = [System.Management.Automation.PowerShell]::Create($iss)
    $ps.AddScript({
        param(
            $payloadPath, $doSign, $signerCN,
            $chkDirectLaunch,
            $chkDefender, $chkExclusion, $chkPolicy, $chkElevate,
            $chkSession, $chkKeep, $chkPrompt,
            $chkAutoCreate, $chkTrustCU, $chkTrustLM, $chkTimestamp,
            $certValidityDays,
            $useCurrentUser, $adminUsername, $adminSecurePass,
            $logAction, $bootEngineContent, $scriptVersion,
            $window, $btnLaunch, $logDoc, $logBox,
            $bridgeFile
        )

        # Re-declare helpers in this runspace
        function Add-LogEntry {
            param([string]$Level, [string]$Message)
            $ts    = Get-Date -Format 'HH:mm:ss'
            $entry = "[$ts] [$($Level.PadRight(4))] $Message"
            $color = switch ($Level) {
                'PASS' { '#00FF88' }
                'FAIL' { '#FF4444' }
                'WARN' { '#FFB800' }
                'INFO' { '#FF8C00' }
                'BOOT' { '#FFFFFF' }
                default { '#CCCCCC' }
            }
            $window.Dispatcher.Invoke([Action]{
                $run = New-Object System.Windows.Documents.Run
                $run.Text       = $entry + [System.Environment]::NewLine
                $run.Foreground = [System.Windows.Media.BrushConverter]::new().ConvertFromString($color)
                $para = New-Object System.Windows.Documents.Paragraph
                $para.Inlines.Add($run)
                $para.Margin = [System.Windows.Thickness]::new(0)
                $logDoc.Blocks.Add($para)
                $logBox.ScrollToEnd()
            }, [System.Windows.Threading.DispatcherPriority]::Background)
        }

        $localLog = { param($lvl, $msg) Add-LogEntry -Level $lvl -Message $msg }

        $ts         = [System.DateTime]::Now.Ticks
        $tmpDir     = $env:TEMP
        $engPath    = Join-Path $tmpDir "PaladinPS-Engine-$ts.ps1"
        $payPath    = Join-Path $tmpDir "PaladinPS-Payload-$ts.ps1"
        # bridgeFile path passed in from UI thread (created and polled there)

        # Write engine
        try {
            [System.IO.File]::WriteAllText($engPath, $bootEngineContent,
                [System.Text.Encoding]::UTF8)
            & $localLog 'INFO' "Engine written to temp"
        } catch {
            & $localLog 'FAIL' "Engine write failed: $_"
            $window.Dispatcher.Invoke([Action]{ $btnLaunch.IsEnabled = $true; $btnLaunch.Content = ">>  LAUNCH  <<" },
                [System.Windows.Threading.DispatcherPriority]::Normal)
            return
        }

        # Build sign block
        $signBlock = ''
        if ($doSign -and -not [string]::IsNullOrWhiteSpace($signerCN)) {
            $cnSafe  = $signerCN   -replace "'", "''"
            $tgtSafe = $payloadPath -replace "'", "''"
            $autoStr = if ($chkAutoCreate) { '$true' } else { '$false' }
            $cuStr   = if ($chkTrustCU)   { '$true' } else { '$false' }
            $lmStr   = if ($chkTrustLM)   { '$true' } else { '$false' }
            $tsArr   = if ($chkTimestamp) {
                "@('http://timestamp.digicert.com','http://timestamp.comodoca.com','http://timestamp.sectigo.com')"
            } else { "@()" }
            $CertValidityDays = if ($certValidityDays -gt 0) { $certValidityDays } else { 1825 }

            $signBlock = @"

# ---- AUTO SIGN -------------------------------------------------------
function SB-Drive { if (-not (Get-PSDrive -Name Cert -EA SilentlyContinue)) { New-PSDrive -Name Cert -PSProvider Certificate -Root '\' | Out-Null } }
function SB-FindCert([string]`$cn) {
    SB-Drive
    foreach (`$s in @('Cert:\CurrentUser\My','Cert:\LocalMachine\My')) {
        `$c = Get-ChildItem `$s -CodeSigningCert -EA SilentlyContinue |
             Where-Object { `$_.Subject -like "CN=`$cn*" } |
             Sort-Object NotAfter -Descending | Select-Object -First 1
        if (`$c) { return `$c }
    }
    return `$null
}
function SB-CreateSelfSigned([string]`$cn) {
    try {
        `$cert = New-SelfSignedCertificate -Subject "CN=`$cn" -KeyUsage DigitalSignature ``
            -Type CodeSigningCert -KeySpec Signature -HashAlgorithm SHA256 ``
            -NotAfter (Get-Date).AddDays($CertValidityDays) -EA Stop
        Write-BootLog 'PASS' "Self-signed cert created: CN=`$cn"
        return `$cert
    } catch {
        Write-BootLog 'FAIL' "Self-signed cert creation failed: `$_"
        return `$null
    }
}
function SB-TrustCert([System.Security.Cryptography.X509Certificates.X509Certificate2]`$cert, [bool]`$cu, [bool]`$lm) {
    if (`$cu) {
        try {
            `$s = New-Object System.Security.Cryptography.X509Certificates.X509Store('TrustedPublisher','CurrentUser')
            `$s.Open('ReadWrite'); `$s.Add(`$cert); `$s.Close()
            Write-BootLog 'PASS' "Cert trusted in CurrentUser\TrustedPublisher"
        } catch { Write-BootLog 'WARN' "CU trust failed: `$_" }
    }
    if (`$lm) {
        try {
            `$s = New-Object System.Security.Cryptography.X509Certificates.X509Store('TrustedPublisher','LocalMachine')
            `$s.Open('ReadWrite'); `$s.Add(`$cert); `$s.Close()
            Write-BootLog 'PASS' "Cert trusted in LocalMachine\TrustedPublisher"
        } catch { Write-BootLog 'WARN' "LM trust failed: `$_" }
    }
}
`$SB_CN         = '$cnSafe'
`$SB_AutoCreate = $autoStr
`$SB_TrustCU    = $cuStr
`$SB_TrustLM    = $lmStr
`$SB_TSUrls     = $tsArr
`$SB_Target     = '$tgtSafe'
`$sigCert = SB-FindCert `$SB_CN
if (`$null -eq `$sigCert -and `$SB_AutoCreate) {
    `$sigCert = SB-CreateSelfSigned `$SB_CN
    if (`$null -ne `$sigCert) { SB-TrustCert `$sigCert `$SB_TrustCU `$SB_TrustLM }
}
if (`$null -ne `$sigCert) {
    try {
        if (`$SB_TSUrls.Count -gt 0) {
            `$sigResult = `$null
            foreach (`$url in `$SB_TSUrls) {
                try {
                    `$sigResult = Set-AuthenticodeSignature -FilePath `$SB_Target ``
                        -Certificate `$sigCert -TimestampServer `$url -EA Stop
                    if (`$sigResult.Status -eq 'Valid') { break }
                } catch { continue }
            }
            if (`$null -eq `$sigResult -or `$sigResult.Status -ne 'Valid') {
                `$sigResult = Set-AuthenticodeSignature -FilePath `$SB_Target -Certificate `$sigCert -EA Stop
            }
        } else {
            `$sigResult = Set-AuthenticodeSignature -FilePath `$SB_Target -Certificate `$sigCert -EA Stop
        }
        Write-BootLog 'PASS' "Script signed [CN=`$SB_CN]"
    } catch { Write-BootLog 'FAIL' "Signing failed: `$_" }
} else {
    Write-BootLog 'FAIL' "No code-signing cert for CN=`$SB_CN -- sign skipped"
}
# ---- END AUTO SIGN ---------------------------------------------------
"@
        }

        # Manifest booleans
        $mDS  = if ($chkDefender)  { '$true' } else { '$false' }
        $mEA  = if ($chkExclusion) { '$true' } else { '$false' }
        $mPU  = if ($chkPolicy)    { '$true' } else { '$false' }
        $mEIN = if ($chkElevate)   { '$true' } else { '$false' }
        $mSB  = if ($chkSession)   { '$true' } else { '$false' }
        $mKE  = if ($chkKeep)      { '$true' } else { '$false' }
        $mPP  = if ($chkPrompt)    { '$true' } else { '$false' }

        $payloadSafe = $payloadPath -replace "'", "''"
        $engSafe     = $engPath     -replace "'", "''"

        $bridgeSafe  = $bridgeFile -replace "'", "''"

        $wrapper = @"
#Requires -Version 3.0
# Paladin PowerShell Wrapper -- auto-generated by Paladin-PowerShell-Launcher v$scriptVersion
Set-StrictMode -Off

. "$engSafe"

# Bridge path: Write-BootLog appends here so launcher GUI receives all output
`$script:LogBridgeFile = "$bridgeSafe"

`$BOOT_MANIFEST = @{
    DefenderSuspend  = $mDS
    ExclusionAdd     = $mEA
    PolicyUnrestrict = $mPU
    ElevateIfNeeded  = $mEIN
    SessionBridge    = $mSB
    KeepExclusion    = $mKE
    PolicyPrompt     = $mPP
}

Invoke-SpectreBoot -Manifest `$BOOT_MANIFEST -TargetScript "$payloadSafe"
$signBlock

# Run payload via IEX -- bypasses ExecutionPolicy Restricted (KI-047). Defender stays suspended (KI-046).
`$crashLog = 'C:\ProgramData\Paladin\Launcher\APM-Crash.log'
try {
    if (-not (Test-Path (Split-Path `$crashLog -Parent))) {
        New-Item -ItemType Directory -Force -Path (Split-Path `$crashLog -Parent) | Out-Null
    }
    [System.IO.File]::AppendAllText(`$crashLog, ("[" + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss') + "] LAUNCHING: $payloadSafe`r`n"))
    `$payContent = [System.IO.File]::ReadAllText("$payloadSafe")
    # Set `$PSScriptRoot so scripts that rely on it (e.g. Win11Debloat) find their support files
    `$PSScriptRoot = Split-Path "$payloadSafe" -Parent
    Invoke-Expression `$payContent
    [System.IO.File]::AppendAllText(`$crashLog, ("[" + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss') + "] PAYLOAD EXITED NORMALLY`r`n"))
} catch {
    `$errText = `$_.ToString() + "`r`n" + `$_.ScriptStackTrace
    [System.IO.File]::AppendAllText(`$crashLog, ("[" + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss') + "] PAYLOAD ERROR: " + `$errText + "`r`n"))
    [System.Windows.MessageBox]::Show(
        "APM failed to start:`r`n`r`n" + `$errText,
        "Paladin PowerShell - Payload Error", "OK", "Error") | Out-Null
} finally {
    if (`$BOOT_MANIFEST.PolicyPrompt) {
        try { Invoke-PolicyPrompt -Snapshot `$script:PolicySnapshot } catch { }
    }
    try { Restore-BootExecutionPolicy } catch { }
    try { Stop-Transcript -ErrorAction SilentlyContinue } catch { }
}
"@

        try {
            [System.IO.File]::WriteAllText($payPath, $wrapper, [System.Text.Encoding]::UTF8)
            & $localLog 'INFO' "Wrapper written to temp"
        } catch {
            & $localLog 'FAIL' "Wrapper write failed: $_"
            try { [System.IO.File]::Delete($engPath) } catch { }
            $window.Dispatcher.Invoke([Action]{ $btnLaunch.IsEnabled = $true; $btnLaunch.Content = ">>  LAUNCH  <<" },
                [System.Windows.Threading.DispatcherPriority]::Normal)
            return
        }

        # ----------------------------------------------------------------
        # DIRECT LAUNCH PATH (default) -- Start-Process, visible window
        # Works for WinUtil, CTT scripts, any tool that creates its own UI.
        # No schtask, no IEX, no hidden window. Just launches the script.
        # ----------------------------------------------------------------
        if ($chkDirectLaunch) {
            & $localLog 'INFO' "Mode: DIRECT LAUNCH -- starting visible PowerShell window"
            $ps64 = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"
            $argList = "-NoProfile -ExecutionPolicy Bypass -File `"$payloadPath`""
            try {
                $procArgs = @{
                    FilePath         = $ps64
                    ArgumentList     = $argList
                    WindowStyle      = 'Normal'
                    Verb             = 'RunAs'
                    ErrorAction      = 'Stop'
                }
                Start-Process @procArgs
                & $localLog 'PASS' "Script launched in new window: $payloadPath"
                & $localLog 'INFO' "Script is running in its own window -- this launcher remains open"
            } catch {
                & $localLog 'FAIL' "Direct launch failed: $_"
                & $localLog 'INFO' "Try unchecking 'Direct Launch' to use the advanced boot path instead"
            }
            # Restore button and exit -- no schtask needed
            try { [System.IO.File]::Delete($engPath) } catch { }
            $window.Dispatcher.Invoke([Action]{
                $btnLaunch.IsEnabled = $true
                $btnLaunch.Content   = ">>  LAUNCH  <<"
            }, [System.Windows.Threading.DispatcherPriority]::Normal)
            return
        }

        # ----------------------------------------------------------------
        # ADVANCED PATH (schtask + IEX) -- used when Direct Launch is OFF
        # Required for: Session Bridge, SYSTEM context, credential-based launch
        # ----------------------------------------------------------------
        & $localLog 'INFO' "Mode: ADVANCED BOOT (schtask + engine wrapper)"

        # Launch via Register-ScheduledTask with LogonType Interactive.
        # This is the ONLY reliable way to get a visible GUI window from an elevated
        # background context without storing a user password.
        # Per Microsoft docs: LogonType Interactive = "Run only when user is logged on"
        # = runs in the active desktop session, window is visible to the user.
        # schtasks /RU username without /RP password uses batch logon (Session 0 invisible).
        $taskName    = "SpectreBoot_$ts"
        $ps64        = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"
        $currentUser = [System.Security.Principal.WindowsIdentity]::GetCurrent().Name

        # Clean up any leftover SpectreBoot_* tasks from previous crashed runs.
        # A crash between Register and Unregister leaves stale tasks. Clean them proactively.
        try {
            $staleTasks = @(Get-ScheduledTask -TaskName "SpectreBoot_*" `
                               -ErrorAction SilentlyContinue)
            foreach ($stale in $staleTasks) {
                try {
                    Unregister-ScheduledTask -TaskName $stale.TaskName `
                        -Confirm:$false -ErrorAction SilentlyContinue
                } catch { }
            }
            if ($staleTasks.Count -gt 0) {
                & $localLog 'INFO' "Cleaned $($staleTasks.Count) stale SpectreBoot task(s)"
            }
        } catch { }

        # Build principal based on credential mode
        if ($useCurrentUser -or [string]::IsNullOrWhiteSpace($adminUsername)) {
            & $localLog 'INFO' "Credential mode: CURRENT USER ($currentUser)"
            $runAsUser = $currentUser
            $principal = New-ScheduledTaskPrincipal `
                             -UserId $runAsUser `
                             -LogonType Interactive `
                             -RunLevel Highest
        } else {
            # Admin credentials provided -- validate they are not empty
            $passLength = 0
            try {
                $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($adminSecurePass)
                $plain = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto($bstr)
                $passLength = $plain.Length
                [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
                $plain = $null
            } catch { }

            if ($passLength -eq 0) {
                & $localLog 'FAIL' "Admin credentials: username provided but password is empty"
                try { [System.IO.File]::Delete($engPath) } catch { }
                try { [System.IO.File]::Delete($payPath) } catch { }
                $window.Dispatcher.Invoke([Action]{ $btnLaunch.IsEnabled = $true; $btnLaunch.Content = ">>  LAUNCH  <<" },
                    [System.Windows.Threading.DispatcherPriority]::Normal)
                return
            }

            & $localLog 'INFO' "Credential mode: ADMIN USER ($adminUsername)"
            $runAsUser = $adminUsername
            $principal = New-ScheduledTaskPrincipal `
                             -UserId $runAsUser `
                             -LogonType Password `
                             -RunLevel Highest
        }

        & $localLog 'INFO' "Registering task: SpectreBoot_$ts as $runAsUser"

        try {
            $action   = New-ScheduledTaskAction -Execute $ps64 `
                            -Argument "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$payPath`""
            $settings = New-ScheduledTaskSettingsSet -ExecutionTimeLimit (New-TimeSpan -Hours 4)
            $task     = New-ScheduledTask -Action $action -Principal $principal -Settings $settings

            if ($useCurrentUser -or [string]::IsNullOrWhiteSpace($adminUsername)) {
                # Interactive logon -- no password needed
                Register-ScheduledTask -TaskName $taskName -InputObject $task -Force -ErrorAction Stop | Out-Null
            } else {
                # Password logon -- must supply password at registration time
                # Convert SecureString to plain text only for the Register call, then discard
                $bstr    = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($adminSecurePass)
                $plain   = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto($bstr)
                [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
                # Note: Register-ScheduledTask -Password handles all special characters
                # (quotes, backslashes, dollar signs, spaces) correctly as a .NET string.
                # No escaping needed -- the value is passed as a CLR string, not a shell arg.
                & $localLog 'INFO' ("Password: {0} chars, special chars: {1}" -f
                    $plain.Length,
                    ($plain -match '[^A-Za-z0-9]'))
                try {
                    Register-ScheduledTask -TaskName $taskName -InputObject $task `
                        -User $runAsUser -Password $plain -Force -ErrorAction Stop | Out-Null
                } finally {
                    # Zero the plain text string immediately after use
                    $plain = $null
                    [System.GC]::Collect()
                }
            }
            & $localLog 'PASS' "Task registered ($runAsUser)"
        } catch {
            $errStr = $_.ToString()
            # Decode common task registration error codes for actionable messages
            $hint = switch -Wildcard ($errStr) {
                '*0x8007052e*' { ' (Wrong username or password)' }
                '*0x80070569*' { ' (Logon failure -- account may not have Log on as batch job right)' }
                '*0x80041315*' { ' (Task Scheduler service not running -- start it in services.msc)' }
                '*0x80041316*' { ' (Task already exists and could not be overwritten)' }
                '*Access*denied*' { ' (Access denied -- run launcher as Administrator)' }
                '*password*'  { ' (Password-related -- check credentials and try again)' }
                default { '' }
            }
            & $localLog 'FAIL' "Register-ScheduledTask failed$hint : $errStr"
            try { [System.IO.File]::Delete($engPath) } catch { }
            try { [System.IO.File]::Delete($payPath) } catch { }
            $window.Dispatcher.Invoke([Action]{ $btnLaunch.IsEnabled = $true; $btnLaunch.Content = ">>  LAUNCH  <<" },
                [System.Windows.Threading.DispatcherPriority]::Normal)
            return
        }

        try {
            Start-ScheduledTask -TaskName $taskName -ErrorAction Stop
            & $localLog 'PASS' "Payload launched in interactive desktop session"
            & $localLog 'INFO' "Boot engine output streaming to log panel below"
            & $localLog 'BOOT' "===================================================="
        } catch {
            & $localLog 'FAIL' "Start-ScheduledTask failed: $_"
        }

        # Cleanup task (brief delay so task has time to start before we delete its definition)
        Start-Sleep -Milliseconds 2000
        try {
            Unregister-ScheduledTask -TaskName $taskName -Confirm:$false -ErrorAction SilentlyContinue  # SilentlyContinue intentional -- task may not exist; missing task is not an error here
        } catch { }

        # Give bridge a final drain window then delete bridge file.
        # UI-thread timer detects file gone and self-stops.
        Start-Sleep -Milliseconds 1500
        try {
            if (Test-Path -LiteralPath $bridgeFile -ErrorAction SilentlyContinue) {
                [System.IO.File]::Delete($bridgeFile)
            }
        } catch { }

        $window.Dispatcher.Invoke([Action]{
            $btnLaunch.IsEnabled = $true
            $btnLaunch.Content   = ">>  LAUNCH  <<"
        }, [System.Windows.Threading.DispatcherPriority]::Normal)

    }) | Out-Null

    # Create bridge file and start UI-thread polling timer BEFORE runspace fires.
    # DispatcherTimer must be created on the UI (STA) thread -- cannot be done inside runspace.
    $script:CurrentBridgeFile = Join-Path $env:TEMP ("PaladinPS-Bridge-" + [System.DateTime]::Now.Ticks + ".log")
    try {
        [System.IO.File]::WriteAllText($script:CurrentBridgeFile, '', [System.Text.Encoding]::UTF8)
    } catch { }

    $script:BridgeOffset = 0
    if ($script:BridgeTimer -and $script:BridgeTimer.IsEnabled) { $script:BridgeTimer.Stop() }
    $script:BridgeTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:BridgeTimer.Interval = [System.TimeSpan]::FromMilliseconds(250)
    $script:BridgeTimer.Add_Tick([System.EventHandler]{
        try {
            $bf = $script:CurrentBridgeFile
            if ([string]::IsNullOrEmpty($bf)) { $script:BridgeTimer.Stop(); return }
            if (-not (Test-Path -LiteralPath $bf -ErrorAction SilentlyContinue)) {
                # File deleted by runspace -- drain complete, stop timer
                $script:BridgeTimer.Stop()
                return
            }
            $raw = [System.IO.File]::ReadAllText($bf, [System.Text.Encoding]::UTF8)
            if ($raw.Length -le $script:BridgeOffset) { return }
            $newContent = $raw.Substring($script:BridgeOffset)
            $script:BridgeOffset = $raw.Length
            $lines = $newContent -split "`n"
            foreach ($bLine in $lines) {
                $bLine = $bLine.TrimEnd("`r")
                if ([string]::IsNullOrWhiteSpace($bLine)) { continue }
                # Bridge line format: LEVEL|Message  (e.g. PASS|ExecutionPolicy set)
                $pipeIdx = $bLine.IndexOf('|')
                if ($pipeIdx -gt 0 -and $pipeIdx -lt 6) {
                    $bLevel = $bLine.Substring(0, $pipeIdx).Trim()
                    $bMsg   = $bLine.Substring($pipeIdx + 1)
                } else {
                    $bLevel = 'INFO'
                    $bMsg   = $bLine
                }
                Add-LogEntry    -Level $bLevel -Message "[boot] $bMsg"
                Update-Checklist -Level $bLevel -Message $bMsg
            }
        } catch { }
    })
    $script:BridgeTimer.Start()

    $ps.AddParameters(@{
        payloadPath       = $script:TxtPayload.Text.Trim()
        doSign            = ($script:ChkSign.IsChecked -eq $true)
        signerCN          = $script:TxtSignerCN.Text.Trim()
        chkDirectLaunch   = ($script:ChkDirectLaunch.IsChecked -eq $true)
        chkDefender       = ($script:ChkDefender.IsChecked  -eq $true)
        chkExclusion      = ($script:ChkExclusion.IsChecked -eq $true)
        chkPolicy         = ($script:ChkPolicy.IsChecked    -eq $true)
        chkElevate        = ($script:ChkElevate.IsChecked   -eq $true)
        chkSession        = ($script:ChkSession.IsChecked   -eq $true)
        chkKeep           = ($script:ChkKeep.IsChecked      -eq $true)
        chkPrompt         = ($script:ChkPrompt.IsChecked    -eq $true)
        chkAutoCreate     = ($script:ChkAutoCreate.IsChecked -eq $true)
        chkTrustCU        = ($script:ChkTrustCU.IsChecked   -eq $true)
        chkTrustLM        = ($script:ChkTrustLM.IsChecked   -eq $true)
        chkTimestamp      = ($script:ChkTimestamp.IsChecked  -eq $true)
        certValidityDays  = (Get-CertValidityDays)
        useCurrentUser    = ($script:ChkUseCurrentUser.IsChecked -eq $true)
        adminUsername     = $script:TxtAdminUser.Text.Trim()
        adminSecurePass   = $script:PwdAdminPass.SecurePassword
        logAction         = $script:LogAction
        bootEngineContent = $script:BootEngineContent
        scriptVersion     = $script:Version
        window            = $script:Window
        btnLaunch         = $script:BtnLaunch
        logDoc            = $script:LogDoc
        logBox            = $script:LogBox
        bridgeFile        = $script:CurrentBridgeFile
    }) | Out-Null

    # Track as recent on the UI thread -- Add-RecentScript not visible inside runspace
    Add-RecentScript -Path ($script:TxtPayload.Text.Trim())
    Update-LibraryDropdown

    $ps.BeginInvoke() | Out-Null
})

#------------------------------------------------------------------------------
# STARTUP LOG
#------------------------------------------------------------------------------
Add-LogEntry -Level 'BOOT' -Message "$($script:Title) ready"
Add-LogEntry -Level 'PASS' -Message "Running as: $([System.Security.Principal.WindowsIdentity]::GetCurrent().Name)"
Add-LogEntry -Level 'INFO' -Message "Select a PS1 payload, configure manifest, then click LAUNCH"
Add-LogEntry -Level 'INFO' -Message "Launch method: schtasks /RL HIGHEST (no UAC dialog required)"

#------------------------------------------------------------------------------
# SHOW WINDOW
#------------------------------------------------------------------------------
$script:Window.ShowDialog() | Out-Null
